  INSERT INTO "05_grc_library"."22_dtl_requirement_properties" (id, requirement_id, property_key, property_value, created_at, updated_at, created_by, updated_by)
  VALUES
      ('00e40d1d-e7e4-417d-8e8e-aac5cb20b939', '3458e8d2-bd98-4443-a058-f9ba4b04b78e', 'description', 'Organizations must manage risks associated with suppliers, contractors, and service providers that access information or systems. Security requirements must be defined within contractual agreements and monitored throughout the supplier relationship lifecycle. Third‑party activities must be evaluated to ensure they meet the organization’s information security expectations.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('03bbc383-e3cc-4a2b-b97a-0326e249fc38', '72857373-2a1f-412c-8cf4-b12f78f49d91', 'name', 'Control Environment', '2026-04-06T15:16:52.874753', '2026-04-06T15:16:52.874753', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('0580eb46-763f-4ec5-8872-b478d4ed16b5', 'a4975aee-1c23-4be2-a6f9-4d413eb92618', 'acceptance_criteria', '["A documented data protection governance structure with defined roles and responsibilities exists and is approved by senior management", "A designated privacy leader or Data Protection Officer is formally assigned responsibility for DPDP compliance oversight", "Data protection policies aligned with DPDP requirements are documented, approved, and communicated", "Periodic governance reviews of personal data protection risks and compliance status are conducted and documented"]', '2026-04-07T19:19:31.293328', '2026-04-07T19:19:31.293328', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('07952053-d820-4120-b802-9f7d76711c08', 'aa873cf7-9fd6-441f-9ae3-7cf0db793a58', 'name', 'Consent Management', '2026-04-07T18:00:21.383009', '2026-04-07T18:00:21.383009', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('0f1745e1-b302-4184-8eec-b717f656c924', '02a8ab51-bbfb-4fb1-9061-e05cbdf9322a', 'description', 'Maintain documentation and evidence demonstrating compliance with DPDP requirements, including policies, processing records, and operational procedures. Organizations must periodically review controls, conduct internal assessments, and update practices in response to regulatory or operational changes. Compliance monitoring ensures continuous adherence to data protection obligations.', '2026-04-07T18:00:21.658018', '2026-04-07T18:00:21.658018', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('10e13d47-59c0-4021-9c52-7781bd549c28', '7846d685-1c13-4d4d-94fe-1f1508554cdb', 'description', 'Ensure that personal data is processed only for lawful purposes permitted under the DPDP Act, including consent-based processing and legitimate uses defined by law. Organizations must document the legal basis for processing activities and ensure processing is limited to the specified purposes. Processing practices must prevent misuse or unauthorized secondary use of personal data.', '2026-04-07T18:00:21.353873', '2026-04-07T18:00:21.353873', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1155aa99-b7d3-4540-b5bf-4b4701a39639', '4aa6b19d-5d95-4e50-b717-4f3166f67b46', 'description', 'Implement procedures and systems that enable Data Principals to exercise their statutory rights, including access, correction, updating, and erasure of personal data. Organizations must ensure requests are authenticated, processed within required timelines, and recorded for accountability. Mechanisms should ensure requests are handled consistently and securely.', '2026-04-07T18:00:21.442866', '2026-04-07T18:00:21.442866', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('12fe245e-9097-4922-adfb-9e71961db30b', '8168dccd-964b-4143-95e3-b2e92b03c7ef', 'name', 'Data Retention and Deletion', '2026-04-07T18:00:21.506789', '2026-04-07T18:00:21.506789', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('131216c3-44f6-450d-a034-98248269ea32', '2af977a8-316a-416e-aafc-cf3e35496901', 'name', 'Monitoring Activities', '2026-04-06T15:16:54.500393', '2026-04-06T15:16:54.500393', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('133ca52c-a732-41e2-ac0b-eb8bc5601efa', 'a652785c-02fe-43c8-a5df-19b9e1c12269', 'name', 'Children''s Personal Data Protection', '2026-04-07T18:00:21.602303', '2026-04-07T18:00:21.602303', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('15eb7829-a18d-4916-bd12-b5c4a2c679d1', 'f44ce050-cc11-40cb-a331-2ed2f613a6e6', 'description', 'Ensure that personal data maintained by the organization is accurate, complete, and kept up to date for the purposes for which it is processed. Procedures should exist for correcting inaccurate data and validating information used in decision-making processes. Data quality practices must reduce risks associated with incorrect or outdated information.', '2026-04-07T18:00:21.469528', '2026-04-07T18:00:21.469528', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('177033b0-6b98-41d6-b6a2-f1aa4c96ff4a', 'a4622f77-0230-480b-b6e9-f07c5bcb18c8', 'description', 'Establishes processes for managing and monitoring system operations to detect and respond to anomalies, security events, and operational failures. This requirement includes logging, alerting, vulnerability monitoring, and incident response processes. The goal is to ensure systems operate securely, reliably, and consistently according to defined operational standards.', '2026-04-06T15:16:55.875797', '2026-04-06T15:16:55.875797', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1a27217b-36ce-4422-8f2e-69750930d530', '94ad6b57-1ebb-44ef-82da-b77067d8b6c1', 'description', 'Requires the organization to identify, analyze, and manage risks that could affect the achievement of security objectives. This includes defining risk tolerance, identifying threats and vulnerabilities, and assessing risks associated with systems, processes, and third parties. The organization must evaluate the likelihood and impact of risks to determine appropriate mitigation strategies.', '2026-04-06T15:16:53.982846', '2026-04-06T15:16:53.982846', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1a6b37e4-ef81-4726-a660-78a8693f8190', '9f852b6f-2c78-432f-be16-bad201fda31b', 'name', 'Acceptable Use and Asset Handling', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1aa6d245-26d6-42f5-ac23-dc7f530dda54', 'a4975aee-1c23-4be2-a6f9-4d413eb92618', 'name', 'Data Protection Governance', '2026-04-07T18:00:21.324519', '2026-04-07T18:00:21.324519', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1d0b3362-1e1b-4903-b101-57a4eb4fd263', 'cc495ac3-2ce6-472e-a700-860d8873ad66', 'description', 'Defines the technological safeguards required to protect systems, networks, applications, and data. This includes controls related to system hardening, malware protection, cryptography, monitoring, logging, vulnerability management, and secure development practices. These technical protections provide the operational security mechanisms supporting the ISMS.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1f3c1f21-6379-41be-85e3-d4d7e431d59d', '4aa6b19d-5d95-4e50-b717-4f3166f67b46', 'acceptance_criteria', '["Documented procedures exist for handling access, correction, and erasure requests", "Requests from Data Principals are authenticated before processing", "Requests are resolved within legally required timelines", "A log of rights requests and resolutions is maintained for audit purposes"]', '2026-04-07T19:19:31.321779', '2026-04-07T19:19:31.321779', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1f9634b9-f616-454c-8f47-a43b9d525800', 'c1061f17-24ba-4e97-aca1-f040f0962cb6', 'name', 'Notice and Transparency', '2026-04-07T18:00:21.412529', '2026-04-07T18:00:21.412529', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('22bfe4c8-0457-4e65-9c20-73858d22ee9d', '0cdd9f4f-7228-4499-b3bf-dba82bf06d60', 'name', 'Asset Management and Ownership', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2658e037-9ffa-4290-88b4-2382c3a21bfe', '76170fbf-fbb9-4f8c-8be6-ddedf5ceba18', 'description', 'Establish procedures for identifying, responding to, and reporting personal data breaches involving digital personal data. Organizations must ensure timely notification to relevant regulatory authorities and affected Data Principals where required. Incident response processes should include containment, investigation, remediation, and documentation.', '2026-04-07T18:00:21.544594', '2026-04-07T18:00:21.544594', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('26e9a2c6-fb15-40b8-bd50-9b271f16f04e', '02a8ab51-bbfb-4fb1-9061-e05cbdf9322a', 'name', 'Compliance Monitoring and Documentation', '2026-04-07T18:00:21.658018', '2026-04-07T18:00:21.658018', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('29fe88bf-a730-459c-8fa8-e3dcc1484ba1', 'b3efe1fa-0756-4147-b579-0611c03536fb', 'description', 'Limit the collection and processing of personal data to only what is necessary for the specified purpose. Organizations should design systems and processes to minimize excessive data collection and restrict usage to authorized purposes. Controls should prevent unnecessary retention or use of personal data beyond its intended purpose.', '2026-04-07T18:00:21.48895', '2026-04-07T18:00:21.48895', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('2a55989f-6c18-4960-98cb-c1e848325048', 'd0bde9d5-d1ce-4052-9b29-59edbec5fc44', 'description', 'Ensures that information security considerations are integrated into project management processes and system development initiatives. Security requirements must be identified and addressed throughout the project lifecycle from planning to deployment. This requirement ensures that new systems and changes do not introduce unmanaged risks.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2bb734d6-5569-4391-8f72-9a2395da61da', '230265fc-c589-42b3-9036-fe421ea09a75', 'name', 'Risk Mitigation', '2026-04-06T15:16:56.760953', '2026-04-06T15:16:56.760953', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2eea1411-ba64-4561-9333-ea908a9737d6', '492d5df9-5daa-42b0-8eb1-1f36e08d8529', 'name', 'Physical Security', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('342d9aab-adc7-42aa-982d-263b466adf5c', '72857373-2a1f-412c-8cf4-b12f78f49d91', 'description', 'Establishes the organizational foundation for internal control through integrity, ethical values, governance oversight, and accountability. This requirement ensures management defines expectations for ethical behavior, assigns responsibilities, and maintains appropriate organizational structures. It also includes processes for attracting, developing, and retaining competent personnel responsible for security and control operations.', '2026-04-06T15:16:52.874753', '2026-04-06T15:16:52.874753', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3644cbd3-d595-4831-bc06-d87510df4fa3', '11d1077f-28fb-4bee-aa7d-0bb4314a5b65', 'name', 'Grievance Redressal Mechanism', '2026-04-07T18:00:21.620471', '2026-04-07T18:00:21.620471', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3c464490-ccec-478c-92f2-2653386d47e1', '5cf3f6c3-52b2-47c0-b18a-554b1078bd84', 'acceptance_criteria', '["All production system changes are documented through an approved change management process.", "Changes are reviewed and approved prior to implementation by authorized personnel.", "Changes are tested in a controlled environment before deployment to production.", "Emergency changes follow documented expedited procedures and are reviewed retrospectively.", "Change records including approvals, testing evidence, and deployment outcomes are retained."]', '2026-04-06T15:44:43.459033', '2026-04-06T15:44:43.459033', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3d9d4faa-a11c-4d46-ad40-c0dfeeaaa764', 'fdc216a9-ae35-418a-a509-91f50e4f070b', 'name', 'Information Security Policies', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('417ecd5e-cc1d-42b2-a78c-44e70b4378ed', 'b7625850-9e8d-4c56-aba0-8ef3fa10e6dd', 'name', 'Security Safeguards for Personal Data', '2026-04-07T18:00:21.526372', '2026-04-07T18:00:21.526372', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('507e4c21-605f-49e6-bd70-280a1c5e6946', '7846d685-1c13-4d4d-94fe-1f1508554cdb', 'acceptance_criteria', '["All personal data processing activities have a documented lawful basis under the DPDP Act", "Records of processing activities identify purposes, categories of data, and lawful basis for processing", "Controls exist to prevent use of personal data for purposes not originally specified", "Periodic compliance reviews verify that processing activities remain aligned with documented lawful purposes"]', '2026-04-07T19:19:31.30109', '2026-04-07T19:19:31.30109', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('5262d4aa-6a37-4828-aca8-b9bc1fa9e4bf', 'bebacfd2-7971-4935-9957-d1580dfcdfea', 'name', 'Significant Data Fiduciary Obligations', '2026-04-07T18:00:21.639739', '2026-04-07T18:00:21.639739', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('528dd6a5-c91f-4d07-b093-428cd8ed0bfd', 'e04a890e-9326-4f38-a9c4-8ac152034daa', 'description', 'Requires organizations to classify information according to its sensitivity, value, and criticality to the organization. Classification schemes must consider confidentiality, integrity, and availability requirements. Labelling procedures must ensure that users understand how to handle and protect information appropriately.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('55208b1d-42c6-4264-8fc7-922f8c214d05', 'b7625850-9e8d-4c56-aba0-8ef3fa10e6dd', 'description', 'Implement appropriate technical and organizational security measures to protect personal data from unauthorized access, disclosure, alteration, or destruction. Safeguards should include access controls, encryption, monitoring, and secure infrastructure practices. Security measures must align with the sensitivity and volume of personal data processed.', '2026-04-07T18:00:21.526372', '2026-04-07T18:00:21.526372', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('5764be1b-ec2e-445d-bf7e-76d6909f04b4', '11d1077f-28fb-4bee-aa7d-0bb4314a5b65', 'description', 'Establish a formal mechanism for Data Principals to submit complaints or grievances related to personal data processing. Organizations must provide accessible communication channels and ensure grievances are reviewed and resolved within defined timelines. Records of grievances and responses should be maintained for accountability.', '2026-04-07T18:00:21.620471', '2026-04-07T18:00:21.620471', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('58761c10-e3c0-49b1-9805-40e2e0bc6602', '8168dccd-964b-4143-95e3-b2e92b03c7ef', 'description', 'Define and enforce retention policies that ensure personal data is stored only for as long as necessary to fulfill the stated purpose or meet legal obligations. Once the purpose is satisfied or consent is withdrawn, data must be securely deleted or anonymized. Organizations must maintain mechanisms to identify and remove obsolete data.', '2026-04-07T18:00:21.506789', '2026-04-07T18:00:21.506789', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('5be57907-fa9b-4e59-a1ce-1a44e3ed9bfd', '492d5df9-5daa-42b0-8eb1-1f36e08d8529', 'description', 'Requires organizations to protect physical facilities, equipment, and supporting infrastructure from unauthorized access, environmental hazards, and operational disruption. Physical security measures include secure areas, entry controls, surveillance, and protection of equipment. These safeguards ensure that physical access does not compromise information systems or data.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('5c3c13d8-6e02-465c-98ab-58e3b2d7117c', '7c9631ae-c695-4416-920f-749d17717e40', 'name', 'People Security', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('61bde68d-a325-4cee-8e49-5512456ad36d', '44c6b47a-8844-4bb7-8824-1849d7e3bfd6', 'description', 'Ensure that Data Processors and third-party service providers handling personal data implement adequate safeguards consistent with DPDP obligations. Contracts and oversight mechanisms must define security requirements, processing limitations, and responsibilities for protecting personal data. Organizations remain accountable for ensuring processors comply with applicable requirements.', '2026-04-07T18:00:21.562053', '2026-04-07T18:00:21.562053', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('6381c509-ba72-49eb-845c-9ad82cc03e46', 'a4622f77-0230-480b-b6e9-f07c5bcb18c8', 'acceptance_criteria', '["System logs capturing authentication, administrative actions, and security events are collected and retained.", "Security monitoring processes detect anomalies and trigger investigation procedures.", "Defined incident response procedures are followed when security events are detected.", "Operational alerts and system failures are reviewed and resolved within defined response timelines.", "Monitoring coverage includes critical production infrastructure and cloud services."]', '2026-04-06T15:44:43.447031', '2026-04-06T15:44:43.447031', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('64e44f93-0576-4804-8fe4-896b56b5f339', '1315dabf-3e68-43f3-9c7b-0cba2855d059', 'name', 'Cloud Services Security', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('67342f1f-62c1-40b7-a9b7-fc8e2e80a1db', '7a0ea8c2-a0a2-44c6-acfd-071d8c252cbe', 'name', 'Identity and Authentication Management', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('6ca1eb63-9924-44cd-8129-c181f0bae5e8', 'bebacfd2-7971-4935-9957-d1580dfcdfea', 'description', 'Where designated as a Significant Data Fiduciary, organizations must implement enhanced compliance measures such as appointing a Data Protection Officer and conducting periodic data protection impact assessments. Additional requirements include independent audits and enhanced monitoring of high-risk processing activities. These obligations ensure higher accountability for organizations processing large volumes or sensitive categories of data.', '2026-04-07T18:00:21.639739', '2026-04-07T18:00:21.639739', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('704912ad-d47f-4667-90a2-1f1f0d9ab8ef', '16756847-2bfe-45ad-a2b8-b98befe4268a', 'description', 'Requires organizations to identify and comply with applicable legal, statutory, regulatory, and contractual obligations related to information security and data protection. Compliance activities must include monitoring regulatory changes and implementing appropriate safeguards. Evidence of compliance must be documented and maintained.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('71c62f58-a96b-41c2-8eb5-911cf706d861', 'f44ce050-cc11-40cb-a331-2ed2f613a6e6', 'name', 'Data Accuracy and Quality', '2026-04-07T18:00:21.469528', '2026-04-07T18:00:21.469528', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('72246db2-cbfc-40ab-bb9d-fbe2572d8536', 'c4a242b3-0150-4756-a6c1-678ae2645aff', 'description', 'Organizations must collect, analyze, and use threat intelligence to understand the evolving cybersecurity landscape and inform security decisions. This includes monitoring threat actors, vulnerabilities, and emerging attack techniques. Intelligence outputs should support risk assessments, defensive planning, and incident response readiness.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('72c90e6c-b13e-4edd-948c-25008c213fd3', 'd4a196d4-c20f-4e27-a2b9-8c8914a5baab', 'description', 'Requires organizations to maintain appropriate relationships with regulatory authorities, law enforcement, and professional security groups. These relationships support compliance, incident coordination, and threat awareness. Engagement with external bodies helps organizations stay informed about regulatory developments, security advisories, and industry best practices.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('73acc1c9-e13a-4e22-a414-cb8d02a3d1eb', 'e04a890e-9326-4f38-a9c4-8ac152034daa', 'name', 'Information Classification and Labelling', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('77e598d9-2d2c-45c8-89d5-295072e7509b', '3458e8d2-bd98-4443-a058-f9ba4b04b78e', 'name', 'Supplier and Third‑Party Security', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7ce8b3ca-82f4-4bc5-992e-e84fb4e46a07', '40e1b704-64cd-4f99-a9df-958d2b7b612b', 'description', 'Ensures that access to systems, data, and facilities is restricted to authorized users based on business need and security principles. This requirement includes identity management, authentication mechanisms, role-based access controls, and periodic access reviews. It also covers physical safeguards to prevent unauthorized access to infrastructure and sensitive assets.', '2026-04-06T15:16:55.394308', '2026-04-06T15:16:55.394308', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7cfc26eb-5b3d-4a0c-a670-1d1807574f0a', 'fdc216a9-ae35-418a-a509-91f50e4f070b', 'description', 'Requires the organization to define, approve, publish, and maintain formal information security policies aligned with business objectives and regulatory obligations. Policies must communicate management direction and expectations for protecting information assets. They must be regularly reviewed and updated to remain relevant to evolving threats and operational changes.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7d1f52df-b4d3-412d-87c3-64dc98e13497', 'a4622f77-0230-480b-b6e9-f07c5bcb18c8', 'name', 'System Operations', '2026-04-06T15:16:55.875797', '2026-04-06T15:16:55.875797', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7d96e6ab-77a8-4cb0-94a1-019a5a244bf9', '1315dabf-3e68-43f3-9c7b-0cba2855d059', 'description', 'Defines governance and risk management practices for the secure use of cloud services. Organizations must evaluate cloud providers, establish security responsibilities, and ensure contractual protections for information assets hosted in cloud environments. Ongoing monitoring must verify that cloud services maintain appropriate security controls.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7e540a1b-b55f-457f-8c92-e7af0444c3e1', 'b3efe1fa-0756-4147-b579-0611c03536fb', 'name', 'Data Minimization and Purpose Limitation', '2026-04-07T18:00:21.48895', '2026-04-07T18:00:21.48895', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('7e667183-5018-40c5-a4fd-1f16eddeff43', 'c906c89d-6734-493c-a0f7-4e75646b8ff8', 'description', 'Defines the policies, procedures, and technical safeguards implemented to mitigate identified risks and achieve control objectives. Control activities include preventive and detective mechanisms such as approvals, verifications, reconciliations, and segregation of duties. These activities must be integrated into business processes and consistently applied across relevant systems and operations.', '2026-04-06T15:16:54.967135', '2026-04-06T15:16:54.967135', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('822ebef4-9d40-43c1-8137-d1ef3f8eb27f', '78463795-2260-4d75-a96d-b1b4991e6b7e', 'name', 'Communication and Information', '2026-04-06T15:16:53.486201', '2026-04-06T15:16:53.486201', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('8305dfa0-8e3c-4600-b718-10d06814584b', '471e8dc7-3727-478e-ac8b-09817e5ff4b6', 'name', 'Organisational Information Security Governance', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('86be807d-0772-4f7a-a59d-963a98b74942', 'b3dd793a-1a5a-486e-b404-5b9c9646197a', 'name', 'Cross-Border Data Transfer Compliance', '2026-04-07T18:00:21.581765', '2026-04-07T18:00:21.581765', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('8b895252-72e6-43cf-9071-997738c349c3', '230265fc-c589-42b3-9036-fe421ea09a75', 'description', 'Addresses the identification and management of risks arising from business relationships, vendor dependencies, and other external factors. This requirement includes evaluating third-party service providers, contractual security expectations, and ongoing oversight of vendor risk. Organizations must implement measures to reduce risks that could impact the security and reliability of systems and data.', '2026-04-06T15:16:56.760953', '2026-04-06T15:16:56.760953', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('900938ae-7858-42ba-a162-94c7fa71230b', '9f852b6f-2c78-432f-be16-bad201fda31b', 'description', 'Establishes rules governing acceptable use of organizational information, systems, and associated assets. Users must understand permitted and prohibited activities when accessing organizational resources. The requirement also addresses responsibilities for safeguarding assets and returning them when employment or contractual relationships change.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('92a7f0f6-d655-4cae-98bb-7d7f973dce7c', 'cc495ac3-2ce6-472e-a700-860d8873ad66', 'name', 'Technological Security Controls', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('92fb4d01-e09e-4c6e-8ebd-623ae375eafe', 'c906c89d-6734-493c-a0f7-4e75646b8ff8', 'name', 'Control Activities', '2026-04-06T15:16:54.967135', '2026-04-06T15:16:54.967135', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('95c949ba-2f7d-4cdd-a9d5-c367cc5ed4e3', '9a0a4421-57c0-42cc-83ba-324443f126e7', 'description', 'Establishes the rules and governance processes for controlling access to information systems and data. Access must be granted based on business requirements, least privilege, and defined authorization procedures. Access control policies must be periodically reviewed to ensure ongoing appropriateness and compliance.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('97bd832d-9ec4-4593-8bad-18ae6b172d5e', '76170fbf-fbb9-4f8c-8be6-ddedf5ceba18', 'name', 'Personal Data Breach Management', '2026-04-07T18:00:21.544594', '2026-04-07T18:00:21.544594', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('9b6bc6a3-9701-4376-a34e-c7f95045a5d6', '7846d685-1c13-4d4d-94fe-1f1508554cdb', 'name', 'Lawful Processing of Personal Data', '2026-04-07T18:00:21.353873', '2026-04-07T18:00:21.353873', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a05748c5-69b3-485b-b571-60cb77c0654d', 'e8ce350f-0609-4b69-aec6-722e01204090', 'name', 'Business Continuity and ICT Readiness', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a18d3f47-2158-44da-b7b9-1ac1f11e7ef1', '5cf3f6c3-52b2-47c0-b18a-554b1078bd84', 'name', 'Change Management', '2026-04-06T15:16:56.326149', '2026-04-06T15:16:56.326149', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a3b413f2-321f-48db-85f7-bb2fd118b3b5', 'c1061f17-24ba-4e97-aca1-f040f0962cb6', 'acceptance_criteria', '["Privacy notices describing data collection and processing purposes are publicly available and accessible", "Notices clearly identify the categories of personal data collected and how they are used", "Notices include contact details for grievance redressal or data protection inquiries", "Privacy notices are reviewed and updated when processing activities change"]', '2026-04-07T19:19:31.315235', '2026-04-07T19:19:31.315235', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a83f624a-d042-4abb-8f49-6d5ff59a3554', 'a4975aee-1c23-4be2-a6f9-4d413eb92618', 'description', 'Establish and maintain a governance structure responsible for oversight of personal data protection obligations under the DPDP Act. This includes defining accountability, policies, and internal roles to ensure that personal data is processed lawfully and responsibly. Governance mechanisms must ensure ongoing compliance with statutory requirements and organizational policies.', '2026-04-07T18:00:21.324519', '2026-04-07T18:00:21.324519', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a8f61f55-fa4c-4638-a697-fde7e6cfe923', 'c4a242b3-0150-4756-a6c1-678ae2645aff', 'name', 'Threat Intelligence and Risk Awareness', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a95053c6-f084-4380-852d-a7f53dd9d9f1', '1f8af257-5eb3-447c-94a6-2a1a045a06f0', 'description', 'Establishes clear assignment of information security roles and responsibilities throughout the organization. Responsibilities must be documented and communicated so personnel understand their obligations for protecting information assets. Segregation of duties must be implemented to reduce the risk of fraud, misuse, or unauthorized modification of systems and data.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('b07d9369-4d4b-4dbf-9823-840e227805db', 'a652785c-02fe-43c8-a5df-19b9e1c12269', 'description', 'Implement additional safeguards when processing personal data belonging to children as defined under the DPDP Act. Organizations must obtain verifiable parental consent and avoid processing practices that could harm children. Systems should ensure that children’s data is handled with enhanced security and restricted use.', '2026-04-07T18:00:21.602303', '2026-04-07T18:00:21.602303', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('b42281e7-b5be-48c3-8a55-d3677e2a0285', '7c9631ae-c695-4416-920f-749d17717e40', 'description', 'Defines security responsibilities and expectations for employees, contractors, and third‑party personnel throughout their employment lifecycle. This includes pre‑employment screening, security awareness training, disciplinary procedures, and responsibilities following termination or role change. The requirement also addresses secure remote working practices.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('b50136d5-39fa-4608-8e74-3db7c58ea885', '471e8dc7-3727-478e-ac8b-09817e5ff4b6', 'description', 'Defines the governance structure, policies, and oversight mechanisms required to manage information security across the organization. This requirement establishes leadership commitment, policy management, defined responsibilities, and coordination with internal and external stakeholders. It ensures that information security is integrated into organizational strategy, decision‑making, and operational management.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('b79af262-7b2b-43da-8d15-df064eb74327', '2611fd7d-e3be-4b52-a2cb-a78a1a9a7e84', 'description', 'Defines controls for protecting information during transfer between internal systems, external parties, and communication channels. Organizations must establish policies, agreements, and technical safeguards that prevent unauthorized access, alteration, or loss of data during transmission. Secure transfer mechanisms and monitoring procedures must be implemented.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('bb6ea542-6cf9-4ee4-bae6-3f3d7c89c520', '0cdd9f4f-7228-4499-b3bf-dba82bf06d60', 'description', 'Requires organizations to identify, document, and manage information assets and supporting resources. Asset inventories must be maintained and ownership assigned to ensure accountability for protection and proper handling. Asset management supports risk management, classification, and lifecycle governance.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('bfe36316-4c09-47b7-9e4a-273d7b44fe29', '9a0a4421-57c0-42cc-83ba-324443f126e7', 'name', 'Access Control Governance', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c0aa2076-2c33-44fb-90a0-2bc8a430d7eb', 'added58b-973d-49d2-b96c-362a3a657237', 'description', 'Establishes processes for detecting, reporting, assessing, and responding to information security incidents. Organizations must ensure incidents are properly documented, investigated, and resolved to minimize operational and security impacts. Lessons learned must feed back into risk management and security improvement processes.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c22027f5-345c-4317-a9e9-c10411cc280e', '94ad6b57-1ebb-44ef-82da-b77067d8b6c1', 'name', 'Risk Assessment', '2026-04-06T15:16:53.982846', '2026-04-06T15:16:53.982846', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c5fbea7d-c707-4d85-93f5-c6298da9588f', '1f8af257-5eb3-447c-94a6-2a1a045a06f0', 'name', 'Roles, Responsibilities and Segregation of Duties', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c6a0e434-91fd-4d61-85e2-be0f72eeb752', 'd0bde9d5-d1ce-4052-9b29-59edbec5fc44', 'name', 'Information Security in Project Management', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cab6e7d7-3b3c-4cf4-bc26-0365ae59cc24', '78463795-2260-4d75-a96d-b1b4991e6b7e', 'description', 'Ensures that relevant internal and external information necessary for supporting internal controls is identified, captured, processed, and communicated in a timely manner. This requirement includes communication of security policies, responsibilities, and expectations across the organization. It also covers mechanisms that enable personnel to report control issues, security concerns, or policy violations.', '2026-04-06T15:16:53.486201', '2026-04-06T15:16:53.486201', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d648e9c5-6086-45ff-9820-bbf04361fc67', 'aa873cf7-9fd6-441f-9ae3-7cf0db793a58', 'acceptance_criteria', '["Systems capture and store verifiable records of consent including timestamp and purpose", "Data Principals can review and withdraw consent through accessible mechanisms", "Processing activities automatically stop when consent is withdrawn unless another lawful basis applies", "Consent records are retained for audit and regulatory review"]', '2026-04-07T19:19:31.307806', '2026-04-07T19:19:31.307806', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('daa8a9fe-ebdf-4680-be74-4f594f52712c', 'added58b-973d-49d2-b96c-362a3a657237', 'name', 'Information Security Incident Management', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('dfb2e34b-ae8e-4752-ad7c-fd2fff505ea8', '40e1b704-64cd-4f99-a9df-958d2b7b612b', 'acceptance_criteria', '["User and administrative access to systems is granted based on documented business need and approved roles.", "Strong authentication mechanisms are enforced for access to production systems and sensitive data.", "Privileged access is restricted, approved, and periodically reviewed.", "Periodic access reviews are conducted and documented at least annually.", "Physical access to infrastructure hosting critical systems is restricted and monitored."]', '2026-04-06T15:44:43.433116', '2026-04-06T15:44:43.433116', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e0f13d72-6746-4c8d-a807-e378d027fdc4', 'c1061f17-24ba-4e97-aca1-f040f0962cb6', 'description', 'Provide clear, accessible notices to Data Principals regarding how their personal data will be collected, used, stored, and shared. Notices must describe processing purposes, rights available to individuals, and contact information for grievance or data protection inquiries. Transparency practices should ensure individuals can understand how their data is handled.', '2026-04-07T18:00:21.412529', '2026-04-07T18:00:21.412529', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('e2d7be9e-875e-4c6a-8509-7548d6d819d8', '2af977a8-316a-416e-aafc-cf3e35496901', 'description', 'Establishes processes to evaluate whether internal controls are present and functioning effectively over time. This requirement includes continuous monitoring activities, periodic evaluations, and the identification and remediation of control deficiencies. Monitoring ensures that control activities remain aligned with evolving risks, technologies, and organizational changes.', '2026-04-06T15:16:54.500393', '2026-04-06T15:16:54.500393', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e5e7e223-9664-4fe4-9797-db3ebc5c9a5f', '40e1b704-64cd-4f99-a9df-958d2b7b612b', 'name', 'Logical and Physical Access Controls', '2026-04-06T15:16:55.394308', '2026-04-06T15:16:55.394308', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ebdf32fe-68f7-44a9-9fcf-f6f143cd2f31', '44c6b47a-8844-4bb7-8824-1849d7e3bfd6', 'name', 'Third-Party Data Processing Management', '2026-04-07T18:00:21.562053', '2026-04-07T18:00:21.562053', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ed6c503b-02f9-4555-a40c-afd86e6b3231', '4aa6b19d-5d95-4e50-b717-4f3166f67b46', 'name', 'Data Principal Rights Management', '2026-04-07T18:00:21.442866', '2026-04-07T18:00:21.442866', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ee3297c5-b193-4e14-b110-ab427f57ccd9', '5cf3f6c3-52b2-47c0-b18a-554b1078bd84', 'description', 'Requires formal processes for managing system and infrastructure changes to minimize the risk of introducing security vulnerabilities or operational disruptions. This includes documenting change requests, testing modifications, approving changes, and maintaining change records. Controlled change management ensures system integrity and traceability across the system lifecycle.', '2026-04-06T15:16:56.326149', '2026-04-06T15:16:56.326149', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ef61f07f-516e-4933-8793-557c71cec2e8', 'd4a196d4-c20f-4e27-a2b9-8c8914a5baab', 'name', 'External and Regulatory Coordination', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ef9f8177-26c2-41b7-97aa-1be4f6f840ad', '7a0ea8c2-a0a2-44c6-acfd-071d8c252cbe', 'description', 'Requires lifecycle management of digital identities for users, systems, and services interacting with organizational resources. Authentication mechanisms such as passwords, tokens, and certificates must be securely issued, managed, and protected. Proper identity management ensures accountability and prevents unauthorized system access.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('effcf57e-d3d1-46e7-a392-4d0b4ca2e9ab', '2611fd7d-e3be-4b52-a2cb-a78a1a9a7e84', 'name', 'Information Transfer Security', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f4ba4906-33b2-4729-aa97-592f06699d7c', '16756847-2bfe-45ad-a2b8-b98befe4268a', 'name', 'Legal, Regulatory and Contractual Compliance', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f6aeaa06-b85d-492d-89ac-a20f88c16858', '230265fc-c589-42b3-9036-fe421ea09a75', 'acceptance_criteria', '["Third\u2011party service providers are evaluated for security risks prior to engagement.", "Security and data protection requirements are documented in vendor contracts or agreements.", "Vendors with access to sensitive data or systems undergo periodic security reassessments.", "Vendor risk assessments and monitoring results are documented and reviewed.", "Identified vendor risks are tracked and remediated according to defined risk management processes."]', '2026-04-06T15:44:43.471251', '2026-04-06T15:44:43.471251', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f6f87f87-da08-4c0b-b1cf-d2505108ce5f', 'b3dd793a-1a5a-486e-b404-5b9c9646197a', 'description', 'Manage transfers of personal data outside India in accordance with government restrictions or approved jurisdictions under the DPDP Act. Organizations must evaluate destination countries, implement safeguards, and ensure compliance with applicable regulatory directives. Cross-border transfer processes should be documented and monitored.', '2026-04-07T18:00:21.581765', '2026-04-07T18:00:21.581765', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f9bfc7dd-80f7-4006-a005-4e2e39941f54', 'e8ce350f-0609-4b69-aec6-722e01204090', 'description', 'Ensures that information and communication technology systems can continue operating or be restored during disruptions. Organizations must plan and implement continuity strategies that protect critical services and data availability. ICT readiness must align with broader business continuity and disaster recovery objectives.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ffda7a98-1dd3-4fba-840d-108e51c9c6f1', 'aa873cf7-9fd6-441f-9ae3-7cf0db793a58', 'description', 'Implement mechanisms to obtain, record, manage, and withdraw user consent for the processing of personal data. Consent must be free, specific, informed, unconditional, and unambiguous. Systems should allow Data Principals to easily review and revoke consent while ensuring processing stops when consent is withdrawn unless another lawful basis applies.', '2026-04-07T18:00:21.383009', '2026-04-07T18:00:21.383009', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce')
