      ('0b97d04b-d911-44de-bb9d-d95f9419a5f0', 'ab84b5b8-9099-4b0f-8735-db138b4edebc', 'description', 'Implement a vulnerability management program that regularly scans systems and applications for known vulnerabilities and ensures timely remediation to reduce the risk of system compromise.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
