      ('0f4ad146-38fc-4869-ba01-9f82a8848c94', '0b09909d-658c-4583-91b5-9c61acd466b1', 'description', 'Define and maintain a structured process for detecting, reporting, assessing, and responding to information security incidents. A formal response capability minimizes operational disruption and limits the impact of security breaches.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('0f9372eb-e54d-4f28-8dbd-caf006b567f7', '644898fc-e846-415f-b288-8d044e203c65', 'implementation_guidance', '["Define mandatory security requirements for new projects and system changes", "Perform security risk assessments during project planning stages", "Include security design reviews and testing before system deployment", "Require security sign\u2011off prior to project completion or production release"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('0fc5f1f3-7f4e-4fa6-ae06-3110a8ef3009', 'c5261520-054b-4147-8cbf-7fa1c3999280', 'implementation_guidance', '["Develop standard privacy notice templates", "Display notices on websites and apps during data collection", "Ensure notices are clear and accessible", "Review notices periodically"]', '2026-04-07T18:51:49.896325', '2026-04-07T18:51:49.896325', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('0ff196ff-0294-42b8-ab6f-a3ff03938768', 'e89d79ab-0dcf-4385-9c5f-1458924de543', 'name', 'Conduct Data Protection Awareness Training', '2026-04-07T19:13:14.549828', '2026-04-07T19:13:14.549828', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('102fab19-5018-4184-97b9-f96b1f6e2528', 'b52c3aec-1593-47ee-a618-211ab9dbe57d', 'description', 'Provide mechanisms for Data Principals to easily withdraw previously granted consent and ensure processing activities relying on consent are halted upon withdrawal. The system must propagate consent status changes to relevant data processing workflows. This prevents continued processing without a lawful basis.', '2026-04-07T18:00:21.779208', '2026-04-07T18:00:21.779208', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('10449807-5cbf-41d0-8d98-abd1aba7f70c', '964773c6-cd11-463e-b9ce-0dfbd93ec14c', 'name', 'Continuously Monitor Control Coverage for New Systems and Assets', '2026-04-06T15:17:09.802343', '2026-04-06T15:17:09.802343', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('10482ae0-8ec0-4297-bbf5-1b3c5cd1b08e', 'df0923d3-14cb-400e-9d2d-70bfecd7f022', 'guidance', 'Ensure legal agreements incorporate security, privacy, and breach notification obligations.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1080687a-0bae-493c-a125-c3aa335fcb44', '94d788d9-4311-4ed6-861d-6ee1cad7f485', 'implementation_guidance', '["Require documented change requests with risk assessment, implementation plan, and rollback strategy.", "Implement workflow-based approvals in a ticketing or change management system before production deployment.", "Require security or infrastructure review for high-risk or sensitive system changes.", "Restrict direct production modifications by enforcing deployment through approved change pipelines.", "Maintain a complete audit trail of change requests, approvals, and implementation timestamps."]', '2026-04-06T15:17:11.166836', '2026-04-06T15:17:11.166836', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('11257875-f7b3-436b-bb6b-4c622fe2870c', '68c3432c-5f54-4aec-9b54-5974ece94a33', 'description', 'Define and document the scope of the Information Security Management System considering business processes, locations, assets, technologies, and external dependencies.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('11afe87f-6ae9-4dbe-bda2-a59e679fa8f9', '44e1eecf-e92c-4505-9d83-8535759d2bc3', 'description', 'Access rights to systems, applications, and data are periodically reviewed to ensure that permissions remain appropriate for users'' job functions. Managers and system owners verify assigned access and revoke privileges that are no longer required. Regular reviews reduce the accumulation of excessive or outdated access rights.', '2026-04-06T15:17:16.963868', '2026-04-06T15:17:16.963868', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('11e5d5cd-3fcc-42ab-ae1d-27ec2417c0aa', '5006dd25-c0e4-41d2-8559-550f8faebee8', 'description', 'Ensure password reset and account recovery mechanisms are secure and prevent unauthorized takeover of accounts that may provide access to personal data.', '2026-04-07T18:29:03.452906', '2026-04-07T18:29:03.452906', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('121af8ba-ec57-4749-a298-0ad43aa9fec9', '4d70ecb5-3e04-402d-bdef-a5bdaa3f9f2f', 'implementation_guidance', '["Deploy automated vulnerability scanning tools across internal networks, cloud infrastructure, and internet-facing assets", "Schedule recurring scans at defined intervals such as weekly or monthly depending on system criticality", "Classify and prioritize vulnerabilities using standardized severity ratings", "Track remediation through ticketing or vulnerability management platforms", "Validate remediation by performing follow-up scans after patches or configuration changes"]', '2026-04-06T15:17:20.930915', '2026-04-06T15:17:20.930915', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('12698ff2-917c-46a2-8a98-0401e7c82226', '807bbd34-3b97-40c7-a51f-ba040ddfca0e', 'description', 'Track investigation and resolution of grievances related to personal data processing.', '2026-04-07T19:36:46.081445', '2026-04-07T19:36:46.081445', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('13137ac5-fba4-4966-a639-f9af9fe4c794', '21c26368-94f0-4cf5-bbc2-0e5711613be3', 'name', 'Conduct Independent Data Protection Compliance Audits', '2026-04-07T18:00:22.237708', '2026-04-07T18:00:22.237708', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('13baccef-d20d-49ec-bb54-63a02b1eab2c', '5b5296da-9902-4c5d-8232-b601ab5f1852', 'name', 'Maintain Record of Personal Data Processing Activities', '2026-04-07T19:36:39.573896', '2026-04-07T19:36:39.573896', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('143f1c94-8df7-4801-b8c6-a8c34b2b1568', '4db2d477-80ee-458e-91dd-1bd4748d5e08', 'implementation_guidance', '["Define retention periods for each category of personal data", "Implement system rules or procedures for deletion after expiration", "Review retention schedules periodically", "Document retention decisions and approvals"]', '2026-04-07T19:13:14.349303', '2026-04-07T19:13:14.349303', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('14ae146e-ef65-4ea3-bef9-95d4b5ab497e', 'd4095971-8355-49cd-905c-bcfb20d22fe1', 'description', 'Ensure that only the minimum personal data necessary to fulfill a defined processing purpose is collected and processed. Limiting the scope of data reduces privacy exposure and lowers the impact of potential breaches. This control promotes privacy-by-design practices in systems and business processes.', '2026-04-07T18:00:21.90538', '2026-04-07T18:00:21.90538', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('14dd17b0-2ba2-488c-b4c8-a48b75a1c312', '0b09909d-658c-4583-91b5-9c61acd466b1', 'name', 'Establish Information Security Incident Response Process', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('14efcc20-fe96-4600-afba-fd14d364c8e9', '44e1eecf-e92c-4505-9d83-8535759d2bc3', 'guidance', 'Establish a recurring review schedule and require system owners and managers to certify user access levels.', '2026-04-06T15:17:16.963868', '2026-04-06T15:17:16.963868', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1537d3da-e5cf-479c-942e-7f494e61f8a2', '392c6c63-177c-4ff4-af85-c396f8ab033d', 'guidance', 'Implement a formal policy review cycle with documented approvals and version control.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('157a8e9d-a2f0-4024-8011-4a0665504456', 'ab045248-5b25-4404-9cfe-e640e6e27508', 'guidance', 'Maintain records linking processing activities with their lawful basis and ensure legal review for new processing activities.', '2026-04-07T18:44:23.712969', '2026-04-07T18:44:23.712969', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('15c2fedf-72db-40a1-9d51-d80768ba5ba6', '4703eb9d-b0c7-4ce8-aca2-0de8e038a061', 'guidance', 'Review data collection forms to eliminate unnecessary fields.', '2026-04-07T18:51:51.549195', '2026-04-07T18:51:51.549195', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('171f4f0a-88d5-44e1-bc3c-91d94fbb8926', '56394af4-39c8-4203-8202-0967d00cf12c', 'implementation_guidance', '["Create and maintain a data processing register covering all systems and processes handling personal data", "Document the lawful basis and intended purpose for each processing activity", "Require legal or privacy team validation before introducing new personal data processing activities", "Perform periodic reviews to ensure processing activities remain aligned with the documented lawful basis"]', '2026-04-07T18:00:21.708565', '2026-04-07T18:00:21.708565', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1757e68d-9002-4556-abb7-efd6a3a96999', '99281042-c4c3-4e72-bdac-3b6065074308', 'name', 'Implement Data Accuracy Validation and Correction Procedures', '2026-04-07T18:00:21.881952', '2026-04-07T18:00:21.881952', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1779dade-8112-453c-96c6-2c0cafcb6be4', 'e974a66b-6999-4076-beba-f6cda38d4955', 'description', 'Restrict physical access to facilities, data centers, and other secure areas using controlled entry mechanisms to prevent unauthorized individuals from accessing sensitive systems or equipment.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('17ef1ff0-2210-446d-8d17-5f7f649b2d9d', '29ba58f4-01cc-4ea8-99c2-742f36cc2e2c', 'acceptance_criteria', '["Retention schedule exists for personal data categories", "Retention rules are approved and documented"]', '2026-04-07T18:51:52.566198', '2026-04-07T18:51:52.566198', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('182a22aa-494b-4506-9951-39b43a36d790', '2b2927c1-14a9-49b3-ae30-5db30f52e9f0', 'acceptance_criteria', '["Privacy notice is publicly accessible", "Notice includes processing purposes and contact information", "Updates occur when processing practices change"]', '2026-04-07T19:36:41.844271', '2026-04-07T19:36:41.844271', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('18f6ad52-fe5c-42c5-9226-f6354e896974', 'fcd799bd-5663-4dbe-ac53-5eee7f57d15f', 'name', 'Plan and Evaluate ISMS Changes', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('18f78f0f-ba73-4038-8965-1916d23a3b54', '762df5cb-f8e9-41b5-92fe-564e8b7f33df', 'acceptance_criteria', '["A documented Statement of Applicability exists covering all Annex A controls", "Each control has a clear applicability status and justification", "The SoA links controls to relevant risks and implemented treatments", "The SoA is reviewed and updated after significant ISMS or risk changes"]', '2026-04-09T04:20:31.791874', '2026-04-09T04:20:31.791874', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('190501b4-4370-4a31-9974-333339ba81d6', '29ba58f4-01cc-4ea8-99c2-742f36cc2e2c', 'description', 'Create a documented retention schedule specifying retention periods for categories of personal data.', '2026-04-07T18:51:52.566198', '2026-04-07T18:51:52.566198', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1a16e47e-06e1-476d-99bb-bde1a51c84ba', '86c070c0-91b7-43ff-9c60-259e6df53c28', 'description', 'Implement mechanisms to obtain and record explicit consent from Data Principals before processing personal data where consent is required. Consent records provide evidence that processing is lawful and that individuals were properly informed. This reduces the risk of invalid or disputed consent.', '2026-04-07T18:00:21.755596', '2026-04-07T18:00:21.755596', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1a20d6d3-b087-41d6-b2b2-46c00c15128f', '35d4079b-2f12-4766-94ca-cc9ac44e1fd2', 'name', 'Maintain Lawful Basis Register for Personal Data Processing', '2026-04-07T19:13:14.03935', '2026-04-07T19:13:14.03935', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1a5d4f04-9c1c-43d6-810b-ceebed09125d', 'cb1fecf9-c6a8-44f9-b2c7-def42e267146', 'description', 'Conduct periodic internal assessments to evaluate adherence to DPDP controls and requirements.', '2026-04-07T19:36:48.961134', '2026-04-07T19:36:48.961134', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1aeeda54-0337-444e-8392-50e74da54687', '2f19fa6b-3132-4df7-bf1e-f06fa4c3fe1b', 'description', 'Maintain an inventory of personal data processing activities including purpose, categories of data, recipients, and retention periods.', '2026-04-07T18:58:56.704966', '2026-04-07T18:58:56.704966', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1b37ce7f-a2e2-443c-ab5a-81348b020e3a', '68c3432c-5f54-4aec-9b54-5974ece94a33', 'implementation_guidance', '["Identify business units, systems, and assets included in the ISMS.", "Document interfaces and dependencies with external systems or suppliers.", "Obtain management approval of the defined scope.", "Review scope when major organizational or technological changes occur."]', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1b4fb3ee-fa29-4bfc-a982-967975142fa6', '98b4583b-0c6f-49e5-a6d5-83179c06f3d1', 'guidance', 'Define classification levels such as public, internal, confidential, and restricted and ensure employees understand handling requirements.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1b84b313-4551-42db-b757-9ab9b60e327c', 'acf1b338-e2ae-482c-af35-5356fbd8d825', 'guidance', 'Privacy notices must be written in clear language and updated whenever processing practices change.', '2026-04-07T19:13:14.135822', '2026-04-07T19:13:14.135822', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1ba3c6fe-1c9d-44cb-92c8-ede84db6bfdf', '35d4079b-2f12-4766-94ca-cc9ac44e1fd2', 'implementation_guidance', '["Create and maintain a register of processing activities involving personal data", "Document lawful basis for each processing activity such as consent or legitimate use", "Link processing purposes with relevant systems, data categories, and business units", "Review the register periodically to ensure continued validity of the lawful basis"]', '2026-04-07T19:13:14.03935', '2026-04-07T19:13:14.03935', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1bb95a9b-de25-49a1-a2e6-dc84d29d964c', '49e1abd6-acf8-4de3-a9cd-6a2d212c6608', 'name', 'Enforce Strong Authentication for Administrative Accounts', '2026-04-07T18:29:03.371668', '2026-04-07T18:29:03.371668', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1c1a7be8-6358-48bb-a46e-cacd077338c8', 'acc1fd26-f64d-4f8f-a185-ec00e9a3810d', 'name', 'Publish Privacy Notice for Data Processing Activities', '2026-04-07T18:58:50.76989', '2026-04-07T18:58:50.76989', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1c403b32-8357-4351-98b4-f6b5ccdd9928', '5b5296da-9902-4c5d-8232-b601ab5f1852', 'acceptance_criteria', '["A centralized record of processing activities exists", "Each processing activity includes documented lawful basis", "The register is reviewed periodically for accuracy"]', '2026-04-07T19:36:39.573896', '2026-04-07T19:36:39.573896', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1c79110f-9c37-4c0e-bbc4-5d7e1561d19a', '513b86c7-f2a2-4401-b0fc-a677b6a71715', 'description', 'Administrative accounts responsible for managing systems processing personal data must be created only after validating mandatory identity attributes of the administrator. This ensures that privileged access is assigned to verified individuals and reduces risk of unauthorized administrative access.', '2026-04-07T19:19:31.331272', '2026-04-07T19:19:31.331272', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1cad3747-5fc4-484f-84ca-e67ffea595fe', 'a4011383-63b9-4c7d-8a82-5064dfc165df', 'description', 'Maintain documented contact information for relevant regulators, supervisory authorities, law enforcement, and incident response bodies. Established communication channels enable timely coordination during incidents and support regulatory compliance obligations.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1d1ad58a-8064-4450-ae27-e319d0d9d373', '8d92e6ee-7eb0-4ace-92ca-e2b7a0f4c7d9', 'name', 'Establish Personal Data Breach Response Procedure', '2026-04-07T18:00:22.013221', '2026-04-07T18:00:22.013221', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1d2ef049-a277-4e76-ae20-efcda47ced1d', 'c9fc9cfd-5fa4-4642-a595-26b42e4941e6', 'description', 'The organization establishes a formal governance charter that defines oversight responsibilities for information security, internal controls, and risk management. The charter documents leadership accountability, reporting lines, and decision authority to ensure security objectives are aligned with business strategy. This governance structure promotes consistent oversight of security risks and ethical conduct across the organization.', '2026-04-06T15:16:57.207266', '2026-04-06T15:16:57.207266', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1d8011dd-0308-438c-adde-4bd77b24b68d', '2bcbf2b5-dbcd-41d0-ad80-29043388323e', 'implementation_guidance', '["Define reconciliation checks for critical systems, transaction records, or data repositories.", "Automate integrity verification where possible using scripts or monitoring tools.", "Investigate and document discrepancies identified during reconciliation processes.", "Escalate significant anomalies through the incident management process.", "Retain reconciliation evidence and investigation records for audit purposes."]', '2026-04-06T15:17:13.707401', '2026-04-06T15:17:13.707401', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1dc153b8-1a4d-4875-baf0-1afe65efab60', 'd2035e09-3460-4afa-9d2e-b07166eb1053', 'implementation_guidance', '["Enable logging on critical systems, applications, and network infrastructure.", "Forward logs to a centralized logging or SIEM platform.", "Define alerting rules for suspicious or anomalous activities.", "Regularly review and retain logs according to security and compliance requirements."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1def22e6-43cb-43c5-84c8-9af62ae16220', 'e3cc508d-4eb4-43a6-a93a-d8e820ced1a9', 'acceptance_criteria', '["Access to personal data systems is role-based", "Access approvals are documented", "Periodic access reviews are conducted"]', '2026-04-07T19:13:14.44361', '2026-04-07T19:13:14.44361', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1df507c8-5317-443e-938d-ff528b0173e3', '892f3863-895d-4ba8-bcf0-7e3b14d3fc0d', 'guidance', 'Maintain incident records and integrate findings into risk management and control updates.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1e63b793-d8b4-471c-ab53-ca06cf3d0135', '06c7a2a2-fd07-4722-93ea-08faa4099ad9', 'guidance', 'Apply environmental safeguards and monitoring systems appropriate to the facility risk profile.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1e7e72ff-0e64-4368-bc46-3a8f3e133859', '573acf45-ec9f-4635-a188-8c7229490619', 'guidance', 'Data collection forms and APIs should enforce field-level validation aligned with defined processing purposes.', '2026-04-07T18:29:03.550262', '2026-04-07T18:29:03.550262', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1e878942-2107-405e-9faf-2c84d0492e0e', 'b61a8edb-cb85-4500-814b-607c2ce6fd0e', 'description', 'Establish a structured workflow to process Data Principal requests such as access, correction, or erasure of personal data.', '2026-04-07T18:58:51.742261', '2026-04-07T18:58:51.742261', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1eb88e28-bf95-4614-8ee5-82a015b5c68e', 'b6e361d7-079e-4f98-8170-8088e16fe228', 'name', 'Manage and Monitor Privileged Access Accounts', '2026-04-06T15:17:16.316161', '2026-04-06T15:17:16.316161', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1ee2eb79-9163-4f52-a162-f0967082b667', 'be04a4db-f834-43b4-b5d8-9f1c2ddd0970', 'description', 'Vendors with access to sensitive systems or data are periodically monitored to ensure their security posture remains acceptable. Ongoing oversight helps identify security control degradation, expired certifications, or emerging risks. This enables early detection of vendor-related risks that could impact system security or data protection.', '2026-04-06T15:17:29.901758', '2026-04-06T15:17:29.901758', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1ee58d60-6df8-4f59-9583-7f939dcd511f', 'b52c3aec-1593-47ee-a618-211ab9dbe57d', 'implementation_guidance', '["Provide user interfaces or portals allowing individuals to review and withdraw consent", "Update consent status in centralized consent management systems in real time", "Integrate consent status checks into processing workflows and APIs", "Verify through periodic testing that withdrawn consent halts related processing activities"]', '2026-04-07T18:00:21.779208', '2026-04-07T18:00:21.779208', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('1f0982e1-d057-4619-b85b-d1703e6d8e2c', '4cf09354-eac7-4e30-8747-1c93fee128cc', 'description', 'Perform regular reviews of user access rights to confirm they remain appropriate for current roles and responsibilities. This helps detect excessive privileges and unauthorized access that may accumulate over time.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('1f213b94-8b8b-4276-a51f-8f20413dd02d', '873c5dd9-14e1-44a3-aea2-e14f3cb3bef6', 'guidance', 'Implement a standardized background screening process aligned with applicable laws and job sensitivity levels. Ensure screening is completed before granting system access.', '2026-04-06T15:16:58.546367', '2026-04-06T15:16:58.546367', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('20180f2e-9e73-4232-9b2d-7e1efe5d23bb', '66d1ecd9-9c4c-434b-97fd-307c901116eb', 'description', 'Implement a structured information security awareness and training program for employees and contractors to ensure they understand their security responsibilities and can recognize potential threats.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('205e755a-7132-413d-bf54-06dd7c042ae8', '94d788d9-4311-4ed6-861d-6ee1cad7f485', 'guidance', 'Implement a centralized change management workflow requiring documented review and approval before deployment. Integrate approval checkpoints into development and operations processes.', '2026-04-06T15:17:11.166836', '2026-04-06T15:17:11.166836', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('209ea82f-f4a2-429d-8358-4a1b45c76795', 'b60d5a03-72bf-4c9f-a31c-a0c55d70adbc', 'guidance', 'Use a combination of internal monitoring, vendor feeds, and public intelligence sources.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('20bb0cca-8d4c-438b-8b40-8b49a1413713', 'af3b8516-e554-4a41-ae04-a47cd9de5b89', 'description', 'Conduct background verification for employees, contractors, and third-party personnel before granting access to organizational systems or sensitive information. Screening helps ensure personnel integrity and reduces the risk of insider threats or misuse of privileged access. The scope of checks should be proportionate to the sensitivity of the role.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('20ee65c2-dda7-4b1f-aea6-f1af36c3142e', 'b60d5a03-72bf-4c9f-a31c-a0c55d70adbc', 'description', 'Implement a structured program to collect, analyze, and disseminate threat intelligence relevant to the organization''s environment. Intelligence outputs help identify emerging threats, inform risk assessments, and guide defensive security strategies.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('21787911-57cc-4b69-844e-752560bcd3e6', 'c036a7dd-3d3e-4a20-871f-e6a31b43859f', 'guidance', 'Use centrally managed endpoint protection platforms with automated signature and engine updates.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('21dad6cc-8f64-4390-8b83-0ac4d4cc6290', '3ec0f435-1798-4fc6-bda2-139c9db28d3b', 'description', 'All vendor agreements must include defined security, privacy, and compliance obligations aligned with organizational policies. Contractual provisions ensure that vendors are legally bound to protect sensitive data and maintain appropriate security controls. This reduces exposure to regulatory violations and operational disruptions caused by third-party failures.', '2026-04-06T15:17:28.718447', '2026-04-06T15:17:28.718447', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('223d92e0-500e-4102-a5e3-d363f02ea1a4', '978bf834-b455-4388-89af-ca0d52980af5', 'acceptance_criteria', '["Data validation rules exist for critical personal data fields", "Periodic data quality reviews are documented"]', '2026-04-07T18:58:52.662174', '2026-04-07T18:58:52.662174', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('22c6a3d2-e54c-4ae1-8014-cf6792a57d7a', '573acf45-ec9f-4635-a188-8c7229490619', 'acceptance_criteria', '["Approved personal data fields are documented for each process", "Applications enforce validation rules for data collection", "Unauthorized data fields are not accepted by systems", "Periodic reviews confirm adherence to defined data collection scopes"]', '2026-04-07T18:29:03.550262', '2026-04-07T18:29:03.550262', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('233ee0e2-7319-4f38-a89f-99607809302f', 'b60d5a03-72bf-4c9f-a31c-a0c55d70adbc', 'name', 'Establish Threat Intelligence Monitoring and Analysis Program', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('23b31833-c6d6-46db-a604-ce8bf12d362d', 'b42db347-3967-4d44-b746-490c4ee02d83', 'implementation_guidance', '["Define conditions under which emergency changes may bypass standard timelines", "Require documentation of the issue, actions taken, and systems affected", "Limit emergency change authority to designated personnel", "Conduct a documented post\u2011implementation review within a defined timeframe", "Update change records and corrective actions if risks or issues are identified"]', '2026-04-06T15:17:26.717418', '2026-04-06T15:17:26.717418', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2457c2a8-1f99-41e9-9b8b-9d82e1898c81', '54bbc3bb-71df-4bab-ba4d-92a31375213f', 'implementation_guidance', '["Document incident response phases including identification, containment, eradication, recovery, and post-incident review", "Define incident severity classifications and response roles for technical and management teams", "Maintain contact lists and escalation procedures for internal teams and external stakeholders", "Conduct periodic tabletop exercises or simulations to test response readiness", "Document lessons learned and update procedures following significant incidents"]', '2026-04-06T15:17:22.231879', '2026-04-06T15:17:22.231879', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2480038a-19b5-43e2-8f21-b7f4f8032dce', '397b2d49-859b-4235-bf6c-2a6a98c90371', 'name', 'Implement Vulnerability Management Program', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('249c0140-c3b2-4f6e-906f-3b1b6a34df17', '7de36ea2-7dab-4802-9218-7528b6203b91', 'guidance', 'Use automated asset discovery tools where possible and assign owners responsible for maintaining asset records.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('258d0893-efb5-4bf4-9f39-6c2a9cb75487', 'a3f2462a-b47f-4f18-b66f-e9e7f9c6581e', 'description', 'Implement procedures to ensure all organizational assets such as devices, credentials, and documents are returned or securely transferred when personnel leave the organization or change roles. This reduces the risk of asset loss and unauthorized continued access.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('25a4cecc-4a9b-444f-b52c-fe581be539e1', 'e850596d-9344-4aca-86d1-609ca5c0c632', 'name', 'Perform Periodic DPDP Compliance Reviews', '2026-04-07T18:58:57.558116', '2026-04-07T18:58:57.558116', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('25be9ebb-ccf8-4c81-86f3-3fbfc7555bc1', '7ef84716-a138-494a-849f-8552d5f506b2', 'name', 'Maintain Inventory of Third‑Party Vendors and Service Dependencies', '2026-04-06T15:17:29.315175', '2026-04-06T15:17:29.315175', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('26ab2c97-9944-4737-9756-dc893b92c7b4', '20b8d630-fda1-4a25-af6c-4487ea86244b', 'implementation_guidance', '["Review all personal data collection forms", "Remove unnecessary data fields", "Document purpose for each collected data element", "Conduct periodic data minimization reviews"]', '2026-04-07T18:44:27.786296', '2026-04-07T18:44:27.786296', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('27453ea4-1a34-4b64-b4ad-8eb03fd53de2', '10e512b8-6796-4df8-a914-751cddc6e499', 'description', 'Establish and maintain a documented register of all applicable legal, statutory, regulatory, and contractual obligations related to information security, privacy, and data protection. The register ensures the organization understands its compliance responsibilities and integrates them into operational and security practices. It supports traceability of obligations to implemented controls.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('277f418c-1bac-4dcf-8fca-31e8b1a5dee2', '36402109-a8cc-4bca-aabe-24a07a074242', 'implementation_guidance', '["Define approved purposes for each data collection process", "Require privacy review before new collection activities", "Implement system checks preventing undefined purposes", "Maintain documentation of approved purposes"]', '2026-04-07T18:51:48.278807', '2026-04-07T18:51:48.278807', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('278724f4-3655-4457-86ac-77300c26f99d', '81683014-7616-4d66-b72c-cb2d6ad23155', 'guidance', 'Excessive collection increases regulatory risk and expands breach impact.', '2026-04-07T19:13:14.301928', '2026-04-07T19:13:14.301928', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('28153183-63a0-4c96-92e7-0d9201ca6da5', 'ea8285c6-5509-42f4-9c5d-5be9a888ac96', 'name', 'Define Personal Data Collection Standards', '2026-04-07T18:58:53.766787', '2026-04-07T18:58:53.766787', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('281aa743-93c3-4858-a3f6-950912f92b52', 'f5b150f5-007f-405a-9eae-35a6c94ca794', 'description', 'Conduct periodic internal reviews to evaluate whether privacy controls, policies, and procedures remain effective and aligned with regulatory changes. Continuous monitoring ensures ongoing compliance and supports timely updates to data protection practices.', '2026-04-07T18:00:22.319436', '2026-04-07T18:00:22.319436', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('2831aa05-b6ae-4499-aa01-ae5567c20580', '7232ce77-13ef-4583-affa-469e60f9d81d', 'description', 'The organization tracks remediation activities for identified security risks and ensures mitigation actions are implemented within defined timelines. Risk treatment plans may include control implementation, risk transfer, risk acceptance, or avoidance strategies. Continuous monitoring ensures unresolved risks are escalated and managed appropriately.', '2026-04-06T15:17:06.534805', '2026-04-06T15:17:06.534805', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('284057b3-4543-424e-90d1-dfe45d661fb0', '0266e7d1-a610-4e26-814e-6df8d4774521', 'name', 'Maintain Data Protection Compliance Documentation', '2026-04-07T19:36:48.148247', '2026-04-07T19:36:48.148247', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('2842d4a9-927a-4ded-96b7-56ce1a8a5488', '45448023-6de6-4ddd-93d3-85de7775b9db', 'description', 'When monitoring or testing identifies control deficiencies, remediation activities are validated to confirm that corrective actions were effectively implemented. Validation prevents recurring issues and ensures the root cause of the control failure has been addressed. Verified closure strengthens confidence in the control environment.', '2026-04-06T15:17:10.512142', '2026-04-06T15:17:10.512142', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('286bc2bf-db98-4495-a2b6-165b551fe809', 'c82506bd-f1bd-4e46-99cc-5db937b44b08', 'implementation_guidance', '["Require multi-factor authentication for privileged and remote access.", "Define password complexity, rotation, and lockout policies.", "Use secure token, certificate, or biometric authentication where appropriate.", "Protect authentication secrets and credentials using secure storage mechanisms."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('286e8996-1fb9-40e7-9fcb-e69b504c7c9d', '644898fc-e846-415f-b288-8d044e203c65', 'guidance', 'Incorporate security checkpoints and risk assessments into project governance processes.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('28bd3280-8e46-4c29-81a6-ada330a0fd91', '220f68b1-0691-4f4b-8c16-8589bdc5cb6f', 'implementation_guidance', '["Define the hierarchy of policies, standards, procedures, and guidelines", "Assign responsibility for maintaining governance documentation and oversight", "Align the governance framework with enterprise risk management processes", "Review and update governance documentation periodically or after major organizational changes"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('29b123cf-6522-4779-b7f2-d8d6d4dd1680', 'e3cc508d-4eb4-43a6-a93a-d8e820ced1a9', 'implementation_guidance', '["Implement role-based access controls for systems storing personal data", "Require approval before granting access privileges", "Review user access periodically", "Revoke access when roles change or employment ends"]', '2026-04-07T19:13:14.44361', '2026-04-07T19:13:14.44361', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('29d750a7-cc04-4465-a9e5-073e00d9f292', 'dd050bbc-e961-4345-8f58-de32b9c318a1', 'description', 'Implement mechanisms to identify and securely delete or anonymize personal data once retention periods expire or consent is withdrawn. Automated deletion reduces the risk of obsolete data being retained or exposed. Secure deletion practices ensure data cannot be reconstructed or recovered improperly.', '2026-04-07T18:00:21.948567', '2026-04-07T18:00:21.948567', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('29d757b1-acec-4c8e-b4f1-b7ac812a1a20', 'b9606853-dc9c-4770-9eb7-ef3040acc600', 'name', 'Maintain Centralized Information Security Risk Register', '2026-04-06T15:17:03.773311', '2026-04-06T15:17:03.773311', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2a4072ec-8df5-436d-95ec-4e1f6a60674d', '50b2fcae-0248-4ebd-bace-fe2042ec4f76', 'description', 'Evaluate and approve any transfer of personal data outside India to ensure compliance with government restrictions and approved jurisdictions under the DPDP Act. Risk assessments confirm that destination countries and receiving entities provide adequate protection for personal data.', '2026-04-07T18:00:22.101243', '2026-04-07T18:00:22.101243', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('2af990b3-32b3-4a03-ab6c-b03b616e0292', '892f3863-895d-4ba8-bcf0-7e3b14d3fc0d', 'description', 'Ensure all incidents are documented, investigated, and analyzed after resolution to identify root causes and control improvements. Lessons learned support continuous improvement of the organization''s security posture.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2b1abeb1-d7ac-4ca5-906c-f7f791d454c6', '23944a7a-86ca-44cf-9dda-646af9285768', 'name', 'Conduct Independent Internal Control Testing and Reviews', '2026-04-06T15:17:08.49601', '2026-04-06T15:17:08.49601', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2b5f25e7-28a8-4bbe-9a32-0929a796ef3b', 'cebf28f2-379b-45d0-9105-5ff32aa851d4', 'guidance', 'Administrative privileges should only be granted after appropriate approval and verification of role necessity.', '2026-04-07T18:29:03.504183', '2026-04-07T18:29:03.504183', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('2bc986e6-5d51-407e-b365-20f3b5722553', '3f51c19f-8007-4d80-9a08-142fca38e737', 'implementation_guidance', '["Review all data collection forms and APIs", "Identify unnecessary personal data fields", "Remove or justify excessive data collection", "Document approved data elements"]', '2026-04-07T19:36:43.86175', '2026-04-07T19:36:43.86175', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('2c14497d-21c6-4d9b-a66c-805f94589d43', 'ec516637-5c4e-4dc6-8e61-262c67e3a4c5', 'name', 'Manage Digital Identity Lifecycle', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2c2b853b-0f02-4161-bc72-91d20bcc0d34', '7ef84716-a138-494a-849f-8552d5f506b2', 'description', 'The organization maintains an up-to-date inventory of all third-party vendors, the services they provide, and the systems or data they access. Maintaining visibility into vendor dependencies supports effective oversight, risk tracking, and impact analysis. This helps ensure critical services and data exposures associated with vendors are clearly understood and managed.', '2026-04-06T15:17:29.315175', '2026-04-06T15:17:29.315175', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2c77f0c1-c326-4c20-8af4-f06898af20e1', 'a3f2462a-b47f-4f18-b66f-e9e7f9c6581e', 'implementation_guidance', '["Maintain records of assets assigned to employees and contractors", "Require asset return verification during termination or role transfer processes", "Revoke system access and recover authentication devices", "Confirm completion of asset return as part of HR offboarding checklists"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2cbd6c40-ecbc-42cb-889d-fba2dcb41fb4', '50b2fcae-0248-4ebd-bace-fe2042ec4f76', 'guidance', 'Implement a formal approval workflow requiring privacy or legal review before transferring personal data across borders.', '2026-04-07T18:00:22.101243', '2026-04-07T18:00:22.101243', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('2e00d257-9ac2-4490-ad07-a1d3f723b88d', 'a9a10778-3b51-4d71-b4ee-17a7a6cb9c9b', 'guidance', 'Conduct periodic disaster recovery and backup restoration exercises.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2e50db22-84df-4f7e-9863-be2119e7b3c9', '397b2d49-859b-4235-bf6c-2a6a98c90371', 'implementation_guidance', '["Conduct regular automated vulnerability scans of infrastructure and applications.", "Prioritize vulnerabilities based on severity and asset criticality.", "Track remediation activities through a formal ticketing or risk management process.", "Validate remediation by performing follow-up scans."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2ee0ce28-8055-4275-8bc1-6cd181199e1f', '037846f7-1941-4d75-8ff7-a8cbbe770ca3', 'guidance', 'Training should be role-based and regularly updated to reflect evolving threats, regulatory obligations, and internal policy changes.', '2026-04-09T04:20:31.950465', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2f1116cf-dcbd-495d-b824-351e56982c7e', 'cdb07056-602c-4716-abee-695e4f0807ab', 'guidance', 'Interested parties may include regulators, customers, partners, suppliers, and employees.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('2f31e2ae-cd4a-49cf-9c92-277dcdca08e9', '50b2fcae-0248-4ebd-bace-fe2042ec4f76', 'name', 'Assess and Approve Cross-Border Personal Data Transfers', '2026-04-07T18:00:22.101243', '2026-04-07T18:00:22.101243', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('2fa979b5-da33-4868-8a01-7c2f9d520803', '68054153-8595-4c5c-a1b9-19efe701bc36', 'description', 'Standardized secure configuration baselines are defined and applied to operating systems, cloud resources, databases, and network devices. These baselines ensure systems are hardened against common attack vectors and misconfigurations. Consistent enforcement reduces the risk of unauthorized access, vulnerabilities, and inconsistent security practices.', '2026-04-06T15:17:12.445575', '2026-04-06T15:17:12.445575', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3065d967-1a40-48c3-8ed9-638c745d7b26', 'd8e05c35-b6b0-4694-9745-f3395c6f4562', 'description', 'Establish a formal access control policy that defines how access to systems and data is requested, approved, and granted. The process ensures that access rights align with business needs and the principle of least privilege.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('30731e5b-0b8a-42ba-abd7-cf757a63b90a', 'af2212ca-5633-4b3d-bf2d-5631044687ee', 'name', 'Control ISMS Documented Information', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('30bd9ff5-0e2f-4d9d-891e-7a9d654bf10b', 'c1320778-ab81-407f-802a-232b40d61869', 'description', 'Establish measurable information security objectives aligned with organizational goals and ISMS policy.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('30d22e0f-e3d7-4e73-9b73-c215f3d55ff3', 'd824b0c1-df1b-40fd-8501-a60670bcbaff', 'name', 'Appoint Data Protection Officer and Establish DPIA Program', '2026-04-07T18:00:22.214777', '2026-04-07T18:00:22.214777', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('31776c92-5ab5-4c25-8175-a653a4ab0901', 'b811e989-24d9-43c3-a6b8-a143f4932db6', 'description', 'Document all cross-border transfers of personal data and monitor them to ensure ongoing compliance with regulatory requirements. Maintaining a transfer register supports regulatory audits and enables oversight of international data flows.', '2026-04-07T18:00:22.122997', '2026-04-07T18:00:22.122997', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('31a04da5-18ec-420d-a639-6c3bc05557d5', 'ab84b5b8-9099-4b0f-8735-db138b4edebc', 'guidance', 'Use automated vulnerability scanners and prioritize remediation based on risk severity.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('31f8ce92-2efa-422f-82dc-e536bd6a6edf', 'ffdbf966-a83e-4ad1-8406-bf7f8a6f57b7', 'description', 'Ensure top management conducts periodic reviews of the ISMS to evaluate its effectiveness, alignment with business objectives, and adequacy in addressing information security risks.', '2026-04-09T04:20:31.911119', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('32189340-5f13-4112-8c02-9164ad421079', 'd2081300-717e-4950-b793-28a3c7fb7116', 'implementation_guidance', '["Identify internal factors such as organizational structure, technologies, and internal capabilities.", "Identify external factors such as regulatory obligations, market conditions, and emerging threats.", "Document the context analysis within ISMS documentation.", "Review and update context analysis periodically or when significant changes occur."]', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('321baf0c-ca66-4cd6-963d-2d5560428ae8', '8444f18d-0495-47fb-8f3e-d8a7fd0fe0f2', 'name', 'Conduct Periodic ISMS Internal Audits', '2026-04-09T04:20:31.853682', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('324ecb9d-1ca7-40c4-b815-0e8e7f190e4b', '807bbd34-3b97-40c7-a51f-ba040ddfca0e', 'guidance', 'Maintain records demonstrating timely resolution and response.', '2026-04-07T19:36:46.081445', '2026-04-07T19:36:46.081445', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3269d9bd-8477-4412-b53f-ae5e385ef1b4', 'cc44ae6f-57ae-45a0-8fb9-9272f015a19d', 'description', 'Conduct periodic reviews to validate accuracy and completeness of stored personal data.', '2026-04-07T19:36:42.916279', '2026-04-07T19:36:42.916279', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('329a491b-89e1-4aa2-a539-d9559ce519e4', '18af81ca-6f2b-430b-8eaf-242c30cf4d3a', 'description', 'Limit processing of children''s personal data to permitted purposes and apply heightened security protections. Enhanced safeguards reduce the risk of misuse, profiling, or harmful processing activities involving children.', '2026-04-07T18:00:22.166489', '2026-04-07T18:00:22.166489', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('32cac62b-bb96-4ef1-8750-a669a14d82f4', 'f35c9188-b24f-41e3-ad14-8f2ac96f192a', 'description', 'Engage with professional security organizations, information sharing communities, or industry groups to stay informed about emerging threats, vulnerabilities, and best practices. These relationships enhance situational awareness and strengthen the organization''s defensive posture.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('33156603-eca9-407a-a83c-6693d88201fb', '447a437c-1817-4961-bd9f-3390f4781e3a', 'acceptance_criteria', '["Security incidents follow documented escalation workflows", "Incident response responsibilities are clearly defined", "Incident records are maintained for investigations"]', '2026-04-07T18:36:51.62446', '2026-04-07T18:36:51.62446', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('331da525-a0d5-4663-9c69-42424c670771', 'fcd799bd-5663-4dbe-ac53-5eee7f57d15f', 'guidance', 'Changes may include new technologies, regulatory requirements, or major business transformations.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('33c0a40d-a71e-476f-a5e0-e10d73c30ada', '644898fc-e846-415f-b288-8d044e203c65', 'description', 'Ensure information security requirements are identified and addressed during all phases of project management and system development. Embedding security early reduces the risk of introducing vulnerabilities or non‑compliant systems into production.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('33f3eb17-dfa7-4c2c-9945-c994b9a88a5d', 'be04a4db-f834-43b4-b5d8-9f1c2ddd0970', 'name', 'Monitor Vendor Security Posture and Compliance Periodically', '2026-04-06T15:17:29.901758', '2026-04-06T15:17:29.901758', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('34b69134-35a1-476f-a523-4138516cdd51', 'df0923d3-14cb-400e-9d2d-70bfecd7f022', 'description', 'Include mandatory information security and data protection requirements in contracts and service agreements with suppliers. These provisions establish clear expectations and accountability for protecting organizational information.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('34cac9b4-cdb7-42c3-9aab-80ee48a308f9', '20b8d630-fda1-4a25-af6c-4487ea86244b', 'description', 'Organizations must design systems to collect only the minimum personal data necessary for defined processing purposes.', '2026-04-07T18:44:27.786296', '2026-04-07T18:44:27.786296', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('352ac85e-b4c0-4bf4-aa7c-ce68dc5401f7', 'd2877bb5-08bd-48e3-9d3c-8d70455e7703', 'implementation_guidance', '["Restrict administrative access to log storage", "Use integrity checks or hashing mechanisms for log records", "Store logs in immutable or append-only storage where possible", "Monitor for unauthorized log modification attempts"]', '2026-04-07T18:36:49.912712', '2026-04-07T18:36:49.912712', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('35a5cfb7-7f8c-4ac1-ab5b-edc452db3a4c', '36402109-a8cc-4bca-aabe-24a07a074242', 'description', 'Ensure personal data is collected only for explicitly defined and approved purposes.', '2026-04-07T18:51:48.278807', '2026-04-07T18:51:48.278807', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('36501608-2892-4642-b276-53d073f96b27', 'be7b4390-4ce6-41ec-9395-ccdd8bc29b80', 'implementation_guidance', '["Define administrative roles and permission sets", "Assign privileges based on job responsibilities", "Review role assignments periodically", "Remove unnecessary privileges promptly"]', '2026-04-07T18:36:46.822792', '2026-04-07T18:36:46.822792', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3665a57d-9cee-4e7e-94c7-104e7cae02ec', 'cdb07056-602c-4716-abee-695e4f0807ab', 'description', 'Identify relevant interested parties and document their information security requirements that influence the ISMS.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('36869fe8-ad07-485f-ac05-427355fa8167', '94d788d9-4311-4ed6-861d-6ee1cad7f485', 'name', 'Enforce Formal Change Approval and Authorization Workflow', '2026-04-06T15:17:11.166836', '2026-04-06T15:17:11.166836', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('36a33cb5-0248-4759-a312-412e9167e183', '8d4080da-ac23-4efe-a90e-4b00af17484d', 'implementation_guidance', '["Define key security roles such as asset owners, system owners, and security administrators", "Document responsibilities within role descriptions or responsibility matrices", "Communicate security responsibilities during onboarding and role changes", "Maintain an up\u2011to\u2011date register of assigned information security roles"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('36b5b9c3-f0e6-484b-8ad3-c9716f056a7e', '5006dd25-c0e4-41d2-8559-550f8faebee8', 'implementation_guidance', '["Generate time-limited password reset tokens", "Send password reset links only to verified user email addresses", "Require additional identity verification for administrative password resets", "Log all password reset requests and completions"]', '2026-04-07T18:29:03.452906', '2026-04-07T18:29:03.452906', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('36ffa3ec-3a0e-4c51-90be-a595cf9612c8', '78949283-ef74-4348-9f54-59a6e1684de3', 'description', 'Perform Data Protection Impact Assessments (DPIAs) for high-risk personal data processing activities.', '2026-04-07T19:36:46.773235', '2026-04-07T19:36:46.773235', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('37a0cbe1-7844-4844-88ae-bd7dda32c2a7', 'dd050bbc-e961-4345-8f58-de32b9c318a1', 'implementation_guidance', '["Implement automated retention enforcement rules within databases or data management platforms", "Trigger deletion or anonymization workflows when retention thresholds are reached", "Maintain logs of deletion or anonymization activities for audit purposes", "Periodically validate that expired records are properly removed from primary and backup systems"]', '2026-04-07T18:00:21.948567', '2026-04-07T18:00:21.948567', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('37b46735-7502-4d65-b2ef-4a9e98bff067', 'a06a0924-7dbf-4fb5-8edd-a4d08b24253a', 'description', 'Multi-factor authentication (MFA) is required for access to critical systems, administrative interfaces, and remote network entry points. By requiring an additional authentication factor beyond passwords, the control significantly reduces the risk of credential compromise leading to unauthorized access.', '2026-04-06T15:17:15.699148', '2026-04-06T15:17:15.699148', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('37c7c515-85e2-441a-94ae-e8b21b780c3e', '71297127-54eb-4b99-b694-06b44a3b057f', 'description', 'System and security logs from critical infrastructure, applications, and security tools are centrally collected to support monitoring, investigation, and forensic analysis. Centralization ensures logs are protected from tampering and consistently retained according to defined retention policies. This control enables effective detection of suspicious behavior and supports incident response investigations.', '2026-04-06T15:17:19.570031', '2026-04-06T15:17:19.570031', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3816fe03-b327-44e9-9e72-aa54f29534a3', 'e8237a9e-c1bd-4b3b-9bf5-f2706c96cb1e', 'implementation_guidance', '["Install CCTV coverage at building entrances, exits, and sensitive operational areas.", "Implement intrusion alarms for restricted zones and outside operational hours.", "Maintain retention of surveillance recordings in accordance with policy and legal requirements.", "Review surveillance logs or alerts as part of physical security monitoring."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3829aca2-3367-4b54-846b-0e5e9073179a', '8bc87eed-60a6-47c7-9070-b0317f051d96', 'acceptance_criteria', '["Privacy notices are publicly accessible", "Notices describe processing purposes and rights", "Notices are reviewed and updated periodically"]', '2026-04-07T18:44:25.542471', '2026-04-07T18:44:25.542471', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('38305ec6-01d9-48f5-bf65-4dd685b230d6', 'adcdda32-228b-40d2-90f1-57ece4451bc2', 'implementation_guidance', '["Define approved channels for security communications such as intranet portals, email announcements, and internal collaboration platforms", "Publish security policy updates, procedural changes, and control expectations through centralized repositories accessible to staff", "Maintain a documented communication calendar for major policy updates and security notices", "Track acknowledgements or readership metrics for critical communications", "Archive communications to support audit and compliance verification"]', '2026-04-06T15:16:59.743104', '2026-04-06T15:16:59.743104', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('38a4da8c-cc32-4359-93ee-c217ca1023ee', 'e4acd353-17d3-46c2-ba20-14b19ca4f255', 'description', 'Regularly test backup and recovery procedures to ensure that critical systems and data can be restored within defined recovery objectives during disruptions or incidents.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('38c8adfb-318c-4d9d-b3a4-44f4e668af88', '3ec0f435-1798-4fc6-bda2-139c9db28d3b', 'guidance', 'Work with legal and security teams to maintain a standard security addendum for vendor contracts.', '2026-04-06T15:17:28.718447', '2026-04-06T15:17:28.718447', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('38df2966-547f-48dc-900b-03339a58a0e8', 'be7b4390-4ce6-41ec-9395-ccdd8bc29b80', 'description', 'Restrict administrative capabilities through role-based access control (RBAC) to ensure only authorized personnel can perform sensitive system actions.', '2026-04-07T18:36:46.822792', '2026-04-07T18:36:46.822792', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('38fe1044-a6f5-4c1a-bd86-bf3fd7146a64', '8184b1be-9a06-4f2d-9d2b-e178aab18542', 'name', 'Document Legal Basis for Personal Data Processing', '2026-04-07T18:51:46.984959', '2026-04-07T18:51:46.984959', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('39814f82-32af-4776-97cb-0ca2f7d7e385', '3f51c19f-8007-4d80-9a08-142fca38e737', 'acceptance_criteria', '["Data collection fields are documented and justified", "Unnecessary personal data fields are removed", "Periodic reviews of collection practices occur"]', '2026-04-07T19:36:43.86175', '2026-04-07T19:36:43.86175', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3992ebb8-56db-450c-a501-ed5afaa1bc30', '392c6c63-177c-4ff4-af85-c396f8ab033d', 'description', 'Ensure information security policies are reviewed regularly and updated when significant organizational, technological, or regulatory changes occur. This keeps policies aligned with current threats, operational practices, and compliance obligations.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3a930d3a-f5ad-4d6f-9675-46c5c71e2b90', '8184b1be-9a06-4f2d-9d2b-e178aab18542', 'acceptance_criteria', '["All processing activities have documented lawful basis", "Processing register is maintained and periodically reviewed"]', '2026-04-07T18:51:46.984959', '2026-04-07T18:51:46.984959', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3aa45b70-7159-4340-9617-9bee404252a4', 'd8e7688b-8ebe-43c7-a652-234d5d05e742', 'implementation_guidance', '["Define severity levels and response timelines for different alert categories", "Create documented runbooks for investigating common alert types", "Assign responsibility to a security operations function for daily alert monitoring", "Configure automated ticketing or case management for alert tracking", "Periodically review alert effectiveness and tune detection rules"]', '2026-04-06T15:17:20.245299', '2026-04-06T15:17:20.245299', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3ad5e6f6-a1f1-47f1-8eb3-f1368404a93c', 'ea8285c6-5509-42f4-9c5d-5be9a888ac96', 'guidance', 'Data collection forms and systems should be reviewed to remove unnecessary personal data fields.', '2026-04-07T18:58:53.766787', '2026-04-07T18:58:53.766787', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3aeccdef-b05c-44ce-a465-d1f93b99aa07', 'a4011383-63b9-4c7d-8a82-5064dfc165df', 'implementation_guidance', '["Identify relevant regulatory, supervisory, and law enforcement authorities", "Document official contact channels and escalation procedures", "Store the contact register in incident response documentation", "Review and update contact details periodically"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3b178028-4520-4f57-9f2a-556a734c66de', '1ec41473-07ef-465e-bae0-9e8fb1285b95', 'description', 'Establish documented plans that ensure critical ICT systems and services can continue operating or be restored during disruptions. These plans align ICT recovery objectives with broader business continuity requirements.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3b66ed5b-c242-43b1-9912-a12b3df2ab94', 'cc44ae6f-57ae-45a0-8fb9-9272f015a19d', 'guidance', 'Data quality checks should focus on records used in operational or decision-making processes.', '2026-04-07T19:36:42.916279', '2026-04-07T19:36:42.916279', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3bb4b7cc-9157-4038-8789-7aeb89819b0b', 'c1014a97-65e3-4708-a81f-5c6f44b101ea', 'description', 'The organization evaluates risks associated with third‑party service providers, processors, and vendors that access organizational systems, process sensitive information, or support critical business operations. Vendor security risk assessments help identify potential threats related to data protection, service availability, and regulatory compliance before establishing or continuing business relationships.', '2026-04-06T15:17:05.877428', '2026-04-06T15:44:43.484375', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3bc9fa6d-9526-4c85-854d-90669377782b', '617f8959-749c-4046-9d9b-0ad32abc20d1', 'description', 'Security and compliance due diligence must be performed before engaging any third-party service provider that will access company systems, process data, or support critical services. This control ensures vendors meet minimum security, privacy, and operational resilience expectations before contractual engagement. It reduces the risk of introducing insecure or non‑compliant partners into the organization''s environment.', '2026-04-06T15:17:28.021666', '2026-04-06T15:17:28.021666', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3c16c130-996e-4869-8547-ccd38f2e36b5', 'd4095971-8355-49cd-905c-bcfb20d22fe1', 'name', 'Enforce Data Minimization in Collection and Processing', '2026-04-07T18:00:21.90538', '2026-04-07T18:00:21.90538', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3c74431d-29eb-4683-b42c-3dd8b8eab9c9', '68054153-8595-4c5c-a1b9-19efe701bc36', 'name', 'Establish and Enforce Secure System Configuration Baselines', '2026-04-06T15:17:12.445575', '2026-04-06T15:17:12.445575', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3d5462c9-01af-491e-92f6-76505c5c69d7', '7de36ea2-7dab-4802-9218-7528b6203b91', 'name', 'Maintain Inventory of Information Assets', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3e041fdc-784e-4d12-ad32-c1d01fb1f427', '80ca07cf-eb89-4294-aa8e-938b8abb0858', 'guidance', 'The inventory should include application ownership, processing purposes, data categories, and associated data processors.', '2026-04-07T19:19:31.394795', '2026-04-07T19:19:31.394795', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3e1ae742-429c-46c8-ab1f-af410ee85a8c', 'ab045248-5b25-4404-9cfe-e640e6e27508', 'name', 'Document Lawful Basis for Personal Data Processing', '2026-04-07T18:44:23.712969', '2026-04-07T18:44:23.712969', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3e336b5e-fbfb-4ad3-99f8-7827ff9db93c', '66e2d32a-d929-44a3-bc0e-8846e4a55cde', 'description', 'Security monitoring systems such as logging platforms, SIEM tools, and monitoring dashboards are protected from unauthorized access or tampering. Restricting administrative access ensures that attackers cannot disable monitoring capabilities or manipulate evidence. This control preserves the integrity and reliability of operational security monitoring.', '2026-04-06T15:17:23.493885', '2026-04-06T15:17:23.493885', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3f0c9a87-54de-4f5a-848f-4899a7f80a85', '98b4583b-0c6f-49e5-a6d5-83179c06f3d1', 'description', 'Implement a formal information classification scheme that categorizes information assets based on sensitivity, confidentiality, integrity, and availability requirements. The scheme ensures consistent protection measures and handling procedures for different types of information.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3f6db2c1-6a6d-4a07-9257-ae0ce412503b', '4599995a-e91f-4505-9431-bdbd8f2b1654', 'name', 'Implement Segregation of Duties for Privileged and Sensitive Operations', '2026-04-06T15:17:11.825755', '2026-04-06T15:17:11.825755', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('3f7bd364-6816-4447-b38c-5a4192018cfa', '2b2927c1-14a9-49b3-ae30-5db30f52e9f0', 'guidance', 'Privacy notices should be accessible at the point of data collection and reviewed periodically.', '2026-04-07T19:36:41.844271', '2026-04-07T19:36:41.844271', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('3fe5df72-8de3-4e73-a4df-04680c7dcc1a', '4c3b6503-ee7f-47a8-94ec-1ce0e4d18d03', 'description', 'Physical access to offices, data centers, and other sensitive infrastructure areas is restricted to authorized personnel using controlled entry mechanisms. Access controls such as badge systems and visitor management reduce the risk of unauthorized individuals accessing critical systems or equipment.', '2026-04-06T15:17:18.239609', '2026-04-06T15:17:18.239609', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('4031cf05-d6c8-4ade-8daf-0fc3ad811171', '09be1965-a848-4f25-9954-4fd11f08c114', 'guidance', 'Provide secure and confidential reporting channels and ensure personnel are informed about how and when to use them.', '2026-04-06T15:17:00.783771', '2026-04-06T15:17:00.783771', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('41b33845-c221-4a84-bc55-94b9ce45ba2b', 'a9a10778-3b51-4d71-b4ee-17a7a6cb9c9b', 'name', 'Test Backup and System Recovery Capabilities', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('42300c6a-1d44-4219-9081-789dbace0751', 'c7ca56ce-ffe2-4530-b78b-7ee26051aa17', 'guidance', 'Deploy infrastructure and application monitoring tools with alert thresholds for abnormal system behavior. Ensure alerts are integrated with operational response processes.', '2026-04-06T15:17:21.54828', '2026-04-06T15:17:21.54828', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('42470ffa-8b02-4c49-8779-ded2589805d4', '71297127-54eb-4b99-b694-06b44a3b057f', 'guidance', 'Deploy a centralized logging or SIEM platform that aggregates logs from all in-scope systems. Define retention, protection, and integrity requirements for collected logs.', '2026-04-06T15:17:19.570031', '2026-04-06T15:17:19.570031', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('426094bd-fcce-4515-a462-fde7bb112700', 'c036a7dd-3d3e-4a20-871f-e6a31b43859f', 'implementation_guidance', '["Deploy endpoint protection software across all supported systems.", "Enable real-time malware scanning and behavioral threat detection.", "Configure automatic updates for malware signatures and detection engines.", "Centralize alerts and monitoring through security management platforms."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('428b84c4-acba-4e05-aba7-2034da0adc40', '5b5296da-9902-4c5d-8232-b601ab5f1852', 'description', 'Establish and maintain a formal Record of Processing Activities (ROPA) documenting all processing of personal data, including purposes, lawful basis, categories of personal data, and involved systems or processors.', '2026-04-07T19:36:39.573896', '2026-04-07T19:36:39.573896', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('4316ea26-7078-4d7f-be53-670f4f6fb806', '8444f18d-0495-47fb-8f3e-d8a7fd0fe0f2', 'acceptance_criteria', '["An ISMS internal audit schedule is defined and executed", "Audit reports document findings, evidence, and recommendations", "Nonconformities are tracked with corrective actions and closure evidence", "Audit outcomes are communicated to management and governance bodies"]', '2026-04-09T04:20:31.853682', '2026-04-09T04:20:31.853682', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('431c6856-7882-42a1-8b99-e23ee5d66ea1', '6edc90f7-0262-4abb-9243-383279252a6b', 'name', 'Perform Security Due Diligence Before Engaging Data Processors', '2026-04-07T18:00:22.056975', '2026-04-07T18:00:22.056975', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('4341ccc7-7a29-4915-abc9-cad2c9e2a750', 'e6097f6d-3449-4662-a8ec-2e01bce7be8c', 'name', 'Implement Continuous Security Event Monitoring', '2026-04-06T15:17:07.173021', '2026-04-06T15:17:07.173021', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('43d9c9e9-59b9-41b7-b16c-7cca235c5ca6', '20b8d630-fda1-4a25-af6c-4487ea86244b', 'name', 'Restrict Personal Data Collection to Necessary Fields', '2026-04-07T18:44:27.786296', '2026-04-07T18:44:27.786296', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('441cb923-3cc2-4283-95f7-af4087a032be', 'f35c9188-b24f-41e3-ad14-8f2ac96f192a', 'name', 'Participate in Industry Security Forums and Threat Sharing Groups', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('442af422-23af-46f2-ae8f-891aff8e8e68', '95f9d4c4-0d22-48f1-a5aa-4fde70eba35f', 'description', 'Continuously monitor cloud environments to detect misconfigurations, suspicious activities, and deviations from defined security baselines. Monitoring helps identify threats and prevent exposure of sensitive information in cloud platforms.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('444097b6-c7aa-4e8d-9deb-c3104ecbd56e', '3dcb224b-7d8e-4b70-9a81-9b726329608f', 'name', 'Implement Data Principal Rights Request Handling Process', '2026-04-07T18:00:21.828555', '2026-04-07T18:00:21.828555', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('4539b7c4-fa9a-4191-a518-03d71f3a3556', 'f97f2c1f-d952-4dcd-90f7-a0dc776efb71', 'acceptance_criteria', '["Processing purposes are documented for all datasets", "Systems restrict use of data outside approved purposes", "Periodic reviews confirm compliance with defined purposes"]', '2026-04-07T19:36:40.518698', '2026-04-07T19:36:40.518698', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('4540bfd5-7311-49d9-ab2a-efbd17a97957', 'acc1fd26-f64d-4f8f-a185-ec00e9a3810d', 'description', 'Provide publicly accessible privacy notices describing how personal data is collected, used, retained, and shared.', '2026-04-07T18:58:50.76989', '2026-04-07T18:58:50.76989', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
