      ('478fbe2c-9b05-4862-ad50-9eb0f104ea13', 'e4acd353-17d3-46c2-ba20-14b19ca4f255', 'guidance', 'Simulate restoration scenarios to validate backup integrity and recovery procedures.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('47f6b586-d941-4fee-b421-9549eee667f3', 'b9606853-dc9c-4770-9eb7-ef3040acc600', 'description', 'The organization maintains a centralized risk register to document identified risks affecting systems, processes, data, and third parties. The register records risk descriptions, likelihood, impact, ownership, mitigation status, and review dates. This ensures risks are consistently tracked, prioritized, and managed over time.', '2026-04-06T15:17:03.773311', '2026-04-06T15:17:03.773311', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
