      ('48be3e02-f634-48e5-b1b3-c4ae6381e91e', 'a469476d-d763-406e-8727-2d48ac513084', 'guidance', 'Document permitted transfer methods, security expectations, and responsibilities with third parties.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
