      ('49e94279-b28a-42aa-aa66-ffffdda56c83', 'e4acd353-17d3-46c2-ba20-14b19ca4f255', 'implementation_guidance', '["Define recovery time objectives (RTO) and recovery point objectives (RPO).", "Perform periodic restoration tests for critical systems and databases.", "Document test outcomes and remediation actions.", "Update continuity plans based on lessons learned from recovery exercises."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('4a566ce4-5877-48bf-a590-19dcbc8675b3', '49e1abd6-acf8-4de3-a9cd-6a2d212c6608', 'implementation_guidance', '["Require multi-factor authentication for all administrative accounts", "Enforce strong password policies including minimum length and complexity", "Disable default administrative accounts or require credential changes before activation", "Monitor administrative login attempts and lock accounts after repeated failures"]', '2026-04-07T18:29:03.371668', '2026-04-07T18:29:03.371668', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
