      ('51301706-3d5c-487b-b2ec-5399f76b55bc', '1996d6fb-40fe-4981-a566-62b52b1f176e', 'implementation_guidance', '["Include data processing agreements defining scope of processing and security responsibilities", "Require processors to report personal data breaches within defined timelines", "Mandate compliance with applicable privacy laws and organizational security policies", "Require rights to audit or obtain assurance reports from processors handling personal data"]', '2026-04-07T18:00:22.079337', '2026-04-07T18:00:22.079337', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
