      ('51e882fc-ce8e-43da-bbb9-caadd2163afe', '45448023-6de6-4ddd-93d3-85de7775b9db', 'implementation_guidance', '["Document corrective action plans for each identified control deficiency", "Require supporting evidence demonstrating that remediation actions were implemented", "Perform follow-up testing or validation of corrected controls", "Ensure remediation items are formally approved before closure", "Retain remediation and validation records for audit and compliance purposes"]', '2026-04-06T15:17:10.512142', '2026-04-06T15:17:10.512142', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
