      ('67c39f03-8924-4267-bbf4-d135203552fc', 'c1320778-ab81-407f-802a-232b40d61869', 'guidance', 'Objectives should include measurable indicators and monitoring mechanisms.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('68243d28-f54f-4142-9b59-c9a94290363e', '04c83c8e-e4e6-4951-acea-6f43493331d7', 'implementation_guidance', '["Store all approved security policies, standards, and procedures in a centralized document management system", "Implement version control and change history tracking for all security documentation", "Restrict editing privileges to authorized policy owners while allowing read access to relevant personnel", "Implement periodic reviews to confirm documentation remains current and aligned with regulatory requirements", "Notify employees when significant policy revisions are published"]', '2026-04-06T15:17:00.161767', '2026-04-06T15:17:00.161767', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('68462cb8-390d-44f2-9f97-fb3070c9b3d9', '276d9ce2-0808-4ec2-b11d-9e6abc5b8cd1', 'implementation_guidance', '["Provide mandatory security awareness training during employee onboarding", "Deliver periodic refresher training covering security policies, data protection, and incident reporting", "Track training completion through a learning management system or training register", "Require additional specialized training for personnel with privileged or security roles"]', '2026-04-06T15:16:58.91588', '2026-04-06T15:16:58.91588', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('6848ced9-521b-4155-8f28-b1b4080536d9', '3ec0f435-1798-4fc6-bda2-139c9db28d3b', 'implementation_guidance', '["Include a standardized data protection and information security addendum in vendor contracts", "Require vendors to implement encryption, access controls, and incident reporting obligations", "Define breach notification timelines and cooperation requirements for security investigations", "Include right-to-audit clauses and requirements for maintaining security certifications where applicable"]', '2026-04-06T15:17:28.718447', '2026-04-06T15:17:28.718447', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('6956f942-8af9-4891-acd1-8177987f5e0a', '58f06dce-a956-4fc2-8296-d00129e311cd', 'name', 'Control and Maintain ISMS Documented Information', '2026-04-09T04:20:31.993586', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('696d1ec8-a51b-4b7a-9ddc-a0fbcf73f369', '8c10560c-13fc-40b8-ad63-85028278507c', 'guidance', 'Use an issue or exception tracking system to document deviations, assign owners, and monitor remediation progress.', '2026-04-06T15:17:14.353424', '2026-04-06T15:17:14.353424', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('69787c5d-b613-41a5-8137-597d9bd0a3cd', 'f436e044-b778-4cfa-affc-0d0972c4ea9d', 'guidance', 'Retention schedules should align with legal obligations and processing purposes.', '2026-04-07T18:58:54.799828', '2026-04-07T18:58:54.799828', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('6979c2dd-5e89-438c-908f-f1c99264a7b6', '447a437c-1817-4961-bd9f-3390f4781e3a', 'description', 'Define escalation procedures and response workflows for security alerts and incidents involving personal data systems.', '2026-04-07T18:36:51.62446', '2026-04-07T18:36:51.62446', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
