      ('791329a9-34c9-4a94-9b3a-a4fa8047d11d', '5941b7d5-2d87-4ccf-888d-1fa8a300cf85', 'implementation_guidance', '["Document systems and processes handling personal data", "Record purposes of processing and data categories", "Maintain records of third parties receiving personal data", "Update records when processing activities change"]', '2026-04-07T19:13:14.510545', '2026-04-07T19:13:14.510545', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('791712ea-0abb-434c-a51e-f901753139d2', '7ab5c678-2e60-4f36-b832-e4693593e6a2', 'name', 'Establish Incident and Breach Communication Procedures', '2026-04-06T15:17:01.705747', '2026-04-06T15:17:01.705747', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
