      ('7a2e01bb-5135-47f8-a075-0213e4b8f1f1', 'e8237a9e-c1bd-4b3b-9bf5-f2706c96cb1e', 'name', 'Deploy Physical Surveillance and Intrusion Detection', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7a3d8b62-50d7-48b2-a71c-092e8ea0581f', '4d70ecb5-3e04-402d-bdef-a5bdaa3f9f2f', 'guidance', 'Use approved vulnerability scanning tools integrated with asset inventories. Schedule recurring scans and track remediation activities through a formal workflow.', '2026-04-06T15:17:20.930915', '2026-04-06T15:17:20.930915', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7a42dfd5-ab43-4cad-8fda-23828e0dc499', 'c2ef645c-6a8d-428e-aabc-2c71f95a73a9', 'description', 'Restrict physical access to facilities and secure areas containing information systems or sensitive information. Access controls ensure that only authorized personnel can enter restricted locations, reducing the risk of physical tampering, theft, or unauthorized system access.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7a53070a-f885-4c56-a1f1-e987ad7ea62b', 'c17b7e42-fd63-4d57-92cb-6fadf30a244c', 'guidance', 'Integrate vendor offboarding steps into procurement, legal, and access management processes.', '2026-04-06T15:17:31.086078', '2026-04-06T15:17:31.086078', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7b66d47c-32da-4770-a1ea-13afdd9a9cd3', '04c83c8e-e4e6-4951-acea-6f43493331d7', 'description', 'Maintain a centralized, version-controlled repository where current security policies, procedures, and control documentation are stored and accessible to relevant personnel. This ensures employees can easily locate authoritative guidance and prevents the use of outdated or inconsistent documentation.', '2026-04-06T15:17:00.161767', '2026-04-06T15:17:00.161767', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7b6f1438-6832-4f8b-9ba8-dc22ec8ecf41', 'f97f2c1f-d952-4dcd-90f7-a0dc776efb71', 'name', 'Purpose Validation Before Personal Data Use', '2026-04-07T19:36:40.518698', '2026-04-07T19:36:40.518698', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('7bc8c73b-2d5f-4d26-a849-f96b13417180', 'adcdda32-228b-40d2-90f1-57ece4451bc2', 'guidance', 'Define official communication channels and schedules for distributing security-related information. Ensure communications are tracked and archived for accountability.', '2026-04-06T15:16:59.743104', '2026-04-06T15:16:59.743104', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7bde658f-32d9-4d13-8852-87aa5d0b8c24', '903688bb-be06-453c-8f4f-5ed38d09361e', 'guidance', 'Integrate training into onboarding and require periodic refresher courses aligned with emerging threats.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7c0c53d9-6b8c-4d6a-9f78-24098aa3fb3f', 'c17b7e42-fd63-4d57-92cb-6fadf30a244c', 'implementation_guidance', '["Revoke all system accounts, API keys, VPN access, and integrations associated with the vendor", "Require written confirmation of secure deletion or return of organizational data", "Verify termination of data processing activities and subcontractor access", "Update vendor inventory and risk records to reflect contract termination"]', '2026-04-06T15:17:31.086078', '2026-04-06T15:17:31.086078', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7c243b32-69b2-470d-88fe-dee076dbd6df', '1ec5e73a-a759-428b-b6a1-d4da25595173', 'guidance', 'Integrate age verification and parental consent mechanisms into user registration or data collection processes where children may be involved.', '2026-04-07T18:00:22.14531', '2026-04-07T18:00:22.14531', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('7c964a06-0d5e-4f24-91e1-297c26bd5e02', '3523377d-20ab-440f-bf84-9ec6866a1118', 'name', 'Maintain Information Security Risk Register', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7d3258b3-949c-4dd7-93f0-3e19a382cc72', 'c5261520-054b-4147-8cbf-7fa1c3999280', 'name', 'Provide Standardized Privacy Notices', '2026-04-07T18:51:49.896325', '2026-04-07T18:51:49.896325', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('7dc61111-dd43-4da1-a920-82f6794f7c51', '09be1965-a848-4f25-9954-4fd11f08c114', 'implementation_guidance', '["Implement a dedicated reporting channel such as a security hotline, ticketing portal, or anonymous reporting platform", "Allow anonymous reporting where permitted by law to encourage disclosure of concerns", "Define procedures for triaging, investigating, and documenting reported issues", "Ensure reported concerns are escalated to the appropriate security or compliance personnel", "Maintain audit trails of reported issues and their resolution status"]', '2026-04-06T15:17:00.783771', '2026-04-06T15:17:00.783771', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('7e59d09e-c300-40b0-9105-3102b09a95d7', 'b0e1f9de-f123-4fec-a59b-ed666c7a7acf', 'guidance', 'Deletion processes should prevent recovery of sensitive personal data from systems or storage media.', '2026-04-07T19:13:14.392032', '2026-04-07T19:13:14.392032', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('7e847709-9045-4498-9ef8-183f606b4b16', '6edc90f7-0262-4abb-9243-383279252a6b', 'implementation_guidance', '["Assess processor security policies, certifications, and privacy practices during vendor onboarding", "Evaluate technical controls such as encryption, access management, and incident response capabilities", "Document risk assessment results and obtain security or privacy approvals before engagement", "Require remediation plans for identified control gaps before processing personal data"]', '2026-04-07T18:00:22.056975', '2026-04-07T18:00:22.056975', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('7e87108f-2f47-4203-b88b-53f8742927ad', '5941b7d5-2d87-4ccf-888d-1fa8a300cf85', 'guidance', 'Processing records support regulatory inspections and internal compliance monitoring.', '2026-04-07T19:13:14.510545', '2026-04-07T19:13:14.510545', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('7fa59e71-dd2d-49d5-8741-9c612621b9d3', '5941b7d5-2d87-4ccf-888d-1fa8a300cf85', 'name', 'Maintain Record of Personal Data Processing Activities', '2026-04-07T19:13:14.510545', '2026-04-07T19:13:14.510545', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('800c52c9-1063-4bd3-8aca-f6d842f78273', '7de36ea2-7dab-4802-9218-7528b6203b91', 'description', 'Establish and maintain an accurate inventory of information assets including hardware, software, data repositories, and supporting infrastructure. The inventory ensures visibility of assets requiring protection and supports risk management, lifecycle management, and incident response.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('805937e8-396c-48a0-b4a3-66674391ea7f', 'b784da50-d22a-449f-a943-7192604c4217', 'implementation_guidance', '["Define actions requiring dual authorization", "Implement approval workflows in administrative tools", "Record approvals and actions in audit logs", "Periodically review destructive action approvals"]', '2026-04-07T18:36:48.541216', '2026-04-07T18:36:48.541216', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('809202bc-3e59-4f47-a330-fc41b2f91da6', 'b784da50-d22a-449f-a943-7192604c4217', 'name', 'Require Dual Authorization for Destructive Administrative Changes', '2026-04-07T18:36:48.541216', '2026-04-07T18:36:48.541216', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('8094455f-55bb-497c-9a57-7aeff31e9d93', '7c72fd6d-8385-4136-acb6-147f88156d97', 'name', 'Establish Information Classification Scheme', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('81bfb5b5-6650-4bbc-b665-1d91ad2e313d', '7eb70961-0f22-4a01-bfae-e974e9febac6', 'guidance', 'Communication should define who communicates, what information is shared, and timing requirements.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
