      ('918ae75a-3e0c-40f7-aaff-b8053765e41b', 'ac52cfed-eb29-41ba-a1c6-87c627bbac6a', 'guidance', 'Audits should be performed by independent internal audit teams or qualified third parties.', '2026-04-07T19:36:47.46516', '2026-04-07T19:36:47.46516', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
