      ('91e93f64-0cc2-4f74-b7ef-5464f5a03cca', '892f3863-895d-4ba8-bcf0-7e3b14d3fc0d', 'name', 'Conduct Incident Documentation and Post‑Incident Reviews', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9217236e-0640-4839-8c9d-818e7ffd5978', 'b61a8edb-cb85-4500-814b-607c2ce6fd0e', 'name', 'Implement Data Principal Request Handling Workflow', '2026-04-07T18:58:51.742261', '2026-04-07T18:58:51.742261', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('9274463d-dcff-4d5e-8108-31181de91029', 'c7ca56ce-ffe2-4530-b78b-7ee26051aa17', 'implementation_guidance', '["Implement monitoring tools that collect metrics such as CPU, memory, network activity, and service availability", "Configure automated alerts for abnormal thresholds or service outages", "Integrate operational alerts with incident or ticket management systems", "Review monitoring dashboards regularly to identify patterns or anomalies", "Periodically test alerting mechanisms to ensure operational effectiveness"]', '2026-04-06T15:17:21.54828', '2026-04-06T15:17:21.54828', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('92b69027-65d3-4012-a163-95cc3adff1a7', '8184b1be-9a06-4f2d-9d2b-e178aab18542', 'guidance', 'Maintain a processing register identifying the legal basis for each processing activity.', '2026-04-07T18:51:46.984959', '2026-04-07T18:51:46.984959', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('939dee21-4bfe-41a1-a21c-952465f54911', 'f97f2c1f-d952-4dcd-90f7-a0dc776efb71', 'guidance', 'Applications and business processes should enforce purpose-based access restrictions where feasible.', '2026-04-07T19:36:40.518698', '2026-04-07T19:36:40.518698', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('945dd22c-051c-4d97-92a8-7436d9e1993e', '00b82e4d-76fe-493e-b403-3679656c8ff3', 'description', 'Protect information during transmission by requiring secure transfer protocols and encryption mechanisms. This reduces the risk of interception, alteration, or unauthorized disclosure of data while in transit.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('948d2d12-d4c5-4886-a346-9c7585adaf73', '56394af4-39c8-4203-8202-0967d00cf12c', 'name', 'Document Lawful Basis for Personal Data Processing', '2026-04-07T18:00:21.708565', '2026-04-07T18:00:21.708565', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('94b8deef-fbef-4123-85a2-dcb7ff84c4b7', '513b86c7-f2a2-4401-b0fc-a677b6a71715', 'guidance', 'Identity attributes such as corporate email, employee identifier, and role justification should be validated before account activation.', '2026-04-07T19:19:31.331272', '2026-04-07T19:19:31.331272', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('950207bb-763e-4c13-970e-e0f6761a84e7', '81933d25-9eee-4cf0-96a7-c34dac85fab7', 'description', 'Ensure that information transferred between internal systems, users, and external parties is protected using secure communication protocols and encryption mechanisms to prevent interception, alteration, or unauthorized disclosure.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('954c1984-321b-4510-a80f-2df91327a7eb', 'c1014a97-65e3-4708-a81f-5c6f44b101ea', 'guidance', 'Establish a vendor risk assessment process that evaluates security posture, compliance status, and data protection practices prior to onboarding vendors and periodically thereafter.', '2026-04-06T15:17:05.877428', '2026-04-06T15:44:43.484375', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('957f178e-16e6-4da5-810d-a6a631ed7099', '54bbc3bb-71df-4bab-ba4d-92a31375213f', 'description', 'A documented incident response process defines how security incidents are identified, contained, investigated, and resolved. The process ensures consistent coordination among technical teams, management, and compliance stakeholders. Effective incident response minimizes damage, restores operations quickly, and supports regulatory reporting obligations when required.', '2026-04-06T15:17:22.231879', '2026-04-06T15:17:22.231879', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9589dea5-ae42-409a-9c16-4cd7bdb54efc', '1ec41473-07ef-465e-bae0-9e8fb1285b95', 'implementation_guidance', '["Define recovery time objectives (RTO) and recovery point objectives (RPO) for critical services.", "Document failover, restoration, and communication procedures during outages.", "Assign responsibilities for ICT continuity execution during incidents.", "Ensure plans align with the organization\u2019s broader business continuity program."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('95c7af01-9752-47fd-9ec0-796b25e1d9c6', '8bc87eed-60a6-47c7-9070-b0317f051d96', 'description', 'Organizations must publish a clear and accessible privacy notice describing personal data processing purposes, data categories, rights, and grievance channels.', '2026-04-07T18:44:25.542471', '2026-04-07T18:44:25.542471', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('9617700f-e391-4408-9abd-68ca214bba3e', 'b42db347-3967-4d44-b746-490c4ee02d83', 'guidance', 'Define criteria for emergency changes and require retrospective review and documentation after implementation.', '2026-04-06T15:17:26.717418', '2026-04-06T15:17:26.717418', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9665bfcc-18ba-4f62-8cf7-1994cdb4c42a', '99281042-c4c3-4e72-bdac-3b6065074308', 'guidance', 'Introduce validation rules and correction procedures within systems handling personal data.', '2026-04-07T18:00:21.881952', '2026-04-07T18:00:21.881952', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('967f6922-5c2e-4bfa-a7c7-3be21179fc89', '873c5dd9-14e1-44a3-aea2-e14f3cb3bef6', 'implementation_guidance', '["Define background screening requirements based on role sensitivity and access level", "Conduct identity verification, employment history checks, and criminal record checks where legally permissible", "Require successful screening completion before provisioning access to critical systems", "Maintain documentation of screening outcomes and approvals in HR records"]', '2026-04-06T15:16:58.546367', '2026-04-06T15:16:58.546367', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9701b33c-1712-4de2-b2ba-98a8903b625a', '892f3863-895d-4ba8-bcf0-7e3b14d3fc0d', 'implementation_guidance', '["Record incident timelines, impact assessments, and response actions.", "Conduct post\u2011incident reviews with relevant stakeholders.", "Identify corrective actions and track remediation tasks to completion.", "Update policies, controls, and awareness training based on lessons learned."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('972deca4-2c2f-4e6b-ad1c-9d2ace2bb42f', '6c0881a6-9815-4884-9fe2-eaf1e9409202', 'implementation_guidance', '["Establish documented criteria and timelines for notifying regulators and affected individuals", "Maintain a centralized breach register capturing incident details, impact, and corrective actions", "Require legal and privacy review before external breach notifications are issued", "Retain evidence of notifications and regulatory communications for audit purposes"]', '2026-04-07T18:00:22.034441', '2026-04-07T18:00:22.034441', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('97438e7d-bffd-431d-9998-fd944bbd4f3b', 'cb1fecf9-c6a8-44f9-b2c7-def42e267146', 'guidance', 'Reviews should evaluate operational effectiveness of privacy and data protection controls.', '2026-04-07T19:36:48.961134', '2026-04-07T19:36:48.961134', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('97c91072-6bed-4a2e-9dad-f3645941a70d', '78949283-ef74-4348-9f54-59a6e1684de3', 'implementation_guidance', '["Define criteria for high-risk processing", "Conduct DPIAs before deploying high-risk systems", "Document identified privacy risks and mitigation actions", "Obtain privacy or legal approval before deployment"]', '2026-04-07T19:36:46.773235', '2026-04-07T19:36:46.773235', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('9811d4bd-10e7-4d15-9734-6c7b356f2289', '43952b23-b228-4eb6-8a5e-4d883ac37039', 'description', 'Establish a formal process for approving residual risk acceptance by authorized management.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('983b9ad0-06dc-4ffc-8af8-d7f2401de402', 'be7b4390-4ce6-41ec-9395-ccdd8bc29b80', 'acceptance_criteria', '["Administrative actions are restricted to defined roles", "Role definitions and permissions are documented", "Access reviews are conducted periodically"]', '2026-04-07T18:36:46.822792', '2026-04-07T18:36:46.822792', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('9884e0a1-3179-490b-a4ab-09dfab585bf0', '66d1ecd9-9c4c-434b-97fd-307c901116eb', 'implementation_guidance', '["Provide mandatory security awareness training during onboarding.", "Conduct periodic refresher training for all employees.", "Deliver specialized training for privileged users and developers.", "Track training completion and participation metrics."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('98ad70d5-6f85-42a3-9fd4-8b96ec74e6dd', 'd4095971-8355-49cd-905c-bcfb20d22fe1', 'implementation_guidance', '["Review data collection forms and APIs to ensure only required fields are collected", "Document justification for each category of personal data collected", "Implement approval requirements for adding new personal data fields", "Conduct periodic data inventory reviews to identify unnecessary data collection"]', '2026-04-07T18:00:21.90538', '2026-04-07T18:00:21.90538', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('98b5cf7b-2f5c-40c5-8d38-6e7335b64ce3', 'c5261520-054b-4147-8cbf-7fa1c3999280', 'acceptance_criteria', '["Privacy notices are present at all data collection points", "Notices contain required regulatory disclosures"]', '2026-04-07T18:51:49.896325', '2026-04-07T18:51:49.896325', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('98ebc4d7-5a27-49b3-89cc-81491c4d8b81', 'c1014a97-65e3-4708-a81f-5c6f44b101ea', 'name', 'Assess Third-Party and Vendor Security Risks', '2026-04-06T15:17:05.877428', '2026-04-06T15:17:05.877428', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9947a8d9-695b-438d-b585-dbc47a1df05e', 'e8237a9e-c1bd-4b3b-9bf5-f2706c96cb1e', 'description', 'Implement surveillance mechanisms such as CCTV, alarms, and intrusion detection systems to monitor sensitive facilities. Continuous monitoring helps detect unauthorized entry attempts and provides evidence for investigations and incident response activities.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('995de320-f26c-4579-b823-4cbfdef58a54', '478bf708-7964-4103-aab4-56ea6eb6d2ee', 'name', 'Define and Maintain Personal Data Retention Schedule', '2026-04-07T18:00:21.927998', '2026-04-07T18:00:21.927998', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('99c12ab6-8b03-4b83-9cbc-248553bd85b3', 'c2ef645c-6a8d-428e-aabc-2c71f95a73a9', 'implementation_guidance', '["Define secure zones such as data centers, server rooms, and network infrastructure areas.", "Implement badge-based or biometric entry systems for restricted locations.", "Maintain an access authorization register for personnel permitted in secure areas.", "Review physical access rights periodically and revoke when roles change."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('99e9aec7-1247-4cd4-a9f6-33430133e03a', '617f8959-749c-4046-9d9b-0ad32abc20d1', 'name', 'Perform Security Due Diligence Before Vendor Onboarding', '2026-04-06T15:17:28.021666', '2026-04-06T15:17:28.021666', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9a1d9e99-3c36-4176-95fc-35ba24c6b511', 'c2ef645c-6a8d-428e-aabc-2c71f95a73a9', 'guidance', 'Deploy badge systems, biometric controls, or physical keys with defined authorization procedures.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9a222b72-d471-428b-b0bf-2990a2b0befd', '00c42ac0-0ce6-40fe-ae36-322098fafb5e', 'description', 'Risk assessments are performed prior to implementing new systems, major architectural changes, or significant process modifications. This ensures potential security, privacy, and operational risks are identified and addressed before deployment. Early evaluation reduces the likelihood of introducing unmitigated vulnerabilities or compliance gaps.', '2026-04-06T15:17:05.200208', '2026-04-06T15:17:05.200208', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9a4f0c98-0295-43a6-9e89-4e928c92d38b', 'e6ebcc93-8bb8-403f-a7e4-1c21268a80a9', 'guidance', 'Integrate deployment pipelines and administrative systems with centralized logging and monitoring tools.', '2026-04-06T15:17:26.096089', '2026-04-06T15:17:26.096089', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9a795a5d-9cfa-4cb6-b68d-5ed975db8b5b', '163f66fa-6159-4cb5-ba3f-fa587b8fd24a', 'implementation_guidance', '["Define measurable security indicators such as patching timelines, alert response times, and access review completion rates", "Automate collection of metrics from monitoring tools, ticketing systems, and asset management platforms", "Present metrics in dashboards or reports for security and management review", "Investigate trends or deviations that may indicate control failures or elevated risk", "Update metrics periodically to reflect evolving technologies and threat landscapes"]', '2026-04-06T15:17:09.124957', '2026-04-06T15:17:09.124957', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9ae28bbc-1970-49d5-bd9e-56d58b6053fb', 'd338d465-bb09-4904-a0fa-d92748897aea', 'implementation_guidance', '["Apply classification labels to documents, databases, files, and collaboration platforms.", "Configure automated labeling or metadata tagging in document management systems where possible.", "Define handling procedures for storage, sharing, printing, and disposal of labeled information.", "Provide user awareness training on recognizing and applying classification labels."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9ae99fb6-3c88-4c23-89c3-92f29a3767b5', '478bf708-7964-4103-aab4-56ea6eb6d2ee', 'implementation_guidance', '["Define retention periods for each category of personal data processed by the organization", "Document legal or regulatory justification for retention durations", "Align system configurations and data lifecycle policies with retention schedules", "Review retention schedules periodically to reflect regulatory or operational changes"]', '2026-04-07T18:00:21.927998', '2026-04-07T18:00:21.927998', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('9b38529c-b1f6-4895-a290-eec66421d30b', '7848d86f-e632-46d8-84c5-6ea2e7b56da0', 'acceptance_criteria', '["Rights requests are logged and tracked", "Identity verification occurs before fulfilling requests", "Requests are resolved within defined timelines"]', '2026-04-07T19:13:14.190621', '2026-04-07T19:13:14.190621', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('9b530814-ab61-4714-be78-ecbfb91b9e52', '030931dc-2482-465d-a7a3-f00b4bbe4d45', 'name', 'Establish Threat Intelligence Monitoring Process', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9b5dc4b4-4bfe-457d-b246-efc14a572868', 'cdb07056-602c-4716-abee-695e4f0807ab', 'name', 'Identify and Manage Interested Party Security Requirements', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9be41393-a131-4729-810e-9a4950916073', '762df5cb-f8e9-41b5-92fe-564e8b7f33df', 'guidance', 'The SoA should act as the authoritative mapping between risk assessment outcomes and implemented security controls and must be reviewed whenever risk assessments or control implementations change.', '2026-04-09T04:20:31.791874', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9c379898-2ed1-47a8-bfa3-f1d1251dcf6a', 'c7ca56ce-ffe2-4530-b78b-7ee26051aa17', 'name', 'Monitor System Health and Operational Anomalies', '2026-04-06T15:17:21.54828', '2026-04-06T15:17:21.54828', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9cfb7d4b-3068-4e6c-8720-e0f33246da8c', '873c5dd9-14e1-44a3-aea2-e14f3cb3bef6', 'name', 'Conduct Background Screening and Security Vetting for Personnel', '2026-04-06T15:16:58.546367', '2026-04-06T15:16:58.546367', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('9d06ac8e-debe-4e1d-8eb7-1cd12367bdbd', 'b784da50-d22a-449f-a943-7192604c4217', 'guidance', 'Dual authorization reduces the risk of accidental or malicious destructive operations.', '2026-04-07T18:36:48.541216', '2026-04-07T18:36:48.541216', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
