      ('9ebcf011-055f-4984-9eab-00f5221add44', '7de36ea2-7dab-4802-9218-7528b6203b91', 'implementation_guidance', '["Create a centralized asset inventory covering systems, applications, databases, and data repositories.", "Assign ownership and classification attributes to each asset.", "Update asset records during provisioning, modification, and decommissioning events.", "Periodically reconcile the asset inventory with discovery scans."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
