      ('9ff302bd-e736-413a-baef-bb3785c52f4d', '03e55674-3c5f-494e-9189-f2d36adf5fd2', 'acceptance_criteria', '["All rights requests are logged and tracked", "Identity verification occurs before data disclosure", "Requests are completed within defined timelines"]', '2026-04-07T18:44:26.510705', '2026-04-07T18:44:26.510705', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a0a6c036-8c8e-4a1f-a2d3-34a7dba2c316', '7072c489-e02e-4873-8b7e-962c4487140f', 'guidance', 'Define clear classification levels and ensure technical and procedural controls enforce appropriate handling of sensitive data.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
