      ('a19d1e9a-0116-43d7-8ef2-5b314a93afe5', '74dcf5d1-22d1-4381-8fe3-6ee797a4de75', 'implementation_guidance', '["Develop standard hardened configurations for operating systems, applications, and network devices.", "Disable unnecessary services, ports, and default accounts.", "Use automated configuration management or infrastructure-as-code where possible.", "Verify compliance with baseline configurations through periodic scans or audits."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a1aa3fd9-5cbd-4957-ad94-36b0f728434c', '6be7389d-f6f8-429a-8ca1-8aefb8303cbb', 'description', 'Establish a documented and repeatable methodology for identifying, analyzing, and evaluating information security risks.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a1c0388b-eb54-4601-b15f-4cc597c168be', '163f66fa-6159-4cb5-ba3f-fa587b8fd24a', 'description', 'The organization defines and monitors key security metrics and control performance indicators to evaluate the ongoing effectiveness of internal controls. Metrics provide quantitative insights into control performance, emerging threats, and operational gaps. Regular review of these indicators enables early identification of deteriorating control effectiveness.', '2026-04-06T15:17:09.124957', '2026-04-06T15:17:09.124957', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a1faf328-7a68-4d49-81b7-699eae51de42', '3dcb224b-7d8e-4b70-9a81-9b726329608f', 'implementation_guidance', '["Create intake channels such as web forms or dedicated email addresses for rights requests", "Log and track requests in a centralized case management or ticketing system", "Define internal service level timelines for reviewing and fulfilling requests", "Document responses and actions taken to maintain an audit trail"]', '2026-04-07T18:00:21.828555', '2026-04-07T18:00:21.828555', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a2079865-e4dd-441d-95d9-ce4fa02712bf', '1ec41473-07ef-465e-bae0-9e8fb1285b95', 'name', 'Develop and Maintain ICT Continuity and Disaster Recovery Plans', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a2e9de79-3679-4e8b-95ca-0954e6912c2a', '2b2927c1-14a9-49b3-ae30-5db30f52e9f0', 'implementation_guidance', '["Draft privacy notice covering processing purposes and rights", "Publish notice on relevant digital platforms", "Provide notice during user onboarding or data collection", "Review and update notice when processing practices change"]', '2026-04-07T19:36:41.844271', '2026-04-07T19:36:41.844271', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a319f9c2-ace7-4b3f-b576-ab50f62762c5', '807bbd34-3b97-40c7-a51f-ba040ddfca0e', 'implementation_guidance', '["Assign grievance cases to responsible staff", "Track investigation progress", "Document response provided to the complainant", "Maintain grievance resolution records"]', '2026-04-07T19:36:46.081445', '2026-04-07T19:36:46.081445', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a35fa6f7-7fe9-4171-977b-0a743bb0ed75', '29707553-899d-42d6-9739-fa8247a3d3da', 'implementation_guidance', '["Enable detailed audit logging for authentication, administrative actions, and data access events", "Aggregate logs from personal data systems into a centralized monitoring or SIEM platform", "Configure alerts for abnormal access patterns, excessive data downloads, or privilege escalations", "Regularly review monitoring alerts and investigate suspicious events"]', '2026-04-07T18:00:21.992156', '2026-04-07T18:00:21.992156', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a3e48457-cf2c-46ef-b2a8-4315f445f641', '68054153-8595-4c5c-a1b9-19efe701bc36', 'implementation_guidance', '["Define approved security configuration standards for operating systems, cloud platforms, and network infrastructure.", "Use automated configuration management tools to deploy and maintain baseline settings.", "Disable unnecessary services, default accounts, and insecure protocols in baseline templates.", "Periodically validate system configurations against approved baselines.", "Remediate detected configuration drift through automated or controlled remediation processes."]', '2026-04-06T15:17:12.445575', '2026-04-06T15:17:12.445575', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a4183528-10c5-4504-9a4c-59ddfec46ea7', '18a440a3-1c20-4023-97c7-b4aeb2704144', 'guidance', 'Establish a centralized repository for privacy documentation and maintain version control for policies and procedures.', '2026-04-07T18:00:22.263824', '2026-04-07T18:00:22.263824', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('a50c15e0-eb78-437f-b5ae-bdf193bbe271', '6be7389d-f6f8-429a-8ca1-8aefb8303cbb', 'guidance', 'The methodology should define risk criteria, scoring models, and evaluation thresholds.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a52091d1-0c0f-41b7-be33-f7ba91526ace', 'e23914b9-c312-4e9b-ba01-bae41134a4e3', 'implementation_guidance', '["Record identified vulnerabilities in a centralized tracking system with severity ratings", "Define remediation timelines for critical, high, medium, and low vulnerabilities", "Assign remediation ownership to system or application owners", "Track remediation progress through periodic reviews and status reporting", "Escalate overdue vulnerabilities to management for resolution"]', '2026-04-06T15:17:22.864221', '2026-04-06T15:17:22.864221', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
