      ('a67ef6e8-a06f-471f-b7bf-b3f968b8b7b0', '20b8d630-fda1-4a25-af6c-4487ea86244b', 'acceptance_criteria', '["Data collection forms only request necessary data", "Each data field has a documented processing purpose", "Periodic reviews confirm compliance with minimization principles"]', '2026-04-07T18:44:27.786296', '2026-04-07T18:44:27.786296', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
