      ('a841a992-89d2-4abb-9666-231304eb0901', '45448023-6de6-4ddd-93d3-85de7775b9db', 'guidance', 'Require independent verification or evidence review before closing remediation items associated with control deficiencies.', '2026-04-06T15:17:10.512142', '2026-04-06T15:17:10.512142', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a85e243d-bfad-40ec-a7de-df9621693c96', '81933d25-9eee-4cf0-96a7-c34dac85fab7', 'implementation_guidance', '["Require TLS or equivalent encryption for network communications involving sensitive data.", "Use secure file transfer protocols such as SFTP or HTTPS.", "Disable insecure protocols and legacy encryption mechanisms.", "Monitor data transfer channels for unauthorized or unencrypted transmissions."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
