      ('bc29d2fe-4e80-4e90-8e35-9aa87d592c28', '1e321c16-777a-425a-9a6f-5b963892f910', 'guidance', 'Treatment plans should clearly define responsible owners and remediation timelines.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
