      ('bdc96fd7-f4bd-4bd1-bba9-cb8335005304', '83270811-0d03-4058-a311-d9afa0cd6683', 'description', 'Implement processes to track, review, and resolve reported control deficiencies, security concerns, or policy violations. Continuous monitoring of reported issues helps ensure they are addressed promptly and systemic weaknesses are identified.', '2026-04-06T15:17:02.319473', '2026-04-06T15:17:02.319473', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('bdfca728-497d-46f8-92b3-5a656d4e5604', '18a440a3-1c20-4023-97c7-b4aeb2704144', 'name', 'Maintain Comprehensive DPDP Compliance Documentation', '2026-04-07T18:00:22.263824', '2026-04-07T18:00:22.263824', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
