      ('c11cd4cc-8d6d-4ec4-af71-6c733420c4d9', 'd8e05c35-b6b0-4694-9745-f3395c6f4562', 'guidance', 'Create documented workflows for access provisioning and require formal approvals before granting access.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
