      ('c5952aa8-f2d4-4ce6-85e7-5b859d331549', '43952b23-b228-4eb6-8a5e-4d883ac37039', 'guidance', 'Residual risks must be documented and approved according to defined governance thresholds.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c599b879-1170-4681-9539-919211c3f355', 'b7d07b5b-cd51-4967-8755-b00021647182', 'description', 'Organizations must define and maintain retention schedules specifying how long personal data is retained for each processing purpose.', '2026-04-07T18:44:28.74602', '2026-04-07T18:44:28.74602', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c5f7170c-7049-47bc-8b96-09c24ab7c1f9', 'e89d79ab-0dcf-4385-9c5f-1458924de543', 'description', 'Provide periodic training to employees on personal data protection responsibilities and DPDP compliance requirements.', '2026-04-07T19:13:14.549828', '2026-04-07T19:13:14.549828', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c60f67f1-a87d-4f27-93fd-c1f71f46b90d', '978bf834-b455-4388-89af-ca0d52980af5', 'guidance', 'Implement validation checks and correction mechanisms in data management processes.', '2026-04-07T18:58:52.662174', '2026-04-07T18:58:52.662174', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c6302a8c-d020-4616-80c2-ab06cc249cce', 'e992f232-9689-46fa-8e08-d084493c287f', 'name', 'Assign and Maintain Documented Security Roles and Responsibilities', '2026-04-06T15:16:58.161206', '2026-04-06T15:16:58.161206', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c639bb11-de41-4ef3-a458-cb072b41de9d', '8c10560c-13fc-40b8-ad63-85028278507c', 'name', 'Track and Remediate Control Exceptions and Process Deviations', '2026-04-06T15:17:14.353424', '2026-04-06T15:17:14.353424', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c672ab12-0d9f-49ff-8365-27c7815458dd', '6c0881a6-9815-4884-9fe2-eaf1e9409202', 'guidance', 'Maintain a breach register and define notification timelines aligned with DPDP requirements and internal escalation thresholds.', '2026-04-07T18:00:22.034441', '2026-04-07T18:00:22.034441', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c67d5a76-0087-4bdf-86c9-058a360d5ed7', '2f19fa6b-3132-4df7-bf1e-f06fa4c3fe1b', 'name', 'Maintain Record of Processing Activities', '2026-04-07T18:58:56.704966', '2026-04-07T18:58:56.704966', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c69c80d4-1fbd-4422-b277-d187a5540b54', 'f5b150f5-007f-405a-9eae-35a6c94ca794', 'implementation_guidance', '["Conduct periodic internal privacy compliance assessments or self-audits", "Review effectiveness of existing data protection controls and procedures", "Track regulatory updates affecting DPDP obligations and update controls accordingly", "Document review findings and assign remediation actions where gaps are identified"]', '2026-04-07T18:00:22.319436', '2026-04-07T18:00:22.319436', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c6e02535-a10e-4844-89bf-170f15ae308a', 'df0923d3-14cb-400e-9d2d-70bfecd7f022', 'name', 'Enforce Security Requirements in Supplier Contracts', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c6f1b074-3a54-44cf-853f-b7bbcd910cdd', '92a83e90-dfb4-4db4-9f0c-e3ee077864d6', 'guidance', 'Develop a documented code of conduct and ensure it is communicated to all employees and contractors. Require acknowledgement at onboarding and periodically thereafter.', '2026-04-06T15:16:57.726409', '2026-04-06T15:16:57.726409', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c6fcd473-d960-4ccb-a657-4cfdf65be8e9', 'dd050bbc-e961-4345-8f58-de32b9c318a1', 'name', 'Automate Secure Deletion or Anonymization of Expired Data', '2026-04-07T18:00:21.948567', '2026-04-07T18:00:21.948567', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c712af85-b96c-4db6-8017-5378c1fd17b7', '2bcbf2b5-dbcd-41d0-ad80-29043388323e', 'name', 'Perform Periodic Reconciliation of System and Data Integrity Controls', '2026-04-06T15:17:13.707401', '2026-04-06T15:17:13.707401', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c83a3b6b-065c-4e3e-bb6e-f8db634814ca', '71297127-54eb-4b99-b694-06b44a3b057f', 'implementation_guidance', '["Integrate servers, cloud services, network devices, security tools, and applications with a centralized logging platform", "Define and enforce log retention requirements aligned with regulatory and operational needs", "Restrict modification or deletion of collected logs using role-based access controls", "Enable log integrity protections such as immutability or write-once storage where feasible", "Periodically validate that critical systems are actively forwarding logs to the central platform"]', '2026-04-06T15:17:19.570031', '2026-04-06T15:17:19.570031', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c84576ec-7b88-4b97-9c79-6a83b603fb92', 'daae86b7-1c1d-4e34-90ad-f7da4eaa49df', 'name', 'Automatically Lock or Disable Inactive and Suspicious Accounts', '2026-04-06T15:17:18.943177', '2026-04-06T15:17:18.943177', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c867cd5e-a197-4b81-a600-627e088d146b', '35d4079b-2f12-4766-94ca-cc9ac44e1fd2', 'description', 'Maintain a documented register identifying the lawful basis for each category of personal data processing performed by the organization in accordance with DPDP requirements.', '2026-04-07T19:13:14.03935', '2026-04-07T19:13:14.03935', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c882daa8-971f-4922-9be9-17de0937a5a3', 'c0b1282d-75b4-4dfc-9ab8-1e003c7964c6', 'description', 'Control owners periodically evaluate whether assigned internal controls are operating as designed and producing the intended outcomes. Self-assessments help identify control degradation, implementation gaps, or changes in operating environments that may impact control effectiveness. Results are documented and escalated when deficiencies are identified.', '2026-04-06T15:17:07.830608', '2026-04-06T15:17:07.830608', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c93eacf9-4c6d-426c-80e2-5fa00f9c566e', '21cadae7-872f-441b-9a54-9ae944b2c5e7', 'implementation_guidance', '["Draft a comprehensive information security policy aligned with regulatory and contractual requirements", "Obtain formal approval from executive leadership or designated governance authority", "Publish the policy in an accessible internal repository", "Communicate policy expectations to employees and relevant external parties"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c94edc4f-f51c-4908-97ea-6ba7cf22fe8b', 'e992f232-9689-46fa-8e08-d084493c287f', 'description', 'Security roles and responsibilities are formally defined and documented to ensure clear accountability for security operations, risk management, and control execution. Role definitions help ensure critical security duties are assigned to competent personnel and reduce gaps or overlaps in responsibility. Clear accountability supports consistent implementation of internal controls.', '2026-04-06T15:16:58.161206', '2026-04-06T15:16:58.161206', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c96416f1-e4c5-4750-92bc-39153ba4707e', '1967551b-0805-4cb9-b86e-3cf0b5d5b68a', 'implementation_guidance', '["Define security KPIs and metrics aligned with ISMS objectives", "Collect data from security tools, incident records, and audit findings", "Analyze performance trends and identify improvement opportunities", "Report metrics regularly to governance bodies and management"]', '2026-04-09T04:20:32.033669', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c96e04aa-b581-4a1c-b215-584d4cf83633', '09be1965-a848-4f25-9954-4fd11f08c114', 'name', 'Implement Confidential Reporting Mechanism for Security Concerns', '2026-04-06T15:17:00.783771', '2026-04-06T15:17:00.783771', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c988fdae-235f-45b6-b31e-fd8114074e32', '1996d6fb-40fe-4981-a566-62b52b1f176e', 'name', 'Enforce Contractual Data Protection Obligations for Processors', '2026-04-07T18:00:22.079337', '2026-04-07T18:00:22.079337', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('c99f0f67-b63c-4d44-8239-349c4ef88732', 'fcd799bd-5663-4dbe-ac53-5eee7f57d15f', 'implementation_guidance', '["Assess potential security impacts of proposed changes.", "Document risk implications of ISMS changes.", "Obtain approvals prior to implementing major changes.", "Update documentation and controls after changes."]', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('c9c580d2-4d72-4f30-a33e-46d61afcdccd', 'b42db347-3967-4d44-b746-490c4ee02d83', 'description', 'Emergency changes required to restore service or address critical vulnerabilities may follow an expedited change process. These changes must be documented and implemented by authorized personnel, followed by a formal post‑implementation review to validate impact and ensure proper documentation. This approach balances operational urgency with accountability and oversight.', '2026-04-06T15:17:26.717418', '2026-04-06T15:17:26.717418', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ca26bd2c-7006-4796-9537-4603d021109b', '8444f18d-0495-47fb-8f3e-d8a7fd0fe0f2', 'description', 'Perform internal audits at planned intervals to evaluate whether the Information Security Management System conforms to organizational policies, ISO/IEC 27001 requirements, and implemented control objectives.', '2026-04-09T04:20:31.853682', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ca29c8b6-175e-446a-926f-5dd9b6b698dd', 'ea8285c6-5509-42f4-9c5d-5be9a888ac96', 'description', 'Establish rules limiting personal data collection to only what is necessary for defined processing purposes.', '2026-04-07T18:58:53.766787', '2026-04-07T18:58:53.766787', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ca6f3f7d-30dd-4f14-8a41-15b64230fa43', '7c72fd6d-8385-4136-acb6-147f88156d97', 'implementation_guidance', '["Define classification levels such as Public, Internal, Confidential, and Restricted with clear criteria.", "Assign asset owners responsible for determining and approving classifications.", "Document required handling, storage, and transmission rules for each classification level.", "Integrate classification requirements into data creation, storage, and sharing processes."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cafc5d48-c101-4f39-b8dd-4ad227ba3a67', '1e321c16-777a-425a-9a6f-5b963892f910', 'description', 'Create and maintain risk treatment plans specifying how identified information security risks will be mitigated, transferred, accepted, or avoided.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cb24e315-0110-4358-9ae7-3c34f74cfefb', 'd824b0c1-df1b-40fd-8501-a60670bcbaff', 'implementation_guidance', '["Formally appoint a Data Protection Officer with defined responsibilities and reporting lines", "Define criteria for identifying high-risk processing activities requiring DPIAs", "Conduct DPIAs prior to deploying systems or processes involving sensitive or large-scale personal data", "Maintain documented DPIA reports including risk assessments and mitigation measures"]', '2026-04-07T18:00:22.214777', '2026-04-07T18:00:22.214777', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('cb9ea2c5-bb74-4cad-a7b9-45d0fe14890b', 'ac52cfed-eb29-41ba-a1c6-87c627bbac6a', 'implementation_guidance', '["Define audit scope covering DPDP obligations", "Engage independent auditors", "Review governance, policies, and technical safeguards", "Track remediation of audit findings"]', '2026-04-07T19:36:47.46516', '2026-04-07T19:36:47.46516', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('cba68696-2048-4c41-b4c7-7cb2b24bd38c', '807bbd34-3b97-40c7-a51f-ba040ddfca0e', 'acceptance_criteria', '["Grievance cases are tracked until resolution", "Resolution records are retained", "Timelines for grievance responses are monitored"]', '2026-04-07T19:36:46.081445', '2026-04-07T19:36:46.081445', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('cbdf7e9b-f054-4660-bd6f-bdf767907cb9', 'e6097f6d-3449-4662-a8ec-2e01bce7be8c', 'implementation_guidance', '["Deploy a centralized logging and monitoring platform such as a SIEM or security monitoring service", "Integrate logs from key sources including identity systems, endpoints, cloud infrastructure, applications, and network devices", "Configure automated alerts for suspicious activities such as failed logins, privilege escalation, and unusual network traffic", "Define escalation and triage procedures for security analysts reviewing alerts", "Review monitoring coverage periodically to ensure new systems and services are included"]', '2026-04-06T15:17:07.173021', '2026-04-06T15:17:07.173021', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cc14f178-d093-484c-b61d-52abe970bc30', 'a9eecc25-906a-4134-a296-0431c5f15fe2', 'name', 'Define and Maintain Organizational Risk Appetite and Tolerance', '2026-04-06T15:17:03.088196', '2026-04-06T15:17:03.088196', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cc3697eb-5ad2-43bb-9aa2-cea0a442b116', '5e783a13-ffdb-4ef7-9934-374d932b768a', 'description', 'Evaluate the information security posture of suppliers and third parties before granting access to systems or data. Risk assessments help identify potential weaknesses and ensure suppliers meet the organization’s security expectations.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cc95e06f-87eb-41ee-8968-aafd843e43b8', '1ec41473-07ef-465e-bae0-9e8fb1285b95', 'guidance', 'Identify critical systems and define recovery objectives for availability and data integrity.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ccc74146-3806-43e1-8ed4-03a44b1c817b', 'cb1fecf9-c6a8-44f9-b2c7-def42e267146', 'implementation_guidance', '["Define review schedule for DPDP compliance", "Assess policy implementation and operational controls", "Document review results and improvement actions", "Report results to governance leadership"]', '2026-04-07T19:36:48.961134', '2026-04-07T19:36:48.961134', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('cd13327b-2bc6-44f4-ba69-39481343705e', 'd2035e09-3460-4afa-9d2e-b07166eb1053', 'name', 'Implement Centralized Security Logging and Monitoring', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cd47a036-639b-4fe8-813f-5f5442f83379', '49e1abd6-acf8-4de3-a9cd-6a2d212c6608', 'description', 'Administrative accounts used to manage systems that process personal data must be protected using strong authentication mechanisms to prevent unauthorized access and misuse of personal data.', '2026-04-07T18:29:03.371668', '2026-04-07T18:29:03.371668', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('cdf59e8f-e35c-41ad-9ee3-41bfaf02011d', 'b4e9ec66-8d8c-4094-a8d6-fca76cedb459', 'name', 'Establish Data Protection Governance Structure', '2026-04-07T18:00:21.677803', '2026-04-07T18:00:21.677803', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ce043465-a8e4-4cd6-a1e3-393c30af2f24', '8ee5d368-91b2-4618-ab70-44a0d4b176bd', 'name', 'Perform Periodic Enterprise Security Risk Assessments', '2026-04-06T15:17:04.435335', '2026-04-06T15:17:04.435335', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cf1625e9-e9d6-4bed-8faa-83834a4e8383', '95f9d4c4-0d22-48f1-a5aa-4fde70eba35f', 'implementation_guidance', '["Implement cloud security posture management or equivalent monitoring tools.", "Track configuration drift against approved security baselines.", "Enable logging for cloud administrative actions and resource access.", "Alert security teams when high-risk changes or anomalies occur."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cf4ec5ad-7b09-4a03-a629-b10f37628f50', '29ba58f4-01cc-4ea8-99c2-742f36cc2e2c', 'implementation_guidance', '["Identify categories of personal data", "Define retention periods for each category", "Approve retention schedule with legal and privacy teams", "Review retention schedules periodically"]', '2026-04-07T18:51:52.566198', '2026-04-07T18:51:52.566198', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('cf63d682-c832-4f8d-8162-244074353556', 'b52c3aec-1593-47ee-a618-211ab9dbe57d', 'guidance', 'Integrate consent management systems with downstream processing systems to automatically enforce consent status changes.', '2026-04-07T18:00:21.779208', '2026-04-07T18:00:21.779208', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('cf690c62-89d3-44ca-a34b-403eccf521d1', 'a469476d-d763-406e-8727-2d48ac513084', 'name', 'Define Information Transfer Agreements and Monitoring', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('cf802d04-89c6-4396-95a2-b36562c54489', 'e23914b9-c312-4e9b-ba01-bae41134a4e3', 'guidance', 'Use a centralized vulnerability management or ticketing system to track remediation activities and enforce remediation deadlines.', '2026-04-06T15:17:22.864221', '2026-04-06T15:17:22.864221', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d09acb3b-a0bd-4e04-844c-456e73705247', '55fae56b-31b0-4dbd-947a-d67c9dcd6214', 'implementation_guidance', '["Form an information security steering committee with executive and business unit representation", "Define governance charter including authority, scope, and decision\u2011making responsibilities", "Schedule regular governance meetings to review risk posture, incidents, and security initiatives", "Report information security metrics and risk status to senior leadership"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d0f94f89-a12e-418e-a0cf-a15a811a1855', '3523377d-20ab-440f-bf84-9ec6866a1118', 'guidance', 'The risk register should support ongoing monitoring and governance reporting.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d11e5375-ac5a-4f8e-b678-5da86ee2f910', '8d92e6ee-7eb0-4ace-92ca-e2b7a0f4c7d9', 'guidance', 'Integrate the data breach process with the organization’s broader incident response program and ensure relevant staff are trained on escalation procedures.', '2026-04-07T18:00:22.013221', '2026-04-07T18:00:22.013221', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d1f61393-b56d-4f01-a82c-bdcd2bcd926f', '4599995a-e91f-4505-9431-bdbd8f2b1654', 'guidance', 'Define separation requirements for system administration, development, and security operations roles and enforce them through role-based access and workflow approvals.', '2026-04-06T15:17:11.825755', '2026-04-06T15:17:11.825755', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d21fb32a-c10d-4b9e-9126-762bce19833c', '2b2927c1-14a9-49b3-ae30-5db30f52e9f0', 'description', 'Ensure privacy notices describing personal data processing practices are publicly available and maintained.', '2026-04-07T19:36:41.844271', '2026-04-07T19:36:41.844271', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d2aa9ad4-0bed-4826-9f15-d6a78f69379a', 'e850596d-9344-4aca-86d1-609ca5c0c632', 'description', 'Conduct periodic internal assessments to verify that DPDP controls are implemented and operating effectively.', '2026-04-07T18:58:57.558116', '2026-04-07T18:58:57.558116', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d2d3a90b-d1e4-4080-af8b-d114f95eaa51', '00b82e4d-76fe-493e-b403-3679656c8ff3', 'implementation_guidance', '["Require encrypted protocols such as TLS, SFTP, or VPN for sensitive data transfers.", "Disable insecure transmission protocols such as FTP or unencrypted email where sensitive data is involved.", "Implement certificate management for secure communications.", "Document approved transfer mechanisms for internal and external communications."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d2df7541-7e39-44df-aba0-953063b04657', 'f141e977-07d6-474b-8e8b-20e7942f4a05', 'description', 'Provide transparent and accessible privacy notices explaining how personal data is collected, used, stored, and shared. Notices ensure individuals understand processing purposes, available rights, and contact points for grievances or inquiries. Transparency supports lawful processing and informed decision-making by Data Principals.', '2026-04-07T18:00:21.803774', '2026-04-07T18:00:21.803774', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d3090345-a866-4a53-92ef-b1003ade75fb', '736fd12f-02d8-4476-ad1f-f2a546cf44f6', 'guidance', 'Use identity management and monitoring systems to control and audit vendor access.', '2026-04-06T15:17:30.493929', '2026-04-06T15:17:30.493929', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d3a22858-dfd9-45b7-a1f2-3e2875df48b4', 'b6e361d7-079e-4f98-8170-8088e16fe228', 'guidance', 'Implement privileged access management (PAM) or equivalent controls to manage privileged account usage and session monitoring.', '2026-04-06T15:17:16.316161', '2026-04-06T15:17:16.316161', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d42a2787-c4b0-43f3-b8cf-57b97c88b2b3', '6edc90f7-0262-4abb-9243-383279252a6b', 'description', 'Evaluate third-party processors handling personal data to ensure they implement adequate security and privacy safeguards aligned with DPDP obligations. Due diligence reduces the risk of data exposure or misuse by external service providers.', '2026-04-07T18:00:22.056975', '2026-04-07T18:00:22.056975', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d4347140-9b7c-4f11-b998-5a5bfda958c7', 'c5261520-054b-4147-8cbf-7fa1c3999280', 'description', 'Ensure standardized privacy notices are presented at the point of data collection.', '2026-04-07T18:51:49.896325', '2026-04-07T18:51:49.896325', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d43af173-653a-4b09-92f6-33cdc71ac2ee', 'd81a9e2e-4a43-4a3b-b55d-a061d9bfcb36', 'name', 'Document Lawful Basis for Personal Data Processing', '2026-04-07T18:58:48.893819', '2026-04-07T18:58:48.893819', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d470a336-a8ed-434f-8cf2-bf01c9e078b7', '7232ce77-13ef-4583-affa-469e60f9d81d', 'implementation_guidance', '["Document mitigation or treatment plans for each identified risk in the risk register", "Assign remediation owners and target completion timelines", "Track progress of mitigation activities through a centralized tracking system", "Escalate overdue or high\u2011risk issues to senior management for action", "Validate remediation effectiveness and update residual risk ratings"]', '2026-04-06T15:17:06.534805', '2026-04-06T15:17:06.534805', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d55b7ed0-3a2c-44bc-a3db-362fa01564ee', '4c036014-d4b9-4537-9e09-baea8f91def6', 'name', 'Define Security Competence Requirements', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d5efd036-09cf-44ed-9e62-aea61247c2b8', 'ab84b5b8-9099-4b0f-8735-db138b4edebc', 'implementation_guidance', '["Conduct scheduled vulnerability scans for infrastructure and applications.", "Track identified vulnerabilities in a centralized remediation system.", "Prioritize remediation based on severity and asset criticality.", "Validate that vulnerabilities are resolved after remediation."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d66fbc70-e3e8-4264-a849-4d6efa6a0af7', '36402109-a8cc-4bca-aabe-24a07a074242', 'guidance', 'Integrate purpose validation into system design and data intake processes.', '2026-04-07T18:51:48.278807', '2026-04-07T18:51:48.278807', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d7aab29a-948a-4e9d-a15c-7b997a6b06b3', '43952b23-b228-4eb6-8a5e-4d883ac37039', 'implementation_guidance', '["Define risk acceptance criteria and thresholds.", "Require formal approval from risk owners or executives.", "Document justification for accepting residual risks.", "Periodically review accepted risks."]', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d7d5d16f-4a2c-4647-bcfc-4880123f9622', 'cebf28f2-379b-45d0-9105-5ff32aa851d4', 'description', 'Administrative accounts with access to personal data systems must be provisioned through a controlled approval process to ensure accountability and least privilege access.', '2026-04-07T18:29:03.504183', '2026-04-07T18:29:03.504183', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d7e2abb1-d203-42d5-bd07-05d28a5ea63d', 'b784da50-d22a-449f-a943-7192604c4217', 'acceptance_criteria', '["Destructive administrative actions require dual approval", "Approval records are retained in audit logs", "Unauthorized destructive actions are blocked"]', '2026-04-07T18:36:48.541216', '2026-04-07T18:36:48.541216', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d862a20e-90c3-424f-baa8-503c68487918', '55fae56b-31b0-4dbd-947a-d67c9dcd6214', 'description', 'Define and implement a formal governance structure responsible for overseeing the Information Security Management System (ISMS). This structure ensures executive oversight, alignment with organizational objectives, and accountability for security risk management and compliance activities.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d9024ae5-3bf4-468c-ab34-4daaaeb5ba33', '41564679-cdc3-4493-98cd-11b7bfbacdd7', 'guidance', 'Maintain separate development, testing, and production environments. Require documented testing evidence before deployment authorization.', '2026-04-06T15:17:24.783484', '2026-04-06T15:17:24.783484', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d9226d53-7ee7-4152-87a8-3e6ce760016a', 'cbfa47ff-b3da-4cf5-8333-f4c729fefe09', 'acceptance_criteria', '["Grievance submission channels are publicly available", "All grievances are logged upon receipt", "Grievances are assigned for review"]', '2026-04-07T19:36:45.442566', '2026-04-07T19:36:45.442566', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d9637356-6ef4-4995-a7f5-f6596d1b65a9', '617f8959-749c-4046-9d9b-0ad32abc20d1', 'guidance', 'Integrate vendor security due diligence into procurement and onboarding workflows so vendors cannot be approved without review.', '2026-04-06T15:17:28.021666', '2026-04-06T15:17:28.021666', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d979cfc4-32bb-4388-9b7c-afd8ca3544fc', 'd8e7688b-8ebe-43c7-a652-234d5d05e742', 'guidance', 'Establish documented runbooks for alert classification, investigation, and escalation. Ensure operational teams are trained and accountable for reviewing alerts within defined service levels.', '2026-04-06T15:17:20.245299', '2026-04-06T15:17:20.245299', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d992e005-94fc-425e-8ce3-9abdd82c89ac', '964773c6-cd11-463e-b9ce-0dfbd93ec14c', 'description', 'Monitoring processes ensure that newly deployed systems, infrastructure components, and applications are incorporated into the organization''s control and monitoring environment. This prevents security gaps caused by unmanaged or unmonitored assets. Continuous evaluation ensures that monitoring scope evolves with organizational changes.', '2026-04-06T15:17:09.802343', '2026-04-06T15:17:09.802343', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('d99b433f-4d95-4ecd-a4ff-cd194c394939', 'b784da50-d22a-449f-a943-7192604c4217', 'description', 'Require approval from multiple authorized personnel before executing destructive administrative actions such as deletion of applications, datasets, or user records.', '2026-04-07T18:36:48.541216', '2026-04-07T18:36:48.541216', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('d9c8f1aa-6984-435c-8bca-631929d45738', '3ec0f435-1798-4fc6-bda2-139c9db28d3b', 'name', 'Define and Enforce Security Requirements in Vendor Contracts', '2026-04-06T15:17:28.718447', '2026-04-06T15:17:28.718447', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('da789842-5abe-4817-ba99-f1487c23e43d', 'a7ff3eaa-2d5c-4086-a546-ee387abaaa68', 'name', 'Maintain Comprehensive Asset Inventory', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('da7dcf7d-abf6-4be7-973b-735ff2e09c93', 'f97f2c1f-d952-4dcd-90f7-a0dc776efb71', 'description', 'Ensure personal data is accessed or used only for the documented purpose associated with its collection.', '2026-04-07T19:36:40.518698', '2026-04-07T19:36:40.518698', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('dac7cd19-7bef-48e7-a316-b14e1dd991e7', '41564679-cdc3-4493-98cd-11b7bfbacdd7', 'implementation_guidance', '["Establish dedicated staging or test environments mirroring production configurations where feasible", "Define testing procedures including functional validation, security checks, and regression testing", "Document test results and attach them to the change record", "Require remediation and retesting if issues are identified during testing", "Ensure test data is sanitized or anonymized when production data is used"]', '2026-04-06T15:17:24.783484', '2026-04-06T15:17:24.783484', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('db427ce4-01b0-40cd-8c83-293a22343057', 'e850596d-9344-4aca-86d1-609ca5c0c632', 'implementation_guidance', '["Define review frequency for DPDP compliance assessments", "Evaluate implementation of privacy and security controls", "Track remediation actions for identified gaps"]', '2026-04-07T18:58:57.558116', '2026-04-07T18:58:57.558116', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('db57991a-0dbb-4224-aad5-716f472a1d64', 'b7d07b5b-cd51-4967-8755-b00021647182', 'guidance', 'Retention schedules should align with regulatory obligations and business requirements.', '2026-04-07T18:44:28.74602', '2026-04-07T18:44:28.74602', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('db5ab068-f842-4fe8-8a29-ab4518dfbd9d', 'e8237a9e-c1bd-4b3b-9bf5-f2706c96cb1e', 'guidance', 'Place monitoring systems in strategic facility locations and retain surveillance logs according to policy.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('db5c1b02-7ee6-4e8a-b10a-098d8abe9301', '50b2fcae-0248-4ebd-bace-fe2042ec4f76', 'implementation_guidance', '["Maintain a documented review process for proposed international data transfers", "Assess whether destination countries are permitted under applicable regulatory directives", "Evaluate safeguards implemented by the receiving entity to protect transferred data", "Require formal privacy or legal approval before initiating cross-border transfers"]', '2026-04-07T18:00:22.101243', '2026-04-07T18:00:22.101243', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('dbb1f197-5fcd-4b02-8530-300bec407cc4', '030931dc-2482-465d-a7a3-f00b4bbe4d45', 'implementation_guidance', '["Subscribe to reputable threat intelligence feeds and industry security advisories.", "Analyze threat intelligence for relevance to organizational systems and services.", "Share actionable intelligence with security and IT operations teams.", "Update risk assessments and defensive controls based on emerging threats."]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('dbd1fff6-cab1-4957-b537-5667fbc4a510', '4fdaa76b-8228-453a-bef7-1ff0aaca8f7c', 'implementation_guidance', '["Require documented access requests specifying the system, access level, and business justification.", "Obtain approval from the appropriate system owner or manager prior to granting access.", "Provision access using role-based access control where possible.", "Maintain logs of all access approvals and provisioning activities.", "Perform periodic reviews to confirm granted access remains appropriate."]', '2026-04-06T15:17:13.114722', '2026-04-06T15:17:13.114722', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('dc5cc4d0-5271-406d-aa27-77923d90512a', '6edc90f7-0262-4abb-9243-383279252a6b', 'guidance', 'Conduct structured vendor risk assessments focusing on privacy practices, security controls, and regulatory compliance before onboarding.', '2026-04-07T18:00:22.056975', '2026-04-07T18:00:22.056975', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('dcd9a3ad-00e5-4b0d-8125-69c967b1b835', '00c42ac0-0ce6-40fe-ae36-322098fafb5e', 'implementation_guidance', '["Require risk assessment as part of project initiation or major system design reviews", "Evaluate potential impacts on confidentiality, integrity, availability, and regulatory obligations", "Assess risks introduced by integrations, APIs, and external service dependencies", "Document mitigation strategies or compensating controls prior to production deployment", "Require management approval when residual risk exceeds defined tolerance thresholds"]', '2026-04-06T15:17:05.200208', '2026-04-06T15:17:05.200208', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ddaba24c-7adc-43e4-acb9-434b24f56ef0', 'ac52cfed-eb29-41ba-a1c6-87c627bbac6a', 'description', 'Conduct periodic independent audits to evaluate compliance with DPDP obligations and internal privacy controls.', '2026-04-07T19:36:47.46516', '2026-04-07T19:36:47.46516', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ddbd833b-830b-4101-8918-d2d713f0da22', '8444f18d-0495-47fb-8f3e-d8a7fd0fe0f2', 'implementation_guidance', '["Define an internal audit program covering ISMS processes and security controls", "Assign qualified and independent personnel to perform audits", "Document audit scope, criteria, findings, and corrective actions", "Track remediation of identified nonconformities until closure"]', '2026-04-09T04:20:31.853682', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ddd1743f-4b3c-4559-9a9b-f725071d7fe8', '030931dc-2482-465d-a7a3-f00b4bbe4d45', 'description', 'Implement processes to gather, analyze, and distribute cybersecurity threat intelligence relevant to the organization''s technology stack and business operations. Threat intelligence improves situational awareness and enables proactive risk mitigation.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ddd56251-97a6-4fda-9f02-8c73ddb03875', '5b1e1d92-b20c-4b30-8a0f-e4ee83066f54', 'implementation_guidance', '["Implement a centralized change request system (e.g., ITSM platform) for all technology changes", "Require submitters to document change description, impacted assets, risk level, and rollback considerations", "Assign unique change identifiers and maintain a full change history", "Link change records to affected configuration items or assets in the asset inventory", "Restrict system modifications that are not associated with an approved change record"]', '2026-04-06T15:17:24.101379', '2026-04-06T15:17:24.101379', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('de01f115-a1f0-4d2d-9e9e-05ec8c0d7f8d', '56394af4-39c8-4203-8202-0967d00cf12c', 'description', 'Require all personal data processing activities to have a documented lawful basis under the DPDP Act, such as valid consent or legally permitted legitimate use. Documenting the legal basis ensures processing activities remain within permitted boundaries and reduces the risk of unlawful or unauthorized use of personal data. This control also supports regulatory audits and internal accountability.', '2026-04-07T18:00:21.708565', '2026-04-07T18:00:21.708565', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('de0ddc07-8fb7-430f-9b8c-971bf506b19a', 'af2d3edb-6ff0-4026-826b-23300f3a1813', 'implementation_guidance', '["Maintain all application code and infrastructure configurations in approved version control repositories", "Require authenticated user accounts and access restrictions for repository usage", "Enable commit history tracking and audit logs for all code changes", "Implement branch protection rules and controlled merge processes", "Regularly back up version control repositories"]', '2026-04-06T15:17:25.455336', '2026-04-06T15:17:25.455336', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('de379793-a2c5-4fd5-a0f8-7d6413274182', 'd2035e09-3460-4afa-9d2e-b07166eb1053', 'description', 'Collect, centralize, and monitor security logs from systems, applications, and network devices to detect suspicious activities and support incident investigation.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
