      ('e396a122-063f-4d0c-b345-d00e153bd25e', 'c036a7dd-3d3e-4a20-871f-e6a31b43859f', 'description', 'Install and maintain anti-malware protection across endpoints, servers, and other computing devices to detect and prevent malicious software execution. Centralized monitoring ensures threats are identified quickly and response actions are triggered when infections occur.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
