      ('e6e76f68-1edf-44bd-af22-e02fbaa27c9c', '83270811-0d03-4058-a311-d9afa0cd6683', 'implementation_guidance', '["Log all reported control issues and security concerns in a centralized issue tracking system", "Assign ownership and remediation deadlines for each reported issue", "Regularly review issue status and remediation progress with security or risk management teams", "Escalate unresolved or high-risk issues to senior management for oversight", "Maintain records of corrective actions taken for audit and compliance purposes"]', '2026-04-06T15:17:02.319473', '2026-04-06T15:17:02.319473', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e6f05edd-c338-4fd1-9226-2d145ce4d323', 'b5910f05-422d-415c-a1e9-e763cdcf2d39', 'guidance', 'Use automated vulnerability scanning tools combined with defined remediation timelines based on severity.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e7a3c833-ab95-4763-924d-b9158eac8910', 'daae86b7-1c1d-4e34-90ad-f7da4eaa49df', 'implementation_guidance', '["Automatically lock accounts after a defined number of consecutive failed login attempts.", "Disable accounts that remain inactive beyond a defined period such as 60\u201390 days.", "Require identity verification and administrative approval before reactivating locked accounts.", "Log and review account lockout and reactivation events for potential security incidents."]', '2026-04-06T15:17:18.943177', '2026-04-06T15:17:18.943177', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e7f2e4dd-c691-4508-a4a4-7c5a6e9b31d2', '037846f7-1941-4d75-8ff7-a8cbbe770ca3', 'description', 'Establish a structured information security awareness and training program to ensure employees, contractors, and relevant third parties understand security policies, threats, and their responsibilities for protecting organizational information.', '2026-04-09T04:20:31.950465', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e808b18b-f3ee-4d3a-a20b-5fafd49e6ee7', '21c26368-94f0-4cf5-bbc2-0e5711613be3', 'description', 'Perform periodic independent audits to assess compliance with DPDP requirements and evaluate the effectiveness of data protection controls. Independent reviews provide assurance that privacy safeguards are functioning and identify areas for remediation.', '2026-04-07T18:00:22.237708', '2026-04-07T18:00:22.237708', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('e81cb9ba-e329-4868-b0ae-4c7ba18e0399', '513b86c7-f2a2-4401-b0fc-a677b6a71715', 'acceptance_criteria', '["Administrative accounts cannot be created without required identity attributes", "Identity verification records exist for all administrative users", "Administrative access approvals are documented and auditable"]', '2026-04-07T19:19:31.331272', '2026-04-07T19:19:31.331272', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('e86d6548-cf84-4cdd-a44d-a70a631c7f21', '5006dd25-c0e4-41d2-8559-550f8faebee8', 'name', 'Implement Secure Password Recovery Mechanisms', '2026-04-07T18:29:03.452906', '2026-04-07T18:29:03.452906', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('e88f8044-3ab8-4c80-8d12-73de3733535b', '093fc395-e769-4882-93d9-441ee7e46edf', 'guidance', 'Assign compliance monitoring responsibilities and integrate regulatory tracking into governance or risk management processes.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e8c3d772-d583-401e-9652-45d31b646734', 'be04a4db-f834-43b4-b5d8-9f1c2ddd0970', 'implementation_guidance', '["Require periodic updates of vendor security attestations or compliance reports", "Track expiration dates of certifications such as SOC 2 or ISO 27001", "Review vendor incident disclosures or publicly reported security events", "Document review outcomes and escalate material concerns to risk management or security leadership"]', '2026-04-06T15:17:29.901758', '2026-04-06T15:17:29.901758', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e8ff7bd3-361d-42e8-8d10-9682c660eac9', '6089f2be-7719-45ce-aa86-15f5fba07601', 'description', 'Require authentication or identity verification before processing Data Principal rights requests to prevent unauthorized disclosure or modification of personal data. Identity validation protects against impersonation and misuse of rights processes. This ensures that data access or deletion actions are performed only for legitimate requesters.', '2026-04-07T18:00:21.859625', '2026-04-07T18:00:21.859625', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('e942ad44-f8b2-4045-92eb-0f72cd32aa30', '43952b23-b228-4eb6-8a5e-4d883ac37039', 'name', 'Formal Risk Acceptance Process', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('e9505534-296e-409b-ad62-aa9b95d50e2e', '86c070c0-91b7-43ff-9c60-259e6df53c28', 'guidance', 'Use system-based consent capture and storage to maintain verifiable records tied to user identity and processing purpose.', '2026-04-07T18:00:21.755596', '2026-04-07T18:00:21.755596', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('e9a4dfce-c9bb-4190-9a16-8bc930aebcaf', '03e55674-3c5f-494e-9189-f2d36adf5fd2', 'name', 'Implement Data Principal Rights Request Workflow', '2026-04-07T18:44:26.510705', '2026-04-07T18:44:26.510705', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ea138749-e0b4-491b-b37e-3fb6f9f6a322', 'c8fe0a12-fcc8-42e3-8163-9c55bdcaf363', 'description', 'Create and maintain an inventory of information assets, including systems, data repositories, and supporting infrastructure, with clearly assigned owners responsible for their protection. Asset ownership ensures accountability for classification, security controls, and lifecycle management.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('eb00be75-e343-49e0-b52d-1ecfa60f733d', 'ab57aba8-5084-4083-a655-c0f3e18e502b', 'name', 'Perform Cloud Service Security Risk Assessment and Governance', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('eb3d4e14-7af1-4782-a9d2-29416c729fa4', 'e23914b9-c312-4e9b-ba01-bae41134a4e3', 'description', 'Security vulnerabilities identified through scanning, monitoring, or external notifications are formally tracked and remediated within defined timelines. A structured remediation workflow ensures vulnerabilities are prioritized based on risk and systematically addressed. This reduces exposure windows and prevents exploitation of known weaknesses.', '2026-04-06T15:17:22.864221', '2026-04-06T15:17:22.864221', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('eb9e2ec2-d22a-4d40-bdf8-a47979ac7d18', 'af2212ca-5633-4b3d-bf2d-5631044687ee', 'implementation_guidance', '["Define document classification and access rules.", "Maintain version history and change logs.", "Store ISMS documentation in secure repositories.", "Control access to sensitive documentation."]', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ebc7e6d8-fb65-4236-9042-8b538ec9570a', 'acf1b338-e2ae-482c-af35-5356fbd8d825', 'name', 'Publish and Maintain Privacy Notice', '2026-04-07T19:13:14.135822', '2026-04-07T19:13:14.135822', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ec25e3a0-dc7a-49d7-983f-6a66e1cbb9b7', 'c1320778-ab81-407f-802a-232b40d61869', 'implementation_guidance', '["Define security objectives aligned with business strategy.", "Establish measurable KPIs and targets.", "Assign owners responsible for achieving objectives.", "Review objectives during management reviews."]', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ec6a0eac-8445-4d0c-8930-ee6470f74f40', '83270811-0d03-4058-a311-d9afa0cd6683', 'name', 'Monitor and Track Reported Control Issues and Security Concerns', '2026-04-06T15:17:02.319473', '2026-04-06T15:17:02.319473', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ec6b1e46-cc78-45e4-b004-e28319cee6aa', 'd81a9e2e-4a43-4a3b-b55d-a061d9bfcb36', 'guidance', 'Maintain a record of processing activities identifying the lawful basis and ensure processing activities are periodically reviewed for continued legality.', '2026-04-07T18:58:48.893819', '2026-04-07T18:58:48.893819', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ec91d3f1-2b15-440d-9ad8-ea2ca98a69cd', 'a7ff3eaa-2d5c-4086-a546-ee387abaaa68', 'guidance', 'Use automated discovery tools where possible and ensure asset ownership is assigned and regularly reviewed.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ecabc33b-af2a-489f-8a55-4ecb10866ad1', 'd2035e09-3460-4afa-9d2e-b07166eb1053', 'guidance', 'Use centralized logging platforms or SIEM solutions to correlate events and detect anomalies across the environment.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('edf897fa-7f19-4eff-a8dd-252ca35c1ff7', '06c7a2a2-fd07-4722-93ea-08faa4099ad9', 'description', 'Implement environmental and infrastructure protections to safeguard information processing equipment from damage, disruption, or theft. Protective measures reduce risks associated with environmental threats such as fire, water damage, power loss, or temperature fluctuations.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ee2e29fc-1382-4ca8-b314-14625e92830f', 'b60d5a03-72bf-4c9f-a31c-a0c55d70adbc', 'implementation_guidance', '["Subscribe to trusted threat intelligence feeds and vulnerability advisories", "Analyze intelligence for relevance to organizational technologies and assets", "Share threat insights with security operations and risk management teams", "Update defensive controls and risk assessments based on identified threats"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ee7b1fec-def0-4e62-aefa-11f4156bc9fc', 'acc1fd26-f64d-4f8f-a185-ec00e9a3810d', 'acceptance_criteria', '["Privacy notices are accessible to Data Principals", "Notices clearly describe purposes, rights, and contact information"]', '2026-04-07T18:58:50.76989', '2026-04-07T18:58:50.76989', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('eee8cccd-9f68-4ee5-a422-e72a9c047d50', '35d4079b-2f12-4766-94ca-cc9ac44e1fd2', 'guidance', 'A processing register helps demonstrate that all personal data processing activities have a defined legal basis and remain limited to permitted purposes.', '2026-04-07T19:13:14.03935', '2026-04-07T19:13:14.03935', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('eff25140-2c99-4b34-ac9a-0a538e1d7940', '09be1965-a848-4f25-9954-4fd11f08c114', 'description', 'Provide personnel with a confidential mechanism to report suspected security incidents, control deficiencies, policy violations, or unethical behavior. This control encourages early detection of control failures and supports rapid investigation and remediation.', '2026-04-06T15:17:00.783771', '2026-04-06T15:17:00.783771', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f0064b66-2d40-40b2-83e1-c3e3ee231206', 'ffdbf966-a83e-4ad1-8406-bf7f8a6f57b7', 'guidance', 'Management reviews should consider audit results, risk status, incident trends, performance metrics, stakeholder feedback, and opportunities for improvement.', '2026-04-09T04:20:31.911119', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f0327923-0cae-44c8-b37d-b794db6b9597', '7ab5c678-2e60-4f36-b832-e4693593e6a2', 'guidance', 'Document communication workflows and escalation paths for incident notifications and regulatory reporting.', '2026-04-06T15:17:01.705747', '2026-04-06T15:17:01.705747', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f0612459-5e4b-49b4-9235-065729f310ca', 'ec516637-5c4e-4dc6-8e61-262c67e3a4c5', 'description', 'Implement processes to manage the lifecycle of identities for users, systems, and services from creation through modification to deactivation. Proper lifecycle management ensures accountability and prevents orphaned or unauthorized accounts.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f171d2a2-fbe4-479c-9f89-fa624d83d677', 'b6e361d7-079e-4f98-8170-8088e16fe228', 'description', 'Privileged accounts with administrative or elevated system capabilities are tightly controlled and monitored to prevent misuse. Access to privileged roles is limited to authorized personnel and granted only when necessary. Enhanced monitoring ensures that suspicious or unauthorized administrative activities are detected promptly.', '2026-04-06T15:17:16.316161', '2026-04-06T15:17:16.316161', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f200886c-38e0-431e-b684-e5d9bbe99128', 'b4280d33-d460-4088-9ba0-b94e269dbcf9', 'description', 'Provide a formal mechanism for Data Principals to submit complaints related to personal data processing. The process ensures grievances are reviewed, investigated, and resolved within defined timelines while maintaining records for accountability and regulatory review.', '2026-04-07T18:00:22.189082', '2026-04-07T18:00:22.189082', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f258f716-bf12-44b0-8a2b-b82582b5b806', 'd81a9e2e-4a43-4a3b-b55d-a061d9bfcb36', 'description', 'Ensure that every personal data processing activity has a documented lawful basis under the DPDP Act, such as valid consent or permitted legitimate use.', '2026-04-07T18:58:48.893819', '2026-04-07T18:58:48.893819', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f2823bfe-4b9a-49a9-92fb-3813580a4037', 'ab57aba8-5084-4083-a655-c0f3e18e502b', 'description', 'Assess risks associated with the use of cloud services and define governance structures that clarify shared security responsibilities. This ensures that cloud deployments meet organizational security requirements and regulatory obligations.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f2d0c760-8cfe-4585-b729-21c43a89e987', 'e850596d-9344-4aca-86d1-609ca5c0c632', 'guidance', 'Compliance reviews should include sampling of processing activities, documentation checks, and control effectiveness validation.', '2026-04-07T18:58:57.558116', '2026-04-07T18:58:57.558116', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f36adba4-813f-4a20-b944-bc04fccdee95', '4d70ecb5-3e04-402d-bdef-a5bdaa3f9f2f', 'name', 'Conduct Automated Vulnerability Scanning of Infrastructure and Applications', '2026-04-06T15:17:20.930915', '2026-04-06T15:17:20.930915', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f3aa7a48-17b3-4115-aaf4-72346bf6a4e3', '3523377d-20ab-440f-bf84-9ec6866a1118', 'implementation_guidance', '["Record identified risks and associated assets.", "Document risk evaluation scores and risk owners.", "Link risks to relevant security controls.", "Review the risk register periodically."]', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f3dfef36-d440-4d4e-8412-d364be6e737f', '030931dc-2482-465d-a7a3-f00b4bbe4d45', 'guidance', 'Subscribe to trusted threat intelligence feeds and integrate insights into security monitoring and risk management activities.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f45113cd-998c-462c-8d23-9f27691bb81c', 'b4280d33-d460-4088-9ba0-b94e269dbcf9', 'implementation_guidance', '["Provide dedicated communication channels such as email, web forms, or portals for privacy grievances", "Define documented timelines and responsibilities for reviewing and resolving complaints", "Track grievances in a centralized register including investigation outcomes and responses", "Retain records of grievances and corrective actions for compliance and audit purposes"]', '2026-04-07T18:00:22.189082', '2026-04-07T18:00:22.189082', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f4f57f94-3e71-48c3-b077-643a54a10868', '92a83e90-dfb4-4db4-9f0c-e3ee077864d6', 'description', 'The organization establishes a code of conduct and security ethics policy that sets expectations for ethical behavior, acceptable system use, and responsible data handling. This policy helps prevent misuse of access and promotes a culture of accountability and integrity. All personnel are required to acknowledge and adhere to these standards.', '2026-04-06T15:16:57.726409', '2026-04-06T15:16:57.726409', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f5505827-8e6f-4fa5-9207-24bb704905dd', '4d70ecb5-3e04-402d-bdef-a5bdaa3f9f2f', 'description', 'Automated vulnerability scans are performed regularly to identify security weaknesses in operating systems, applications, containers, and network infrastructure. Identified vulnerabilities are evaluated and prioritized based on severity and exploitability. This process helps reduce the likelihood of system compromise due to unpatched or misconfigured systems.', '2026-04-06T15:17:20.930915', '2026-04-06T15:17:20.930915', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f5638ce5-89d8-49e2-ba71-193a8b59ad1e', 'af2212ca-5633-4b3d-bf2d-5631044687ee', 'description', 'Ensure ISMS documentation is properly created, maintained, protected, and controlled.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f5718f5d-341d-446f-97df-649916460166', 'c1014a97-65e3-4708-a81f-5c6f44b101ea', 'implementation_guidance', '["Define vendor risk tiers based on data sensitivity, system access, and operational criticality", "Require vendors to complete security questionnaires or provide independent assurance reports (e.g., SOC 2, ISO 27001)", "Evaluate vendor security controls related to access management, encryption, incident response, and data protection", "Document identified risks and required remediation actions prior to onboarding", "Perform periodic reassessments of critical vendors"]', '2026-04-06T15:17:05.877428', '2026-04-06T15:44:43.484375', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f62050b5-8c5d-4c4e-a7ec-634bbb3852b3', 'd81a9e2e-4a43-4a3b-b55d-a061d9bfcb36', 'acceptance_criteria', '["All personal data processing activities have a documented lawful basis", "Processing records are maintained and reviewed periodically"]', '2026-04-07T18:58:48.893819', '2026-04-07T18:58:48.893819', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f63ce5f5-b63e-4524-9a3d-d54158b07ec8', 'ec516637-5c4e-4dc6-8e61-262c67e3a4c5', 'guidance', 'Integrate identity lifecycle management with HR onboarding, role change, and termination processes.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f64effb8-a77b-4712-85e9-cc2b0c7606ad', 'faa66b97-7296-48fb-a583-83937c6eea3d', 'guidance', 'Require personnel to acknowledge the acceptable use policy during onboarding and periodically thereafter.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f67333d2-5c33-4ec5-b592-f7d2ca2fee58', 'f141e977-07d6-474b-8e8b-20e7942f4a05', 'name', 'Provide Clear Privacy Notices for Personal Data Processing', '2026-04-07T18:00:21.803774', '2026-04-07T18:00:21.803774', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f6fa73e2-fe5f-4009-a1c2-e331335d9a5f', '23944a7a-86ca-44cf-9dda-646af9285768', 'guidance', 'Establish an internal audit or independent review function responsible for testing key controls on a scheduled basis.', '2026-04-06T15:17:08.49601', '2026-04-06T15:17:08.49601', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f766d845-8c14-4e6e-abbe-bf1f5f5476ac', 'c82506bd-f1bd-4e46-99cc-5db937b44b08', 'description', 'Require secure authentication methods to verify user and system identities before granting access. Strong authentication reduces the likelihood of unauthorized access through credential compromise or impersonation.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f7a46ef5-d2f6-430a-9b6e-dc425ce04ca8', 'c8fe0a12-fcc8-42e3-8163-9c55bdcaf363', 'implementation_guidance', '["Identify all information assets including hardware, software, and data repositories", "Assign accountable owners responsible for security and lifecycle management", "Record asset details such as location, classification, and responsible department", "Review and update the asset inventory periodically"]', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f7d1985d-7eac-4711-a19e-24c3bb38c793', 'f436e044-b778-4cfa-affc-0d0972c4ea9d', 'implementation_guidance', '["Identify categories of personal data processed", "Define retention periods for each category", "Publish and enforce retention policy across systems"]', '2026-04-07T18:58:54.799828', '2026-04-07T18:58:54.799828', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f7e06d31-2701-4cf5-a5df-7cd5ce5577fd', 'd824b0c1-df1b-40fd-8501-a60670bcbaff', 'guidance', 'Ensure the DPO operates with sufficient authority and independence and that DPIAs are performed before initiating high-risk processing.', '2026-04-07T18:00:22.214777', '2026-04-07T18:00:22.214777', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f7f5f68c-7430-4b6c-97c2-73741126a3cb', '03e55674-3c5f-494e-9189-f2d36adf5fd2', 'guidance', 'Use a centralized tracking system to manage request intake, verification, fulfillment, and response timelines.', '2026-04-07T18:44:26.510705', '2026-04-07T18:44:26.510705', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f8732e80-c118-4eb9-af72-19492dda88e7', '4db2d477-80ee-458e-91dd-1bd4748d5e08', 'description', 'Establish retention schedules defining how long personal data may be stored and enforce automated or procedural deletion once retention periods expire.', '2026-04-07T19:13:14.349303', '2026-04-07T19:13:14.349303', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f91ad046-4f86-4954-83e1-4ca428812a1f', '68054153-8595-4c5c-a1b9-19efe701bc36', 'guidance', 'Develop baseline configurations aligned with recognized standards and enforce them using configuration management or infrastructure-as-code tools.', '2026-04-06T15:17:12.445575', '2026-04-06T15:17:12.445575', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f9917163-a96d-4a43-afce-1e6c42ab5088', 'c82506bd-f1bd-4e46-99cc-5db937b44b08', 'guidance', 'Implement multi-factor authentication and enforce strong credential management standards.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('f9d51bdc-6a7f-4410-b1ca-8a3d13dcf7b3', '1ec5e73a-a759-428b-b6a1-d4da25595173', 'implementation_guidance', '["Implement age verification checks during account creation or data collection", "Require verifiable parental or guardian consent before processing children''s personal data", "Store consent records and verification evidence for audit and compliance purposes", "Block or suspend processing if parental consent cannot be verified"]', '2026-04-07T18:00:22.14531', '2026-04-07T18:00:22.14531', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('f9dec992-2b74-416b-b003-e6afa5fad045', '8c10560c-13fc-40b8-ad63-85028278507c', 'implementation_guidance', '["Require documentation of control exceptions including justification, scope, and duration.", "Assign remediation owners and due dates for resolving identified deviations.", "Review open exceptions periodically to ensure timely closure.", "Escalate overdue or high-risk exceptions to management for action.", "Maintain historical records of exceptions for audit and trend analysis."]', '2026-04-06T15:17:14.353424', '2026-04-06T15:17:14.353424', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fad5fa15-d346-4651-83d0-b18623aaf4d1', '94d788d9-4311-4ed6-861d-6ee1cad7f485', 'description', 'All changes to production systems, infrastructure, and security configurations must undergo a documented approval process before implementation. This control ensures that changes are reviewed for security, operational, and compliance risks and authorized by appropriate personnel. It reduces the likelihood of unauthorized or poorly evaluated modifications affecting systems or data.', '2026-04-06T15:17:11.166836', '2026-04-06T15:17:11.166836', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fae2485b-3ac8-4f41-9417-d59d3bbf7262', 'b61a8edb-cb85-4500-814b-607c2ce6fd0e', 'guidance', 'Requests should be tracked and processed within legally required timelines.', '2026-04-07T18:58:51.742261', '2026-04-07T18:58:51.742261', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('fbd1be9e-b6e8-4e50-847d-02492466efd2', '1967551b-0805-4cb9-b86e-3cf0b5d5b68a', 'description', 'Establish processes to monitor, measure, analyze, and evaluate the effectiveness of information security controls and the overall ISMS performance using defined metrics and indicators.', '2026-04-09T04:20:32.033669', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fbfc4912-f2e3-4981-91fa-3c751fdf3640', '5941b7d5-2d87-4ccf-888d-1fa8a300cf85', 'description', 'Maintain documented records of personal data processing activities including purposes, categories of data, recipients, and safeguards.', '2026-04-07T19:13:14.510545', '2026-04-07T19:13:14.510545', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('fc603cb4-d478-41b6-8dee-dadea676b079', '6089f2be-7719-45ce-aa86-15f5fba07601', 'guidance', 'Implement identity verification steps appropriate to the sensitivity of the requested action.', '2026-04-07T18:00:21.859625', '2026-04-07T18:00:21.859625', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('fc628703-7db6-47b8-9982-c633dc51e03d', '8d4080da-ac23-4efe-a90e-4b00af17484d', 'guidance', 'Integrate defined responsibilities into job descriptions, onboarding processes, and governance documentation.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fcf3a182-33f9-4730-bbc3-cd51ec78936a', '093fc395-e769-4882-93d9-441ee7e46edf', 'description', 'Implement a structured process to monitor regulatory updates, legal developments, and contractual obligations that may impact information security and data protection practices. Identified changes are assessed for operational and control impact and translated into required policy or control updates. Evidence of review and remediation actions is documented for audit purposes.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fd0b4b6c-0456-4db0-8104-17cbba6bae35', '5b5296da-9902-4c5d-8232-b601ab5f1852', 'guidance', 'A centralized processing inventory helps demonstrate lawful processing and enables regulatory audits.', '2026-04-07T19:36:39.573896', '2026-04-07T19:36:39.573896', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('fd20f6b9-7ac1-4827-9f80-f429a5eb91b6', '037846f7-1941-4d75-8ff7-a8cbbe770ca3', 'acceptance_criteria', '["All personnel receive security awareness training upon onboarding", "Periodic refresher training is conducted at defined intervals", "Training completion rates are tracked and reported", "Role-based training is provided for personnel with elevated privileges or specialized responsibilities"]', '2026-04-09T04:20:31.950465', '2026-04-09T04:20:31.950465', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fd30b5eb-9b8a-4b1d-a3ed-f50818504904', '35d4079b-2f12-4766-94ca-cc9ac44e1fd2', 'acceptance_criteria', '["A documented processing register exists covering all personal data processing activities", "Each processing activity includes a clearly documented lawful basis", "Processing register is reviewed periodically and updated when processing changes"]', '2026-04-07T19:13:14.03935', '2026-04-07T19:13:14.03935', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('fd57deeb-76dc-4545-8a2f-6f9f1114b05b', 'e6097f6d-3449-4662-a8ec-2e01bce7be8c', 'description', 'Security-relevant events across systems, networks, and applications are continuously monitored to identify anomalies, control failures, or indicators of compromise. Centralized monitoring enables timely detection of suspicious activity and operational issues that may indicate ineffective or bypassed controls. This ensures ongoing visibility into the effectiveness of the control environment.', '2026-04-06T15:17:07.173021', '2026-04-06T15:17:07.173021', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fd73409f-1b78-4806-8816-c07d2d274a7a', 'd2081300-717e-4950-b793-28a3c7fb7116', 'guidance', 'Context analysis should consider regulatory environment, threat landscape, technology dependencies, business strategy, and organizational structure.', '2026-04-09T04:13:35.339189', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fe1cdebd-a1da-4ef7-8e75-2cb085c081bc', '78949283-ef74-4348-9f54-59a6e1684de3', 'acceptance_criteria', '["High-risk processing activities undergo DPIA", "DPIA results and mitigation actions are documented", "Approvals are recorded before system deployment"]', '2026-04-07T19:36:46.773235', '2026-04-07T19:36:46.773235', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('fe6c30ec-e645-41d3-ac29-ddee6ab382a4', '58f06dce-a956-4fc2-8296-d00129e311cd', 'implementation_guidance', '["Define a document management process for ISMS documentation", "Implement version control and approval workflows for policy and procedure updates", "Ensure documents are accessible to authorized personnel and protected from unauthorized modification", "Maintain records of document revisions and review history"]', '2026-04-09T04:20:31.993586', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('fe918fc8-af72-457b-a6ea-53436dfd7f00', 'd4095971-8355-49cd-905c-bcfb20d22fe1', 'guidance', 'Incorporate data minimization checks during system design and data collection form development.', '2026-04-07T18:00:21.90538', '2026-04-07T18:00:21.90538', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('fed77849-db69-4a9e-a43b-9faddfdae8fb', '20718b9e-9375-4e96-af44-d05e846040f9', 'implementation_guidance', '["Require documented rollback procedures within change records for high\u2011risk or production changes", "Validate rollback capability during testing or staging deployments where feasible", "Maintain backups or snapshots prior to major changes", "Train operations personnel on executing rollback procedures", "Document lessons learned after rollback events to improve future change planning"]', '2026-04-06T15:17:27.380805', '2026-04-06T15:17:27.380805', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ff1c62ef-e997-44e2-a8c5-00d19a77eb9f', '3f51c19f-8007-4d80-9a08-142fca38e737', 'name', 'Personal Data Collection Minimization Review', '2026-04-07T19:36:43.86175', '2026-04-07T19:36:43.86175', '4add1867-32f4-4871-aa48-c683114039ce', '4add1867-32f4-4871-aa48-c683114039ce'),
      ('ff2726f3-8dd9-44e3-8812-c7029bac0ce4', '04c83c8e-e4e6-4951-acea-6f43493331d7', 'name', 'Maintain Centralized Repository for Security Policies and Control Documentation', '2026-04-06T15:17:00.161767', '2026-04-06T15:17:00.161767', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('ff9dbe63-9fdb-43b3-b4e6-4eed54fcb625', 'a469476d-d763-406e-8727-2d48ac513084', 'description', 'Establish formal agreements and monitoring processes governing information transfers with internal teams and external parties. These agreements clarify responsibilities and ensure transfers comply with security, privacy, and regulatory requirements.', '2026-04-08T17:01:44.377349', '2026-04-09T04:25:49.713986', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
