compliant", "expected_output": {"result": "pass", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository devops-helper-scripts (acme/devops-helper-scripts) archive status evaluated"}], "summary": "0/1 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}], "description": "", "json_schema": null, "dataset_code": "ai-tests-github_repositories_archived_detection-3695cc37", "record_count": 18}, "dataset_template": null}'::jsonb, '7b89f85a-c665-4a8c-93c0-fef8d24f2824', '14f1cd79-7947-436f-8d23-89d56dfacef8', NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 5, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-31T10:52:21.68659+00:00', TRUE, FALSE, '2026-03-31T10:52:21.68659+00:00', '2026-04-08T11:06:14.265693+00:00'),
      ('1f23c931-50a9-4127-ae18-4b6a8b043c3c', 'stale_repository_detection', 'github', 1, '{"policy": null, "signals": [{"name": "GitHub Repository Stale Push Age", "timeout_ms": 10000, "description": "Detects repositories whose last push is older than a configured number of days.", "signal_code": "github_repo_stale_push_age", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    pushed_at = dataset.get(\"pushed_at\", \"\")\n\n    threshold_days = 180\n    now = datetime.datetime.now(datetime.timezone.utc)\n\n    repo_identifier = external_id if external_id else name if name else \"unknown\"\n\n    if not pushed_at:\n        details.append({\n            \"check\": \"repo_push_age\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{repo_identifier}'' has no valid pushed_at timestamp (pushed_at=''{pushed_at}''), so the repository activity age cannot be calculated against the {threshold_days}-day threshold\"\n        })\n        return {\n            \"result\": \"warning\",\n            \"summary\": f\"Repository ''{repo_identifier}'' could not be evaluated because the last push timestamp is missing\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    try:\n        if isinstance(pushed_at, datetime.datetime):\n            pushed_dt = pushed_at.astimezone(datetime.timezone.utc) if pushed_at.tzinfo else pushed_at.replace(tzinfo=datetime.timezone.utc)\n        elif isinstance(pushed_at, str):\n            s = pushed_at.strip()\n            if s.endswith(\"Z\"):\n                s = s[:-1] + \"+00:00\"\n            pushed_dt = datetime.datetime.fromisoformat(s)\n            if pushed_dt.tzinfo is None:\n                pushed_dt = pushed_dt.replace(tzinfo=datetime.timezone.utc)\n            else:\n                pushed_dt = pushed_dt.astimezone(datetime.timezone.utc)\n        else:\n            raise ValueError(\"unsupported pushed_at type\")\n    except:\n        details.append({\n            \"check\": \"repo_push_age\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{repo_identifier}'' has an invalid pushed_at value (''{pushed_at}'') which cannot be parsed as ISO8601 time, preventing comparison with the {threshold_days}-day threshold\"\n        })\n        return {\n            \"result\": \"warning\",\n            \"summary\": f\"Repository ''{repo_identifier}'' could not be evaluated due to invalid last push timestamp format\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    age_days = (now - pushed_dt).total_seconds() / 86400\n    age_days_int = int(age_days)\n\n    if age_days_int > threshold_days:\n        status = \"fail\"\n        comparison = \"above\"\n    else:\n        status = \"pass\"\n        comparison = \"below or equal to\"\n\n    details.append({\n        \"check\": \"repo_push_age\",\n        \"status\": status,\n        \"message\": f\"Repository ''{repo_identifier}'' last pushed at {pushed_at}, approximately {age_days_int} days ago, which is {comparison} the allowed {threshold_days}-day inactivity threshold\"\n    })\n\n    if status == \"fail\":\n        summary = f\"Repository ''{repo_identifier}'' last push is {age_days_int} days old, exceeding the {threshold_days}-day threshold\"\n    else:\n        summary = f\"Repository ''{repo_identifier}'' last push is {age_days_int} days old, within the {threshold_days}-day threshold\"\n\n    return {\n        \"result\": status,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_repository_confirmed_inactive", "description": "", "threat_code": "github_repository_confirmed_inactive", "severity_code": "medium", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "github_repo_stale_push_age", "expected_result": "fail"}, {"operator": "NOT", "conditions": [{"signal_code": "github_repo_stale_push_age", "expected_result": "pass"}]}]}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_repo_stale_push_age", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Recent repository push well within default threshold", "dataset_input": {"name": "auth-service", "pushed_at": "2026-03-01T10:15:30Z", "_external_id": "acme/auth-service"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository auth-service last pushed 25 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Recently updated infrastructure repository", "dataset_input": {"name": "infra-terraform", "pushed_at": "2026-02-10T08:22:11Z", "_external_id": "cloudops/infra-terraform"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository infra-terraform last pushed 44 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_003", "description": "Repository with push older than default threshold", "dataset_input": {"name": "legacy-payment-gateway", "pushed_at": "2025-01-12T05:10:00Z", "_external_id": "fintech/legacy-payment-gateway"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository legacy-payment-gateway last pushed 438 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_004", "description": "Very old archived repository", "dataset_input": {"name": "old-reporting-engine", "pushed_at": "2023-11-03T14:00:00Z", "_external_id": "analytics/old-reporting-engine"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository old-reporting-engine last pushed 874 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_005", "description": "Repository slightly stale relative to threshold", "_verification": {"reason": "The detection logic marks a repository as fail if age_days > max_days_since_push (default 180). From 2025-07-15 to 2026-03-26 is about 254 days, which exceeds the 180‑day threshold, so the correct result is fail, not warning.", "original_result": "warning", "corrected_result": "fail"}, "dataset_input": {"name": "customer-data-sync", "pushed_at": "2025-07-15T09:00:00Z", "_external_id": "platform/customer-data-sync"}, "scenario_name": "mixed", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository customer-data-sync last pushed 254 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_006", "description": "Repository pushed exactly around the boundary threshold", "_verification": {"reason": "The logic marks a repository as fail only if age_days > max_days_since_push (180). A push exactly ~180 days ago does not exceed the threshold, so the record should pass. The evaluate() function for a single record also does not produce ''warning''.", "original_result": "warning", "corrected_result": "pass"}, "dataset_input": {"name": "edge-threshold-repo", "pushed_at": "2025-09-27T00:00:00Z", "_external_id": "security/edge-threshold-repo"}, "scenario_name": "boundary_value", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository edge-threshold-repo last pushed 180 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_007", "description": "Very recent commit activity", "dataset_input": {"name": "ui-dashboard", "pushed_at": "2026-03-20T16:42:00Z", "_external_id": "frontend/ui-dashboard"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository ui-dashboard last pushed 6 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_008", "description": "Abandoned open source mirror repository", "dataset_input": {"name": "openssl-fork", "pushed_at": "2024-06-01T11:30:00Z", "_external_id": "archive/openssl-fork"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository openssl-fork last pushed 663 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_009", "description": "Single repository slightly within acceptable activity window", "dataset_input": {"name": "mobile-api", "pushed_at": "2025-12-20T12:00:00Z", "_external_id": "apps/mobile-api"}, "scenario_name": "single_item", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository mobile-api last pushed 96 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_010", "description": "Single stale repository beyond threshold", "dataset_input": {"name": "deprecated-auth-lib", "pushed_at": "2025-02-01T07:00:00Z", "_external_id": "libs/deprecated-auth-lib"}, "scenario_name": "single_item", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository deprecated-auth-lib last pushed 418 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_011", "description": "Repository just under threshold", "dataset_input": {"name": "near-threshold-repo", "pushed_at": "2025-09-30T10:00:00Z", "_external_id": "platform/near-threshold-repo"}, "scenario_name": "boundary_value", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository near-threshold-repo last pushed 177 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_012", "description": "Repository just over threshold", "dataset_input": {"name": "slightly-stale-repo", "pushed_at": "2025-09-20T10:00:00Z", "_external_id": "platform/slightly-stale-repo"}, "scenario_name": "boundary_value", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository slightly-stale-repo last pushed 187 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_013", "description": "Threshold overridden to minimum value", "_verification": {"reason": "With the threshold overridden to the minimum (1 day), a repository is stale if age_days > 1. A push at 2026-03-25T09:00:00Z will typically be more than 1 day old when evaluated on 2026-03-26, so it should be marked fail.", "original_result": "pass", "corrected_result": "fail"}, "dataset_input": {"name": "daily-build-scripts", "pushed_at": "2026-03-25T09:00:00Z", "_external_id": "devops/daily-build-scripts"}, "scenario_name": "config_min_boundary", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository daily-build-scripts last pushed 1 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {"max_days_since_push": 1}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_014", "description": "Threshold minimum causing repository to fail", "dataset_input": {"name": "slow-update-tool", "pushed_at": "2026-03-20T09:00:00Z", "_external_id": "tools/slow-update-tool"}, "scenario_name": "config_min_boundary", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository slow-update-tool last pushed 6 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {"max_days_since_push": 1}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_015", "description": "Threshold overridden to maximum allowing very old repository", "dataset_input": {"name": "historic-codebase", "pushed_at": "2018-05-10T12:00:00Z", "_external_id": "archive/historic-codebase"}, "scenario_name": "config_max_boundary", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository historic-codebase last pushed 2877 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {"max_days_since_push": 3650}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_016", "description": "Extremely old repository still exceeding maximum threshold", "dataset_input": {"name": "ancient-monolith", "pushed_at": "2010-01-01T00:00:00Z", "_external_id": "legacy/ancient-monolith"}, "scenario_name": "config_max_boundary", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository ancient-monolith last pushed 5937 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {"max_days_since_push": 3650}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_017", "description": "Repository moderately stale but near operational boundary", "_verification": {"reason": "Per spec a repository fails if age_days > 180. With pushed_at=2025-06-01 and current date 2026-03-26, the repo is ~298 days old, exceeding the threshold. The per-record evaluation only yields pass or fail, not warning.", "original_result": "warning", "corrected_result": "fail"}, "dataset_input": {"name": "integration-adapters", "pushed_at": "2025-06-01T10:10:10Z", "_external_id": "enterprise/integration-adapters"}, "scenario_name": "mixed", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository integration-adapters last pushed 298 days ago which is above the threshold"}], "summary": "1/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_018", "description": "No repository records available", "_verification": {"reason": "The scenario ''empty_dataset'' means no records should be evaluated. The provided input is a record with required fields present but empty. Since ''pushed_at'' is required and must be a valid ISO8601 timestamp for age calculation, the detection logic cannot parse it, so the record cannot pass the check. This should result in a fail, not pass.", "original_result": "pass", "corrected_result": "fail"}, "dataset_input": {"name": "", "pushed_at": "", "_external_id": ""}, "scenario_name": "empty_dataset", "expected_output": {"result": "fail", "details": [], "summary": "0/0 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}], "description": "", "json_schema": null, "dataset_code": "ai-tests-github_repo_stale_push_age-1bbb7d56", "record_count": 18}, "dataset_template": null}'::jsonb, '5becae9f-94b3-47e1-9a9d-5870d37ab675', NULL, NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 0, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-30T05:17:38.15581+00:00', TRUE, FALSE, '2026-03-30T05:17:38.15581+00:00', '2026-03-30T05:17:38.15581+00:00'),
      ('29c489fc-1bbd-4703-9957-0ade0c8db3c6', 'github_template_repository_detection', 'github', 1, '{"policy": null, "signals": [{"name": "GitHub Template Repository Detection", "timeout_ms": 10000, "description": "Detects repositories that are marked as template repositories.", "signal_code": "github_repo_template_repository_detected", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    is_template_raw = dataset.get(\"is_template\", \"\")\n    is_template = str(is_template_raw).lower() == \"true\"\n\n    # Detect empty dataset case\n    if name == \"\" and external_id == \"\" and is_template_raw == \"\":\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"0/0 repositories are marked as template repositories\",\n            \"details\": [],\n            \"metadata\": {}\n        }\n\n    total_repos = 1\n    template_repos = 1 if is_template else 0\n\n    if is_template:\n        details.append({\n            \"check\": \"template_repository_check\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is marked as a template repository (is_template={is_template_raw}), meaning it can be used to generate new repositories and may require stricter governance.\"\n        })\n        result = \"warning\"\n    else:\n        details.append({\n            \"check\": \"template_repository_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not marked as a template repository (is_template={is_template_raw}), so it cannot be used as a repository template.\"\n        })\n        result = \"pass\"\n\n    summary = f\"{template_repos}/{total_repos} repositories are marked as template repositories\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_template_repository_configuration_warning", "description": "", "threat_code": "github_template_repository_configuration_warning", "severity_code": "low", "expression_tree": {"signal_code": "github_repo_template_repository_detected", "expected_result": "warning"}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_repo_template_repository_detected", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Standard private repository not marked as template", "dataset_input": {"name": "internal-api", "is_template": "False", "_external_id": "acmecorp/internal-api"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "template_repository_check", "status": "pass", "message": "Repository internal-api (acmecorp/internal-api) is not marked as a template repository"}], "summary": "0/1 repositories are marked as template repositories"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Public fork repository but not a template", "dataset_input": {"name": "forked-ui-lib", "is_template": "False", "_external_id": "devhub/forked-ui-lib"}, "scenario_name": "public_fork_not_template", "expected_output": {"result": "pass", "details": [{"check": "template_repository_check", "status": "pass", "message": "Repository forked-ui-lib (devhub/forked-ui-lib) is not marked as a template repository"}], "summary": "0/1 repositories are marked as template repositories"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_003", "description": "Archived repository that is not a template", "dataset_input": {"name": "legacy-payment-service", "is_tem