er_login_match", "status": "fail", "message": "Repository core-platform (founder-raj/core-platform) owner_login=founder-raj does not match expected organization"}], "summary": "1/1 repositories are not owned by the expected organization"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_018", "description": "Security tooling repository under official org account", "dataset_input": {"name": "security-scanner", "_asset_type": "github_repo", "owner_login": "kreesalis", "_external_id": "kreesalis/security-scanner"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "owner_login_match", "status": "pass", "message": "Repository security-scanner (kreesalis/security-scanner) owner_login=kreesalis matches expected organization"}], "summary": "0/1 repositories are not owned by the expected organization"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}], "description": "", "json_schema": null, "dataset_code": "ai-tests-github_repo_owner_not_expected_org-c80bb295", "record_count": 18}, "dataset_template": null}'::jsonb, '1985f5f6-973b-4db3-b703-df98ffdede22', NULL, NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 0, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-30T05:17:35.9144+00:00', TRUE, FALSE, '2026-03-30T05:17:35.9144+00:00', '2026-03-30T05:17:35.9144+00:00'),
      ('47129551-fb73-4c1a-9390-00f39b79e56e', 'archived_repository_detection', 'github', 2, '{"policy": {"name": "Archived Repository Detection", "actions": [{"config": {}, "action_type": "notification"}], "description": "", "policy_code": "archived_repo_detection_8859aadd", "cooldown_minutes": 0}, "signals": [{"name": "GitHub Archived Repositories Detection", "timeout_ms": 10000, "description": "Detects GitHub repositories that are marked as archived.", "signal_code": "github_repositories_archived_detection", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    asset_type = dataset.get(\"_asset_type\", \"\")\n    name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\", \"unknown\")\n    is_archived_raw = dataset.get(\"is_archived\", \"\")\n    is_archived = is_archived_raw.lower() == \"true\"\n\n    total_repos = 0\n    archived_repos = 0\n\n    if asset_type != \"github_repo\":\n        details.append({\n            \"check\": \"repository_archive_status\",\n            \"status\": \"pass\",\n            \"message\": f\"Record with external_id ''{external_id}'' has _asset_type=''{asset_type}'', so it is not a GitHub repository and was skipped from archived repository evaluation\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"0 repositories evaluated\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    total_repos = 1\n\n    if is_archived:\n        archived_repos = 1\n        details.append({\n            \"check\": \"repository_archive_status\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is marked as archived (is_archived={is_archived_raw}), indicating the codebase is no longer actively maintained and should be reviewed for potential legacy risks\"\n        })\n    else:\n        details.append({\n            \"check\": \"repository_archive_status\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not archived (is_archived={is_archived_raw}), indicating it remains active and does not trigger the archived repository policy check\"\n        })\n\n    if total_repos == 0:\n        result = \"pass\"\n        summary = \"0 repositories evaluated\"\n    elif archived_repos == 0:\n        result = \"pass\"\n        summary = f\"{archived_repos}/{total_repos} repositories are archived\"\n    elif archived_repos < total_repos:\n        result = \"warning\"\n        summary = f\"{archived_repos}/{total_repos} repositories are archived\"\n    else:\n        result = \"fail\"\n        summary = f\"{archived_repos}/{total_repos} repositories are archived\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_archived_repository_legacy_code_risk", "description": "", "threat_code": "github_archived_repository_legacy_code_risk_f2219651", "severity_code": "medium", "expression_tree": {"signal_code": "github_repositories_archived_detection", "expected_result": "fail"}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_repositories_archived_detection", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Single active repository that is not archived", "dataset_input": {"name": "payment-service", "_asset_type": "github_repo", "is_archived": "False", "_external_id": "acme/payment-service"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository payment-service (acme/payment-service) archive status evaluated"}], "summary": "0/1 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Another active repository that is not archived", "dataset_input": {"name": "inventory-api", "_asset_type": "github_repo", "is_archived": "False", "_external_id": "acme/inventory-api"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository inventory-api (acme/inventory-api) archive status evaluated"}], "summary": "0/1 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_003", "description": "Repository is archived and should trigger failure", "dataset_input": {"name": "legacy-auth-lib", "_asset_type": "github_repo", "is_archived": "True", "_external_id": "acme/legacy-auth-lib"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "repository_archive_status", "status": "fail", "message": "Repository legacy-auth-lib (acme/legacy-auth-lib) archive status evaluated"}], "summary": "1/1 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_004", "description": "Archived infrastructure repository", "dataset_input": {"name": "old-terraform-modules", "_asset_type": "github_repo", "is_archived": "True", "_external_id": "acme/old-terraform-modules"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "repository_archive_status", "status": "fail", "message": "Repository old-terraform-modules (acme/old-terraform-modules) archive status evaluated"}], "summary": "1/1 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_005", "description": "Single archived repository boundary case", "dataset_input": {"name": "deprecated-mobile-sdk", "_asset_type": "github_repo", "is_archived": "True", "_external_id": "acme/deprecated-mobile-sdk"}, "scenario_name": "boundary_value_single_archived", "expected_output": {"result": "fail", "details": [{"check": "repository_archive_status", "status": "fail", "message": "Repository deprecated-mobile-sdk (acme/deprecated-mobile-sdk) archive status evaluated"}], "summary": "1/1 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_006", "description": "Archived repository detected producing warning scenario", "_verification": {"reason": "The record has is_archived = ''True''. With a single evaluated repository, archived_repos = 1 and total_repos = 1, which matches the spec condition archived_repos == total_repos, resulting in ''fail'', not ''warning''. The ''warning'' outcome only applies when some but not all repositories are archived.", "original_result": "warning", "corrected_result": "fail"}, "dataset_input": {"name": "legacy-reporting-engine", "_asset_type": "github_repo", "is_archived": "True", "_external_id": "acme/legacy-reporting-engine"}, "scenario_name": "mixed", "expected_output": {"result": "fail", "details": [{"check": "repository_archive_status", "status": "warning", "message": "Repository legacy-reporting-engine (acme/legacy-reporting-engine) archive status evaluated"}], "summary": "1/2 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_007", "description": "Active repository contributing to mixed scenario", "_verification": {"reason": "The repository has is_archived=''False'', meaning it is not archived. According to the detection logic, if archived_repos == 0 after evaluation, the r