      ('48999bc5-3f0a-42f1-9f01-1e6112a33ee6', 'recent_unreviewed_repo_check', 'github', 1, '{"policy": null, "signals": [{"name": "Recently Created GitHub Repositories", "timeout_ms": 10000, "description": "Detects GitHub repositories created within a recent time window that require governance review.", "signal_code": "github_recent_repository_creation", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    created_at = dataset.get(\"created_at\", \"\")\n    owner = dataset.get(\"owner_login\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    if not external_id:\n        if owner and name:\n            external_id = owner + \"/\" + name\n        else:\n            external_id = name if name else \"unknown\"\n\n    review_window_days = 30\n    evaluation_time_str = \"2026-03-01T00:00:00Z\"\n\n    total_repos = 0\n    recent_repos = 0\n\n    if not name or not created_at:\n        details.append({\n            \"check\": \"recent_repository_creation\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository record has missing identifiers (name=''{name}'', created_at=''{created_at}''), so repository age cannot be evaluated and governance review cannot be verified\"\n        })\n        result = \"fail\"\n        summary = \"0/0 repositories could be evaluated due to missing repository metadata\"\n        return {\n            \"result\": result,\n            \"summary\": summary,\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    total_repos = 1\n\n    try:\n        eval_time = datetime.datetime.fromisoformat(evaluation_time_str.replace(\"Z\", \"+00:00\"))\n        created_time = datetime.datetime.fromisoformat(created_at.replace(\"Z\", \"+00:00\"))\n        delta = eval_time - created_time\n        age_days = delta.days\n    except Exception:\n        details.append({\n            \"check\": \"recent_repository_creation\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) has an invalid created_at timestamp ''{created_at}'', preventing calculation of repository age\"\n        })\n        return {\n            \"result\": \"fail\",\n            \"summary\": f\"Repository ''{name}'' could not be evaluated due to invalid creation timestamp\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    if age_days < 0:\n        details.append({\n            \"check\": \"recent_repository_creation\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) has created_at={created_at} which is in the future relative to evaluation_time={evaluation_time_str}, producing a negative age of {age_days} days\"\n        })\n    elif age_days <= review_window_days:\n        recent_repos += 1\n        details.append({\n            \"check\": \"recent_repository_creation\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) was created at {created_at} and is {age_days} days old relative to evaluation_time={evaluation_time_str}, which is within the {review_window_days}-day governance review window\"\n        })\n    else:\n        details.append({\n            \"check\": \"recent_repository_creation\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) was created at {created_at} and is {age_days} days old relative to evaluation_time={evaluation_time_str}, which is outside the {review_window_days}-day governance review window\"\n        })\n\n    if recent_repos == 0:\n        result = \"pass\"\n    elif recent_repos == total_repos:\n        result = \"fail\"\n    else:\n        result = \"warning\"\n\n    summary = f\"{recent_repos}/{total_repos} repositories were created within the {review_window_days}-day review window\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_recent_repository_created_review_warning", "description": "", "threat_code": "github_recent_repository_created_review_warning", "severity_code": "medium", "expression_tree": {"signal_code": "github_recent_repository_creation", "expected_result": "warning"}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_recent_repository_creation", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Repository created long before review window", "dataset_input": {"name": "infra-terraform-modules", "is_fork": "False", "pushed_at": "2025-12-11T10:21:44Z", "created_at": "2024-05-14T09:10:22Z", "is_private": "True", "updated_at": "2025-12-11T10:21:44Z", "visibility": "PRIVATE", "description": "Terraform modules for internal infrastructure", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "platform-team"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "recent_repository_creation", "status": "pass", "message": "Repository infra-terraform-modules (platform-team/infra-terraform-modules) created 656 days ago"}], "summary": "0/1 repositories were created within the review window"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Repository created very recently", "dataset_input": {"name": "ai-experiment-sandbox", "is_fork": "False", "pushed_at": "2026-02-26T13:11:02Z", "created_at": "2026-02-25T08:30:00Z", "is_private": "False", "updated_at": "2026-02-26T13:11:02Z", "visibility": "PUBLIC", "description": "Temporary AI prototype testing", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "ml-labs"}, "scen