      ('4a353712-cf42-4ba0-a660-b0ae7122f025', 'archived_repository_detection', 'github', 5, '{"policy": {"name": "Archived Repository Detection", "actions": [{"config": {}, "action_type": "notification"}], "description": "", "policy_code": "archived_repo_detection_8859aadd", "cooldown_minutes": 0}, "signals": [{"name": "GitHub Archived Repositories Detection", "timeout_ms": 10000, "description": "Detects GitHub repositories that are marked as archived.", "signal_code": "github_repositories_archived_detection", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    asset_type = dataset.get(\"_asset_type\", \"\")\n    name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\", \"unknown\")\n    is_archived_raw = dataset.get(\"is_archived\", \"\")\n    is_archived = is_archived_raw.lower() == \"true\"\n\n    total_repos = 0\n    archived_repos = 0\n\n    if asset_type != \"github_repo\":\n        details.append({\n            \"check\": \"repository_archive_status\",\n            \"status\": \"pass\",\n            \"message\": f\"Record with external_id ''{external_id}'' has _asset_type=''{asset_type}'', so it is not a GitHub repository and was skipped from archived repository evaluation\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"0 repositories evaluated\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    total_repos = 1\n\n    if is_archived:\n        archived_repos = 1\n        details.append({\n            \"check\": \"repository_archive_status\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is marked as archived (is_archived={is_archived_raw}), indicating the codebase is no longer actively maintained and should be reviewed for potential legacy risks\"\n        })\n    else:\n        details.append({\n            \"check\": \"repository_archive_status\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not archived (is_archived={is_archived_raw}), indicating it remains active and does not trigger the archived repository policy check\"\n        })\n\n    if total_repos == 0:\n        result = \"pass\"\n        summary = \"0 repositories evaluated\"\n    elif archived_repos == 0:\n        result = \"pass\"\n        summary = f\"{archived_repos}/{total_repos} repositories are archived\"\n    elif archived_repos < total_repos:\n        result = \"warning\"\n        summary = f\"{archived_repos}/{total_repos} repositories are archived\"\n    else:\n        result = \"fail\"\n        summary = f\"{archived_repos}/{total_repos} repositories are archived\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_archived_repository_legacy_code_risk", "description": "", "threat_code": "github_archived_repository_legacy_code_risk_f2219651", "severity_code": "medium", "expression_tree": {"signal_code": "github_repositories_archived_detection", "expected_result": "fail"}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_repositories_archived_detection", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Single active repository that is not archived", "dataset_input": {"name": "payment-service", "_asset_type": "github_repo", "is_archived": "False", "_external_id": "acme/payment-service"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository payment-service (acme/payment-service) archive status evaluated"}], "summary": "0/1 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null