d_output": {"result": "pass", "details": [{"check": "template_repository_check", "status": "pass", "message": "Repository ml-experiments (datascience/ml-experiments) is not marked as a template repository"}], "summary": "0/1 repositories are marked as template repositories"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_018", "description": "Dataset with no repository records", "dataset_input": {"name": "", "is_template": "", "_external_id": ""}, "scenario_name": "empty_dataset", "expected_output": {"result": "pass", "details": [], "summary": "0/0 repositories are marked as template repositories"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}], "description": "", "json_schema": null, "dataset_code": "ai-tests-github_repo_template_repository_detected-9e304608", "record_count": 18}, "dataset_template": null}'::jsonb, 'ba29e889-cb58-4c6d-a858-c2e97121adc6', NULL, NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 1, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-30T05:17:39.784225+00:00', TRUE, FALSE, '2026-03-30T05:17:39.784225+00:00', '2026-04-01T05:52:25.758053+00:00'),
      ('6e1c5757-f4db-40f2-96f0-15d0e057ab49', 'github_forked_repository_detection', 'github', 1, '{"policy": null, "signals": [{"name": "GitHub Forked Repository Detection", "timeout_ms": 10000, "description": "Detects GitHub repositories that are forks of other repositories.", "signal_code": "github_forked_repository_detected", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\")\n    owner = dataset.get(\"owner_login\", \"\")\n    if not external_id:\n        external_id = f\"{owner}/{name}\" if owner else name\n\n    is_fork_raw = dataset.get(\"is_fork\", \"False\")\n    is_archived_raw = dataset.get(\"is_archived\", \"False\")\n    asset_type = dataset.get(\"_asset_type\", \"github_repo\")\n\n    is_fork = str(is_fork_raw).lower() == \"true\"\n    is_archived = str(is_archived_raw).lower() == \"true\"\n\n    # Ensure we only evaluate GitHub repositories\n    if asset_type and asset_type != \"github_repo\":\n        details.append({\n            \"check\": \"asset_type_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Asset ''{external_id}'' has _asset_type={asset_type}, so it is not a GitHub repository and was not evaluated by the fork detection policy\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Asset ''{external_id}'' not applicable for GitHub fork evaluation\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    # Archived non-fork repositories are ignored (treated as zero evaluated)\n    if is_archived and not is_fork:\n        details.append({\n            \"check\": \"archived_repository_ignored\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is archived (is_archived={is_archived_raw}) and not a fork (is_fork={is_fork_raw}); archived non-fork repositories are excluded from evaluation\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"0 repositories evaluated because the repository is archived and excluded\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    # Evaluate fork status\n    if is_fork:\n        details.append({\n            \"check\": \"fork_status_check\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is marked as a fork (is_fork={is_fork_raw}), meaning it inherits code from an upstream repository which may introduce unreviewed dependencies or supply chain risk\"\n        })\n        result = \"fail\"\n        summary = \"1/1 repositories are forks\"\n    else:\n        details.append({\n            \"check\": \"fork_status_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not a fork (is_fork={is_fork_raw}), indicating it is an original repository and does not inherit upstream code\"\n        })\n        result = \"pass\"\n        summary = \"0/1 repositories are forks\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_forked_repository_inherited_vulnerability_risk", "description": "", "threat_code": "github_forked_repository_inherited_vulnerability_risk", "severity_code": "medium", "expression_tree": {"signal_code": "github_forked_repository_detected", "expected_result": "fail"}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_forked_repository_detected", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Private repository that is not a fork", "dataset_input": {"name": "internal-auth-service", "is_fork": "False", "pushed_at": "2025-01-10T11:21:33Z", "created_at": "2023-03