      ('8dc0363f-c571-4aa3-9b7e-dd6108fa9734', 'missing_repo_description_check', 'github', 2, '{"policy": null, "signals": [{"name": "GitHub Repositories Missing Description", "timeout_ms": 10000, "description": "Checks whether GitHub repositories have an empty description field.", "signal_code": "github_repo_missing_description", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    asset_type = dataset.get(\"_asset_type\", \"\")\n    name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\", \"unknown\")\n    description_raw = dataset.get(\"description\", \"\")\n\n    if asset_type != \"github_repo\":\n        details.append({\n            \"check\": \"repo_description_present\",\n            \"status\": \"pass\",\n            \"message\": f\"Asset ''{external_id}'' has _asset_type=''{asset_type}'', so the repository description policy check is not applicable (only evaluated for _asset_type=''github_repo'')\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Asset ''{external_id}'' is not a GitHub repository; description policy not applicable\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    description_normalized = (description_raw or \"\").strip()\n\n    if description_normalized == \"\":\n        details.append({\n            \"check\": \"repo_description_present\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) has an empty description field (description=''{description_raw}''), which reduces visibility for ownership, security review, and governance\"\n        })\n        result = \"fail\"\n        summary = f\"Repository ''{name}'' ({external_id}) is missing a description\"\n    else:\n        details.append({\n            \"check\": \"repo_description_present\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) includes a description (''{description_raw}''), providing context for ownership and governance\"\n        })\n        result = \"pass\"\n        summary = f\"Repository ''{name}'' ({external_id}) has a description configured\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "Repository Missing Documentation", "description": "", "threat_code": "repo_missing_documentation", "severity_code": "low", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "", "expected_result": "fail"}, {"signal_code": "github_repo_missing_description", "expected_result": "fail"}]}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_repo_missing_description", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Repository has a proper description", "dataset_input": {"name": "payment-gateway", "_asset_type": "github_repo", "description": "Core API gateway for payment platform", "_external_id": "fintech-labs/payment-gateway"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repo_description_present", "status": "pass", "message": "Repository payment-gateway (fintech-labs/payment-gateway) contains a valid description"}], "summary": "0/1 repositories are missing descriptions"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Repository with empty description", "dataset_input": {"name": "infra-modules", "_asset_type": "github_repo", "description": "", "_external_id": "acme-sec/infra-modules"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "repo_description_present", "status": "fail", "message": "Repository infra-modules (