      ('a5f0c896-2375-4727-bb5c-71aa4600372a', 'github_private_flag_and_visibility_mismatch', 'github', 1, '{"policy": null, "signals": [{"name": "GitHub Private Flag and Visibility Mismatch", "timeout_ms": 10000, "description": "Detects repositories where is_private is True but visibility is not PRIVATE.", "signal_code": "github_private_visibility_mismatch", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"unknown\")\n    owner = dataset.get(\"owner_login\", \"unknown-owner\")\n    external_id = dataset.get(\"_external_id\", f\"{owner}/{name}\")\n    is_private_raw = dataset.get(\"is_private\", \"\")\n    visibility = (dataset.get(\"visibility\", \"\") or \"\").upper()\n\n    is_private = str(is_private_raw).lower() == \"true\"\n\n    if not is_private:\n        details.append({\n            \"check\": \"private_visibility_consistency\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not marked private (is_private={is_private_raw}), so the visibility mismatch rule is not applicable; current visibility={visibility}\"\n        })\n        result = \"pass\"\n        summary = f\"Repository ''{name}'' is not private, so no private visibility consistency check was required\"\n    else:\n        if visibility == \"PRIVATE\":\n            details.append({\n                \"check\": \"private_visibility_consistency\",\n                \"status\": \"pass\",\n                \"message\": f\"Repository ''{name}'' ({external_id}) has consistent privacy settings with is_private={is_private_raw} and visibility={visibility}\"\n            })\n            result = \"pass\"\n            summary = f\"Repository ''{name}'' has matching private visibility settings\"\n        else:\n            details.append({\n                \"check\": \"private_visibility_consistency\",\n                \"status\": \"fail\",\n                \"message\": f\"Repository ''{name}'' ({external_id}) is marked private (is_private={is_private_raw}) but visibility is set to {visibility}, which is not PRIVATE and indicates a configuration mismatch\"\n            })\n            result = \"fail\"\n            summary = f\"Repository ''{name}'' has a mismatch between is_private={is_private_raw} and visibility={visibility}\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_confirmed_privacy_mismatch_condition", "description": "", "threat_code": "github_confirmed_privacy_mismatch_condition", "severity_code": "high", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "github_private_visibility_mismatch", "expected_result": "fail"}, {"operator": "NOT", "conditions": [{"signal_code": "github_private_visibility_mismatch", "expected_result": "pass"}]}]}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_private_visibility_mismatch", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Private repository correctly marked PRIVATE", "dataset_input": {"name": "auth-service", "is_fork": "False", "pushed_at": "2025-02-11T10:22:31Z", "created_at": "2023-03-01T09:11:10Z", "is_private": "True", "updated_at": "2025-02-11T10:22:31Z", "visibility": "PRIVATE", "description": "Authentication microservice", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "sec-platform"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "private_visibility_consistency", "status": "pass", "message": "Repository auth-service (sec-platform/auth-service) has consistent privacy configuration"}], "summary": "0/1 repositories have is_private=True but visibility not PRIVATE"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Another compliant private repository", "dataset_input": {"name": "billing-api", "is_fork": "False", "pushed_at": "2025-01-20T18:02:11Z", "created_at": "2022-10-14T12:41:55Z", "is_private": "True", "updated_at": "2025-01-20T18:02:11Z", "visibility": "PRIVATE", "description": "Internal billing APIs", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "finance-eng"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "private_visibility_consistency", "status": "pass", "message": "Repository billing-api (finance-eng/billing-api) has consistent privacy configuration"}], "summary": "0/1 repositories have is_private=True but visibility not PRIVATE"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_003", "description": "Private flag true but visibility PUBLIC", "dataset_input": {"name": "ml-experiments", "is_fork": "False", "pushed_at": "2025-02-01T06:14:51Z", "created_at": "2024-01-02T11:04:33Z", "is_private": "True", "updated_at": "2025-02-01T06:14:51Z", "visibility": "PUBLIC", "description": "Machine learning experiments", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "ai-lab"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "private_visibility_consistency", "status": "fail", "message": "Repository ml-experiments (ai-lab/ml-experiments) has mismatched privacy configuration"}], "summary": "1/1 repositories have is_private=True but visibility not PRIVATE"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_004", "description": "Private repo incorrectly marked INTERNAL", "dataset_input": {"name": 