      ('ae51c786-cce0-43ac-b543-0eae96be9ba5', 'public_repo_documentation_hygiene', 'github', 1, '{"policy": {"name": "Public Repo Documentation Hygiene", "actions": [{"config": {}, "action_type": "notification"}], "description": "", "policy_code": "public_repo_doc_hygiene_check", "cooldown_minutes": 0}, "signals": [{"name": "Public Repository Missing Description", "timeout_ms": 10000, "description": "Detects GitHub repositories that are public but have an empty description.", "signal_code": "public_repo_empty_description", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    visibility = (dataset.get(\"visibility\", \"\") or \"\").upper()\n    description = dataset.get(\"description\", \"\")\n    owner = dataset.get(\"owner_login\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    if not external_id:\n        if owner and name:\n            external_id = owner + \"/\" + name\n        else:\n            external_id = name or \"unknown\"\n\n    min_description_length = 1\n    trimmed_description = (description or \"\").strip()\n    desc_length = len(trimmed_description)\n\n    if visibility == \"PUBLIC\":\n        if desc_length < min_description_length:\n            details.append({\n                \"check\": \"public_repo_description\",\n                \"status\": \"fail\",\n                \"message\": f\"Repository ''{external_id}'' is publicly accessible (visibility={visibility}) but its description is empty or whitespace (raw_description=''{description}'', trimmed_length={desc_length}), which violates the requirement for public repositories to include a meaningful description\"\n            })\n            result = \"fail\"\n            summary = f\"1/1 repositories violate the public description requirement: ''{external_id}'' is public but missing a description\"\n        else:\n            details.append({\n                \"check\": \"public_repo_description\",\n                \"status\": \"pass\",\n                \"message\": f\"Repository ''{external_id}'' is public (visibility={visibility}) and has a description with trimmed length {desc_length} characters (''{trimmed_description}''), meeting the minimum requirement of {min_description_length}\"\n            })\n            result = \"pass\"\n            summary = f\"0/1 repositories violate the public description requirement\"\n    else:\n        details.append({\n            \"check\": \"public_repo_description\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{external_id}'' is not publicly accessible (visibility={visibility}); description policy applies only to public repositories, so an empty description (''{description}'') is allowed\"\n        })\n        result = \"pass\"\n        summary = f\"0/1 repositories violate the public description requirement\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "public_repo_documentation_hygiene_issue", "description": "", "threat_code": "public_repo_documentation_hygiene_issue", "severity_code": "low", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "public_repo_empty_description", "expected_result": "fail"}, {"signal_code": "public_repo_empty_description", "expected_result": "fail"}]}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — public_repo_empty_description", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Public repository with a valid description", "dataset_input": {"name": "payment-api", "is_fork": "False", "pushed_at": "2025-02-11T10:12:44Z", "created_at": "2023-01-02T08:21:10Z", "is_private": "False", "updated_at": "2025-02-11T10:12:44Z", "visibility": "PUBLIC", "description": "Payment processing service for checkout 