ls": [{"check": "public_repo_description", "status": "pass", "message": "No repositories evaluated"}], "summary": "0/0 repositories violate the public description requirement"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}], "description": "", "json_schema": null, "dataset_code": "ai-tests-public_repo_empty_description-771494f3", "record_count": 18}, "dataset_template": null}'::jsonb, '459413c8-e4f2-4f30-bd58-87dd6da4e304', '9c69dd3f-6075-4398-b3c4-a9f41bb90145', NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 0, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-30T05:17:31.255416+00:00', TRUE, FALSE, '2026-03-30T05:17:31.255416+00:00', '2026-03-30T05:17:31.255416+00:00'),
      ('b71e8651-583c-4b65-bd3a-4eb99c892a76', 'github_repository_stale_push_age', 'github', 1, '{"policy": null, "signals": [{"name": "GitHub Repository Stale Push Age", "timeout_ms": 10000, "description": "Detects repositories whose last push is older than a configured number of days.", "signal_code": "github_repo_stale_push_age", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    pushed_at = dataset.get(\"pushed_at\", \"\")\n\n    threshold_days = 180\n    now = datetime.datetime.now(datetime.timezone.utc)\n\n    repo_identifier = external_id if external_id else name if name else \"unknown\"\n\n    if not pushed_at:\n        details.append({\n            \"check\": \"repo_push_age\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{repo_identifier}'' has no valid pushed_at timestamp (pushed_at=''{pushed_at}''), so the repository activity age cannot be calculated against the {threshold_days}-day threshold\"\n        })\n        return {\n            \"result\": \"warning\",\n            \"summary\": f\"Repository ''{repo_identifier}'' could not be evaluated because the last push timestamp is missing\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    try:\n        if isinstance(pushed_at, datetime.datetime):\n            pushed_dt = pushed_at.astimezone(datetime.timezone.utc) if pushed_at.tzinfo else pushed_at.replace(tzinfo=datetime.timezone.utc)\n        elif isinstance(pushed_at, str):\n            s = pushed_at.strip()\n            if s.endswith(\"Z\"):\n                s = s[:-1] + \"+00:00\"\n            pushed_dt = datetime.datetime.fromisoformat(s)\n            if pushed_dt.tzinfo is None:\n                pushed_dt = pushed_dt.replace(tzinfo=datetime.timezone.utc)\n            else:\n                pushed_dt = pushed_dt.astimezone(datetime.timezone.utc)\n        else:\n            raise ValueError(\"unsupported pushed_at type\")\n    except:\n        details.append({\n            \"check\": \"repo_push_age\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{repo_identifier}'' has an invalid pushed_at value (''{pushed_at}'') which cannot be parsed as ISO8601 time, preventing comparison with the {threshold_days}-day threshold\"\n        })\n        return {\n            \"result\": \"warning\",\n            \"summary\": f\"Repository ''{repo_identifier}'' could not be evaluated due to invalid last push timestamp format\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    age_days = (now - pushed_dt).total_seconds() / 86400\n    age_days_int = int(age_days)\n\n    if age_days_int > threshold_days:\n        status = \"fail\"\n        comparison = \"above\"\n    else:\n        status = \"pass\"\n        comparison = \"below or equal to\"\n\n    details.append({\n        \"check\": \"repo_push_age\",\n        \"status\": status,\n        \"message\": f\"Repository ''{repo_identifier}'' last pushed at {pushed_at}, approximately {age_days_int} days ago, which is {comparison} the allowed {threshold_days}-day inactivity threshold\"\n    })\n\n    if status == \"fail\":\n        summary = f\"Repository ''{repo_identifier}'' last push is {age_days_int} days old, exceeding the {threshold_days}-day threshold\"\n    else:\n        summary = f\"Repository ''{repo_identifier}'' last push is {age_days_int} days old, within the {threshold_days}-day threshold\"\n\n    return {\n        \"result\": status,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_repository_confirmed_inactive", "description": "", "threat_code": "github_repository_confirmed_inactive", "severity_code": "medium", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "github_repo_stale_push_age", "expected_result": "fail"}, {"operator": "NOT", "conditions": [{"signal_code": "github_repo_stale_push_age", "expected_result": "pass"}]}]}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_repo_stale_push_age", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Recent repository push well within default threshold", "dataset_input": {"name": "auth-service", "pushed_at": "2026-03-01T10:15:30Z", "_external_id": "acme/auth-service"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository auth-service last pushed 25 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Recently updated infrastructure repository", "dataset_input": {"name": "infra-terraform", "pushed_at": "2026-02-10T08:22:11Z", "_external_id": "cloudops/infra-terraform"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository infra-terraform last pushed 44 days ago which is below the threshold"}], "summary": "0/1 repositories have last push older than the allowed threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_003", "description": "Repository with push older than default threshold", "dataset_input": {"name": "legacy-payment-gateway", "pushed_at": "2025-01-12T05:10:00Z", "_external_id": "fintech/legacy-payment-gateway"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "repo_push_age", "status": "fail", 