compliant", "expected_output": {"result": "pass", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository devops-helper-scripts (acme/devops-helper-scripts) archive status evaluated"}], "summary": "0/1 repositories are archived"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}], "description": "", "json_schema": null, "dataset_code": "ai-tests-github_repositories_archived_detection-3695cc37", "record_count": 18}, "dataset_template": null}'::jsonb, '7b89f85a-c665-4a8c-93c0-fef8d24f2824', '14f1cd79-7947-436f-8d23-89d56dfacef8', NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 3, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-31T10:45:07.301098+00:00', TRUE, FALSE, '2026-03-31T10:45:07.301098+00:00', '2026-04-06T18:30:42.211137+00:00'),
      ('cf927964-45e3-4cef-a6d3-28c05ef6e609', 'repository_metadata_drift_pushed_at_vs_updated_at', 'github', 1, '{"policy": null, "signals": [{"name": "Repository Metadata Drift (pushed_at vs updated_at)", "timeout_ms": 10000, "description": "Detects repositories where pushed_at is significantly newer than updated_at, suggesting repository settings or metadata may not be maintained.", "signal_code": "repo_metadata_drift_pushed_vs_updated", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\") or \"unknown\"\n    owner = dataset.get(\"owner_login\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    if not external_id:\n        if owner:\n            external_id = owner + \"/\" + name\n        else:\n            external_id = name\n\n    pushed_at_str = dataset.get(\"pushed_at\", \"\") or \"\"\n    updated_at_str = dataset.get(\"updated_at\", \"\") or \"\"\n\n    fail_threshold_days = 90\n    warning_threshold_days = 30\n\n    if not pushed_at_str or not updated_at_str:\n        details.append({\n            \"check\": \"metadata_drift_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository {external_id} cannot be evaluated because pushed_at=''{pushed_at_str}'' and updated_at=''{updated_at_str}'' are missing or empty, so no metadata drift could be calculated\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Repository ''{external_id}'': insufficient timestamp data to detect metadata drift\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    try:\n        pushed_at = datetime.datetime.fromisoformat(pushed_at_str.replace(\"Z\", \"+00:00\"))\n        updated_at = datetime.datetime.fromisoformat(updated_at_str.replace(\"Z\", \"+00:00\"))\n    except Exception:\n        details.append({\n            \"check\": \"metadata_drift_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository {external_id} has non-parseable timestamps (pushed_at=''{pushed_at_str}'', updated_at=''{updated_at_str}''), so drift could not be computed\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Repository ''{external_id}'': timestamps could not be parsed for drift evaluation\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    diff_seconds = (pushed_at - updated_at).total_seconds()\n    drift_days = diff_seconds / 86400.0\n    drift_days_int = int(drift_days)\n\n    if drift_days <= 0:\n        status = \"pass\"\n        message = f\"Repository {external_id} has pushed_at={pushed_at_str} and updated_at={updated_at_str}; updated_at is newer or equal (drift_days={drift_days_int}), indicating repository metadata is current\"\n    elif drift_days > fail_threshold_days:\n        status = \"fail\"\n        message = f\"Repository {external_id} shows metadata drift of {drift_days_int} days (pushed_at={pushed_at_str} is much newer than updated_at={updated_at_str}), exceeding the {fail_threshold_days}-day threshold and suggesting repository settings may not be maintained\"\n    elif drift_days >= warning_threshold_days:\n        status = \"warning\"\n        message = f\"Repository {external_id} shows metadata drift of {drift_days_int} days (pushed_at={pushed_at_str} newer than updated_at={updated_at_str}), exceeding the {warning_threshold_days}-day warning threshold but not the {fail_threshold_days}-day failure threshold\"\n    else:\n        status = \"pass\"\n        message = f\"Repository {external_id} shows minimal metadata drift of {drift_days_int} days between pushed_at={pushed_at_str} and updated_at={updated_at_str}, which is within the acceptable {warning_threshold_days}-day threshold\"\n\n    details.append({\n        \"check\": \"metadata_drift_check\",\n        \"status\": status,\n        \"message\": message\n    })\n\n    result = status\n    if status == \"fail\":\n        summary = f\"Repository ''{external_id}'' shows metadata drift beyond the {fail_threshold_days}-day failure threshold\"\n    elif status == \"warning\":\n        summary = f\"Repository ''{external_id}'' shows moderate metadata drift between push activity and metadata updates\"\n    else:\n        summary = f\"Repository ''{external_id}'' metadata updates are consistent with recent code pushes\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "confirmed_repository_metadata_drift_condition", "description": "", "threat_code": "confirmed_repository_metadata_drift_condition", "severity_code": "high", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "repo_metadata_drift_pushed_vs_updated", "expected_result": "fail"}, {"operator": "NOT", "conditions": [{"signal_code": "repo_metadata_drift_pushed_vs_updated", "expected_result": "warning"}]}]}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — repo_metadata_drift_pushed_vs_updated", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Single repository with minimal drift between pushed_at and updated_at", "dataset_input": {"name": "auth-service", "is_fork": "False", "pushed_at": "2025-05-10T10:00:00Z", "created_at": "2023-01-01T09:00:00Z", "is_private": "True", "updated_at": "2025-05-08T10:00:00Z", "visibility": "PRIVATE", "description": "Authentication service", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "acme-sec"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "metadata_drift_check", "status": "pass", "message": "Repository acme-sec/auth-service drift_days=2 (pushed_at newer than updated_at)"}], "summary": "0/1 repositories show metadata drift beyond threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Repository with large drift indicating neglected metadata", "dataset_input": {"name": "legacy-api", "is_fork": "False", "pushed_at": "2025-07-01T12:00:00Z", "created_at": "2019-03-10T08:00:00Z", "is_private": "True", "updated_at": "2024-05-27T12:00:00Z", "visibility": "PRIVATE", "description": "Old API service", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "infra-team"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "metadata_drift_check", "status": "fail", "message": "Repository infra-team/legacy-api drift_days=400 (pushed_at newer than updated_at)"}], "summary": "1/1 repositories show metadata drift beyond threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_003", "description": "Repository with years of metadata drift", "dataset_input": {"name": "data-pipeline", "is_fork": "False", "pushed_at": "2025-06-10T06:00:00Z", "created_at": "2018-11-11T10:00:00Z", "is_private": "True", "updated_at": "2023-04-02T06:00:00Z", "visibility": "PRIVATE", "description": "ETL processing pipeline", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "analytics"}, "scenario_name": "all_fail", "expected_output": {"result": "fail", "details": [{"check": "metadata_drift_check", "status": "fail", "message": "Repository analytics/data-pipeline drift_days=800 (pushed_at newer than updated_at)"}], "summary": "1/1 repositories show metadata drift beyond threshold"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_004", "description": "Repository with moderate drift producing wa