      ('e7540170-dc2a-4398-9ab9-f5cad3ce6a4a', 'repo_outside_expected_org', 'github', 1, '{"policy": null, "signals": [{"name": "GitHub Repository Owned Outside Expected Organization", "timeout_ms": 10000, "description": "Detects repositories whose owner_login does not match the expected organization account.", "signal_code": "github_repo_owner_not_expected_org", "max_memory_mb": 256, "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    asset_type = dataset.get(\"_asset_type\", \"\")\n    repo_name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\", \"unknown\")\n    owner_login = dataset.get(\"owner_login\", \"unknown\")\n\n    expected_owner = dataset.get(\"expected_owner_login\", \"kreesalis\")\n\n    if asset_type != \"github_repo\":\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"No repositories found in this record (asset_type is not ''github_repo'')\",\n            \"details\": [\n                {\n                    \"check\": \"asset_type_filter\",\n                    \"status\": \"pass\",\n                    \"message\": f\"Record with external_id ''{external_id}'' has _asset_type=''{asset_type}'', so it is not evaluated as a GitHub repository\"\n                }\n            ],\n            \"metadata\": {}\n        }\n\n    if owner_login == expected_owner:\n        details.append({\n            \"check\": \"owner_login_match\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{repo_name}'' ({external_id}) is owned by owner_login=''{owner_login}'', which matches the expected organization account ''{expected_owner}''\"\n        })\n        failed_repos = 0\n    else:\n        details.append({\n            \"check\": \"owner_login_match\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{repo_name}'' ({external_id}) is owned by owner_login=''{owner_login}'', which does not match the expected organization account ''{expected_owner}'', indicating the repository is owned outside the approved organization\"\n        })\n        failed_repos = 1\n\n    total_repos = 1\n\n    if failed_repos == 0:\n        result = \"pass\"\n    elif failed_repos < total_repos:\n        result = \"warning\"\n    else:\n        result = \"fail\"\n\n    summary = f\"{failed_repos}/{total_repos} repositories are not owned by the expected organization\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "source_prompt": null, "connector_type_codes": ["github"]}], "threat_type": {"name": "github_repo_owner_mismatch_warning", "description": "", "threat_code": "github_repo_owner_mismatch_warning", "severity_code": "medium", "expression_tree": {"signal_code": "github_repo_owner_not_expected_org", "expected_result": "warning"}, "mitigation_guidance": null}, "test_dataset": {"name": "AI Tests — github_repo_owner_not_expected_org", "records": [{"description": "", "record_data": {"case_id": "tc_001", "description": "Repository owned by expected organization", "dataset_input": {"name": "api-gateway", "_asset_type": "github_repo", "owner_login": "kreesalis", "_external_id": "kreesalis/api-gateway"}, "scenario_name": "all_compliant", "expected_output": {"result": "pass", "details": [{"check": "owner_login_match", "status": "pass", "message": "Repository api-gateway (kreesalis/api-gateway) owner_login=kreesalis matches expected organization"}], "summary": "0/1 repositories are not owned by the expected organization"}, "configurable_args_override": {}}, "record_name": "", "scenario_name": null, "expected_result": null}, {"description": "", "record_data": {"case_id": "tc_002", "description": "Repository owned by unexpected personal account", "dataset_input": {"name": "payment-service", "_asset_type": "github_repo", "owner_login": "srigaddeks", "_external_id": "srigaddeks/payment-service"}, "scenario_name": "all_fai